window.__LIBQ=window.__LIBQ||{};window.__LIBQ["the-gioi-hoan-my"]=window.__LIBQ["the-gioi-hoan-my"]||{};window.__LIBQ["the-gioi-hoan-my"]["q01"]=window.__LIBQ["the-gioi-hoan-my"]["q01"]||{};window.__LIBQ["the-gioi-hoan-my"]["q01"]["artifacts"]={"updatedAt":"2026-07-04","count":262,"artifacts":[{"id":"cot-bong-xuong-cu-thu","name":"Cốt bổng (gậy xương cự thú)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Phàm","soHuu":[],"trangThai":"dang-co","blurb":"Gậy lớn mài từ xương cự thú, trai tráng Thạch Thôn dùng để rèn luyện và săn bắn.","detail":"Cốt bổng được mài từ xương của cự thú, là vũ khí trai tráng Thạch Thôn sử dụng khi rèn luyện cũng như đi săn.","nguon":["@c0001"]},{"id":"dai-kiem-kim-loai-den","name":"Đại kiếm kim loại đen","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Phàm","soHuu":["Thạch Lâm Hổ"],"trangThai":"dang-co","blurb":"Đại kiếm rèn từ kim loại màu đen, khi múa tiếng gió nổi như sấm; kiếm của Thạch Lâm Hổ nặng hơn ba trăm cân.","detail":"Đại kiếm rèn từ kim loại màu đen; trai tráng múa lên tiếng gió nổi như sấm. Đại kiếm của Thạch Lâm Hổ nặng hơn ba trăm cân, đeo sau lưng.","nguon":["@c0001"]},{"id":"sua-thu-bach-thu","name":"Sữa thú (sữa bách thú)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Phàm","soHuu":["Thạch Vân Phong"],"trangThai":"dang-co","blurb":"Sữa của trăm loài thú do Thạch Vân Phong nấu, dùng nuôi chú nhóc mồ côi.","detail":"Sữa bách thú do Thạch Vân Phong nấu, thi thoảng bỏ thêm dược thảo, dùng nuôi chú nhóc mồ côi mất cha mẹ từ nửa tuổi.","nguon":["@c0001"]},{"id":"thit-tho-long","name":"Thịt Thổ Long","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Phàm","soHuu":[],"trangThai":"dang-co","blurb":"Món thịt hiếm có trong bát của lũ trẻ Thạch Thôn.","detail":"Thịt Thổ Long là loại thức ăn có thịt hiếm hoi trong khẩu phần ăn thiếu thốn của lũ trẻ Thạch Thôn.","nguon":["@c0001"]},{"id":"mieng-ngoc-cot-ky-di","name":"Miếng ngọc cốt kỳ dị","category":"khac","categoryLabel":"Vật phẩm bí ẩn","phamCap":"Chưa rõ","soHuu":["Thạch Vân Phong"],"trangThai":"dang-co","blurb":"Miếng ngọc cốt Thạch Vân Phong cất trong ngực áo, lai lịch bí ẩn.","detail":"Miếng ngọc cốt kỳ dị Thạch Vân Phong cất trong ngực áo. Lão sờ tới nó với ánh mắt lộ ánh sáng khác thường khi nói về tương lai của lũ trẻ, gợi ý vật này có lai lịch và bí mật quan trọng.","nguon":["@c0002"]},{"id":"cot-bong","name":"Cốt bổng","cn":"","category":"khac","categoryLabel":"Vũ khí","phamCap":"Phàm khí","soHuu":[],"trangThai":"dang-co","blurb":"Cây gậy lớn mài từ xương cự thú do trai tráng Thạch Thôn dùng khi rèn luyện và săn bắn.","detail":"Cốt bổng là vũ khí thô sơ mài từ xương của cự thú, do các trai tráng vạm vỡ trong Thạch Thôn sử dụng — phản ánh hoàn cảnh sinh tồn khốc liệt nơi mãng sơn, vũ khí làm từ vật liệu săn được trong tự nhiên.","nguon":["@c0001"]},{"id":"sua-bach-thu","name":"Sữa bách thú","cn":"","aliases":["Sữa thú nấu dược thảo"],"category":"khac","categoryLabel":"Thực phẩm/Dưỡng chất","phamCap":"Phàm phẩm","soHuu":["Chú nhóc Thạch Thôn"],"trangThai":"dang-co","blurb":"Chất lỏng trắng nấu trong ang gốm bỏ thêm dược thảo, nuôi lớn chú nhóc mồ côi của Thạch Thôn.","detail":"Sữa bách thú là sữa thú được nấu trong ang gốm, bỏ thêm dược thảo cho bổ dưỡng. Lão tộc trưởng Thạch Vân Phong dùng nó nuôi đứa trẻ mồ côi mất cha mẹ từ nửa tuổi; tới hơn một năm tuổi đứa bé vẫn chưa cai sữa.","nguon":["@c0001"]},{"id":"huyet-tinh","name":"Huyết tinh","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Phàm phẩm","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Thuốc đại bổ máu huyết quý giá lấy từ tinh huyết hung thú.","detail":"Tinh huyết chảy ra từ phần đặc biệt trên cơ thể hung thú, được trai tráng Thạch Thôn hứng vào vò đất nung khi mổ xẻ cự thú. Là thuốc đại bổ máu huyết tuyệt vời, quá nửa dùng trên người đám trẻ để rèn da thịt rắn chắc.","nguon":["@c0003"]},{"id":"chan-huyet-ty-huu","name":"Chân huyết Tỳ Hưu","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Trân phẩm","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Chân huyết quý còn ẩn trong con Tỳ Hưu hậu duệ, dược tính cực mạnh.","detail":"Tỳ Hưu là hậu duệ kém vương tộc huyết mạch thuần tịnh nhưng còn ẩn một phần chân huyết, quý nhất trong các hung thú; hơn hai năm Thạch Thôn mới bẫy được một con. Phần chân huyết ấy có dược tính cực mạnh, giá trị cực lớn.","nguon":["@c0003"]},{"id":"chan-huyet-hoa-te-hai-dau","name":"Chân huyết Hỏa Tê hai đầu","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Trân phẩm","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Chân huyết đỏ rực trích từ dưới sừng Hỏa Tê hai đầu, dược tính không thua Tỳ Hưu.","detail":"Một lão gia mổ chân huyết trong máu thịt cứng dưới sừng con Hỏa Tê hai đ��u; dòng máu hóa thành một quầng sáng đỏ tạo hình con Hỏa Tê nhỏ bằng bàn tay phẫn nộ rít gào. Dược tính không thua chân huyết Tỳ Hưu.","nguon":["@c0003"]},{"id":"sung-rong","name":"Sừng rồng","aliases":["sừng voi sừng rồng"],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Trân phẩm","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Cặp sừng rồng mọc nhiều năm trên đầu voi sừng rồng, là thuốc báu bổ cốt khó kiếm.","detail":"Cặp sừng rồng mọc lâu năm trên đầu con voi sừng rồng, là thuốc bổ cốt quý hiếm. Thạch Vân Phong dặn trai tráng cẩn thận cưa sừng rồng để không phí của báu.","nguon":["@c0003"]},{"id":"gan-quy-thu-mot-chan","name":"Gân Quỳ Thú một chân","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Phàm phẩm","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Sợi gân dai bền của Quỳ Thú một chân, rìu chém mãi không đứt.","detail":"Gân của con Quỳ Thú một chân là sợi gân dai bền, rìu chém mãi không đứt, được Thạch Thôn thu thập làm nguyên liệu quý khi mổ xẻ hung thú.","nguon":["@c0003"]},{"id":"mau-hai-canh-phi-mang","name":"Máu hai cánh Phi Mãng","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Phàm phẩm","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Máu quý nằm ở hai cánh con Phi Mãng.","detail":"Máu quý của con Phi Mãng tập trung ở hai cánh, được Thạch Thôn thu thập trong buổi mổ xẻ hung thú sau săn bắn.","nguon":["@c0003"]},{"id":"nuoc-tam-thuoc","name":"Nước tắm thuốc","category":"dan-duoc","categoryLabel":"Dược dịch","soHuu":["Thạch Thôn"],"trangThai":"da-dung","blurb":"Dược dịch tắm thuốc của Thạch Thôn dùng tăng cường thể chất lũ trẻ.","detail":"Chế trong tám đỉnh đồng lớn từ dược thảo, rết dài vài thược, nhện to bằng nắm tay, chân huyết hung thú, xương cánh Phi Mãng và xương chân Quỳ Thú, nước đen kịt như mực. Làm gân cốt trẻ con cường tráng sánh ngang cự thú nhưng chưa đến mức thoát thai hoán cốt; tắm vào da thịt như dao cắt, trẻ con kêu gào thảm thiết.","nguon":["@c0004"]},{"id":"thuoc-bot-tri-thuong","name":"Thuốc bột trị thương","category":"dan-duoc","categoryLabel":"Bảo dược","soHuu":["Thạch Thôn"],"trangThai":"da-dung","blurb":"Bảo dược trị thương của Thạch Thôn chế từ nước thuốc thừa.","detail":"Vì chân huyết quý hiếm nên các bô lão không nỡ để phí, đun cạn nước thuốc tắm thừa rồi thêm dược thảo đặc biệt chế thành thuốc b���t; vừa là thuốc bổ vừa là bảo dược trị thương mang theo đi săn cứu mạng.","nguon":["@c0004"]},{"id":"bao-duoc-dac-biet","name":"Bảo dược đặc biệt","category":"dan-duoc","categoryLabel":"Đan dược","soHuu":["Thạch Vân Phong","Nhóc tỳ"],"trangThai":"da-dung","blurb":"Bảo dược Thạch Vân Phong chế riêng cho nhóc tỳ ăn để bồi bổ thể chất.","detail":"Chế từ đoạn quý nhất trên sừng voi sừng rồng, xương móng vuốt Tỳ Hưu, sừng đỏ Hỏa Tê (mài bột), trộn chân huyết hung thú, nấu trong sữa thú thêm thảo dược kì dị thành chất lỏng đặc sệt thơm đậm. Nhóc tỳ ăn hết khiến dược kình phát tác cực mạnh, nổi cơn quậy phá; cốt văn lan rộng, thể chất tăng mạnh.","nguon":["@c0004"]},{"id":"chuy-tu-kim","name":"Chùy Tử Kim","category":"khac","categoryLabel":"Công cụ","soHuu":["Thạch Vân Phong"],"trangThai":"dang-co","blurb":"Chùy Thạch Vân Phong dùng đập vỡ vật liệu quý khi chế bảo dược.","detail":"Công cụ dùng để đập đoạn quý nhất trên sừng voi sừng rồng khi Thạch Vân Phong chế bảo dược cho nhóc tỳ.","nguon":["@c0004"]},{"id":"hai-chiec-binh-dac-biet","name":"Hai chiếc bình đặc biệt","category":"khac","categoryLabel":"Vật chứa","soHuu":["Thạch Vân Phong"],"trangThai":"da-dung","blurb":"Hai bình chứa của tộc trưởng dùng trong tắm thuốc đặc biệt cho nhóc tỳ.","detail":"Tộc trưởng mở hai bình: bình thứ nhất phóng làn mây đỏ ngưng thành con Tỳ Hưu dài bằng bàn tay hung dữ; bình thứ hai phóng con tê giác hai đầu đỏ rực. Cả hai bị Thạch Vân Phong vỗ tan thành huyết dịch rơi vào hắc đỉnh của nhóc tỳ.","nguon":["@c0004"]},{"id":"thuoc-tam","name":"Thuốc tắm","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Phương thuốc cổ Thạch Thôn","soHuu":["Thạch Thôn"],"trangThai":"da-dung","blurb":"Nước thuốc đen kịt nấu trong đỉnh đồng để tắm cho trẻ con Thạch Thôn.","detail":"Pha từ dược thảo, rết dài vài thược, nhện to bằng nắm tay khiến nước đen kịt như mực, thêm chân huyết đỏ tươi cùng xương cánh Phi Mãng và xương chân Quỳ Thú đập nát. Tăng cường gân cốt cho trẻ con, khiến chúng bong da cũ từng mảng và khỏe hơn rõ rệt sau một đêm, dù chưa đến mức thoát thai hoán cốt.","nguon":["@c0004"]},{"id":"chan-huyet-hung-thu","name":"Chân huyết hung thú","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Quý hiếm","soHuu":["Thạch Thôn"],"trangThai":"da-dung","blurb":"Chút huyết quý giá lấy từ hung thú săn được, dùng tắm thuốc tăng cường thể chất.","detail":"Huyết đỏ tươi lấy từ cơ thể hung thú săn được, cực kỳ quý giá trong hoàn cảnh khốc liệt của Đại Hoang nên không nỡ phí chút nào. Rót vào nước thuốc giúp tăng cường thể chất cho cả trẻ con lẫn người lớn; cũng là thành phần trong lô bảo dược riêng của nhóc tỳ.","nguon":["@c0004"]},{"id":"lo-bao-duoc-rieng","name":"Lô bảo dược riêng cho nhóc tỳ","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Dược kình cực mạnh","soHuu":["Thạch Vân Phong","Nhóc tỳ"],"trangThai":"da-dung","blurb":"Lô bảo dược Thạch Vân Phong tự nấu riêng cho nhóc tỳ, dược kình cực mạnh.","detail":"Thạch Vân Phong nấu từ đoạn quý nhất trên sừng voi sừng rồng (đập bằng chùy Tử Kim), xương móng vuốt Tỳ Hưu và sừng đỏ Hỏa Tê mài bột, trộn chân huyết bỏ vào nồi sữa thú cùng thảo dược kỳ dị, nấu thành chất sệt thơm ngào ngạt. Dược kình quá mạnh khiến nhóc tỳ sau khi ăn hết nồi thì mắt đỏ au, quậy phá hai canh giờ; thể chất-tốc độ-sức mạnh tăng nhiều và cốt văn lan rộng lên cả cánh tay.","nguon":["@c0004"]},{"id":"dinh-dong-ngan-can","name":"Đỉnh đồng ngàn cân","cn":"","aliases":[],"category":"khac","categoryLabel":"Khí vật luyện lực","phamCap":"Phàm vật","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Chiếc đỉnh đồng nặng cả ngàn cân đặt giữa sân Thạch Thôn, dùng để thử sức nâng đỉnh của lũ trẻ.","detail":"Đỉnh đồng nặng cả ngàn cân, hoa văn chim bay thú chạy cổ xưa, vách dày, chân đỉnh nhẵn bóng như gương, bề mặt khắc hoa văn chu tước. Trong chương, đám trẻ Thạch Thôn thi nhau nâng đỉnh: Thạch Đại Tráng chín tuổi nâng qua đầu thành công, còn Thạch Hạo ba tuổi rưỡi ngồi sụp nâng đáy đỉnh, nhấc bổng qua chỏm đầu.","nguon":["@c0005"]},{"id":"huyet-duoc","name":"Huyết dược","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Thạch Vân Phong"],"trangThai":"dang-co","blurb":"Tinh hoa chưng cất từ máu mãnh thú qua cốt văn, dùng cho tẩy lễ.","detail":"Được Thạch Vân Phong chưng cất từ máu các mãnh thú có linh tính bằng cốt văn. Mỗi con thú cuối cùng chỉ còn một giọt máu lung linh trong suốt rực rỡ như kim cương màu máu, chảy vào bình ngọc. Chỉ chân huyết phẩm chất cao mới có tác dụng; dùng chuẩn bị tẩy lễ cho Thạch Hạo.","nguon":["@c0006"]},{"id":"tuong-qua","name":"Tương Quả","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Thường","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Quả đỏ au thơm lừng, món Thạch Hạo thích ăn nhất.","detail":"Loại quả đỏ au thơm lừng, căng mọng như viên mã não, là món Thạch Hạo thích ăn nhất, do Thạch Lâm Hổ hái tặng sau khi đội săn trở về.","nguon":["@c0006"]},{"id":"trung-thanh-lan-ung","name":"Trứng Thanh Lân Ưng","category":"khac","categoryLabel":"Trứng dị cầm","phamCap":"Chưa rõ","soHuu":[],"trangThai":"dang-co","blurb":"Ba quả trứng của dị cầm Thanh Lân Ưng, óng ánh như bích ngọc, mang tiềm năng huyết dịch Thái Cổ Ma Cầm.","detail":"Ba quả trứng đặt trong Ngô Sào trên lớp Kim Ti Thảo, mỗi quả to bằng chậu nước, xanh biếc như mã não, có đường vằn và chấm li ti. Đây là trứng của Thanh Lân Ưng — dị cầm hung hãn mang huyết dịch truyền thừa từ Thái Cổ Ma Cầm. Đám trẻ Thạch Thôn phát hiện và định mang về thôn ấp.","nguon":["@c0007","@c0010"]},{"id":"kim-ti-thao","name":"Kim Ti Thảo","category":"nguyen-lieu","categoryLabel":"Cỏ linh","phamCap":"Chưa rõ","soHuu":[],"trangThai":"dang-co","blurb":"Loại cỏ mềm mại được Thanh Lân Ưng trải trong tổ để ấp trứng.","detail":"Cỏ mềm mại thoải mái được trải bên trong Ngô Sào của Thanh Lân Ưng, làm nền lót cho ba quả trứng dị cầm.","nguon":["@c0007"]},{"id":"vay-thanh-lan-ung","name":"Vảy Thanh Lân Ưng","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Tấm vảy kim loại hung cầm to bằng bàn tay trẻ sơ sinh, sắc lẻm hàn quang.","detail":"Vảy hung cầm trưởng thành lót trong tổ Thanh Lân Ưng, sắc lẻm tỏa hàn quang lấp lóa, cứng đến mức đại kiếm mấy trăm cân cũng khó chém đứt. Thạch Đại Tráng dẫm phải bị đâm thủng đế giày tóe máu chân; Thạch Hạo thu mấy tấm mang về.","nguon":["@c0008"]},{"id":"to-khi-cuc-xuong-tay-hung-thu","name":"Tổ Khí","cn":"","category":"than-khi","categoryLabel":"Bảo khí gia truyền","phamCap":"Bảo khí trấn thôn","soHuu":["Thạch Lâm Hổ","Thạch Vân Phong"],"trangThai":"Đang dùng","blurb":"Bảo khí gia truyền lâu đời của Thạch Thôn dùng để chấn nhiếp hung thú, vốn là một cục xương tay hung thú.","detail":"Tổ Khí là bảo khí gia truyền lâu đời trong Thạch Thôn, hình dạng là một cục xương tay hung thú, dùng để chấn nhiếp cường địch. Khi tế, người dùng thúc giục khiến tay trái nổi cốt văn rực rỡ rồi ấn cục xương lên; cục xương phát ra một luồng hơi thở như vua vạn thú sống lại, khiến hung cầm chấn động bay lên xa. Sau khi kích hoạt, cục xương dung hợp vào cánh tay trái người tế, huyết nhục dung hòa, ngưng thành một phù hiệu cổ xưa như thể hung thú sắp nhảy ra. Trong thôn có ít nhất hai cái Tổ Khí; lần này Thạch Lâm Hổ tế bảo để đẩy lui Thanh Lân Ưng.","nguon":["@c0009"]},{"id":"cung-sung-rong","name":"Cung sừng rồng","cn":"","category":"khac","categoryLabel":"Vũ khí","phamCap":"","soHuu":["Bì Hầu"],"trangThai":"Vũ khí Thạch Thôn","blurb":"Cung cứng làm từ sừng cắt ra từ Long Giác Tượng, nguyên liệu làm cung tốt nhất của Thạch Thôn.","detail":"Cung sừng rồng là loại cung cứng được chế từ sừng cắt ra từ Long Giác Tượng — nguyên liệu làm cung tốt nhất của Thạch Thôn. Cung rất cứng, chỉ người đã trưởng thành mới đủ sức kéo nổi. Trong trận đối đầu, Bì Hầu bắn cung này vào đầu Thanh Lân Ưng nhưng mũi tên chỉ tóe lửa, không xuyên thủng được lớp vẩy xanh cứng như kim loại của hung cầm.","nguon":["@c0009"]},{"id":"thiet-mau","name":"Thiết mâu","cn":"","category":"khac","categoryLabel":"Vũ khí","phamCap":"","soHuu":["Thạch Hạo"],"trangThai":"Vũ khí Thạch Thôn","blurb":"Mâu sắt nặng bốn năm chục cân, vũ khí ném uy lực trong tay các nhóc khỏe của Thạch Thôn.","detail":"Thiết mâu là mâu sắt nặng chừng bốn năm chục cân. Thạch Hạo mượn thiết mâu, lấy đà tăng tốc ném thẳng về mắt Thanh Lân Ưng khiến nó lần đầu lộ vẻ kinh dị; dù né kịp, mâu vẫn làm bong một miếng vẩy ở khóe mắt khiến hung cầm chảy máu. Về sau ba đứa khỏe nhất — Thạch Hạo, Nhị Mãnh, Thạch Đại Tráng — chuyên dùng thiết mâu nhắm vào hai mắt con hung cầm để câu giờ chờ cứu viện.","nguon":["@c0009"]},{"id":"to-khi-da-thu-co","name":"Tổ Khí (thứ hai — da thú cổ)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo vật","soHuu":["Thạch Phi Giao"],"trangThai":"dang-co","blurb":"Tổ Khí thứ hai của Thạch Thôn — tấm da thú cổ ngưng phù văn.","detail":"Tấm da thú cổ lấm máu khô, được Thạch Phi Giao ấn lên ngực; da thú dung hợp thành da thịt gã, kết thành kí tự thần bí hiện bóng hung thú mơ hồ, ngực như mọc thêm gương mặt thú phát tiếng thú gầm rung núi. Loại hung thú này ngưng sức mạnh ở da thịt thay vì xương.","nguon":["@c0010"]},{"id":"lang-nha-dai-bong","name":"Lang Nha Đại Bổng","category":"khac","categoryLabel":"Binh khí","phamCap":"Binh khí thường","soHuu":["Thạch Phi Giao"],"trangThai":"mat","blurb":"Gậy lớn của Thạch Phi Giao.","detail":"Cây gậy lớn Thạch Phi Giao vốn dùng, bị gã vứt bỏ để rảnh tay tế Tổ Khí thứ hai.","nguon":["@c0010"]},{"id":"hac-thiet-con","name":"Hắc Thiết Côn","category":"khac","categoryLabel":"Binh khí","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Côn đen của sinh vật hình người cao chọc mây (hồi tưởng).","detail":"Cây côn đen của một sinh vật hình người cao chọc mây mà Thạch Phi Giao từng thấy bước qua mấy ngọn núi hai năm trước, thuộc thế lực Thái Cổ chưa lộ diện.","nguon":["@c0010"]},{"id":"trung-vay-tim-phan-to","name":"Quả trứng phản tổ (trứng vảy tím)","category":"khac","categoryLabel":"Trứng linh cầm","phamCap":"Chưa rõ","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Quả trứng bị cành liễu già phất qua nên xảy ra phản tổ, kế thừa mảnh ấn ký Thái Cổ Ma Cầm.","detail":"Một trong ba quả trứng của Thanh Lân Ưng, sau khi cành liễu xanh nhạt phất qua thì tỏa hào quang chói lọi, xuất hiện vô số ký hiệu phức tạp như Long Xà, Thần Tước bay trong lửa. Sinh cơ mạnh hơn nhiều lần nhờ Sinh mệnh lạc ấn truyền thừa từ Thái Cổ Ma Cầm hồi phục, huyết mạch cao quý hơn cả bố mẹ. Khi nở, vỏ trứng vỡ nát thành bột phấn, con chim non trên người là vảy tím rực rỡ lấp lánh như lửa đang thiêu đốt, linh tính kinh người, đôi mắt to lóng lánh — một linh cầm rất không bình thường.","nguon":["@c0011"]},{"id":"thuoc-mau-tim","name":"Thuốc màu tím","category":"dan-duoc","categoryLabel":"Đan dược","soHuu":["Thạch Vân Phong"],"trangThai":"da-dung","blurb":"Hai viên thuốc màu tím thơm nức tộc trưởng đựng trong bình ngọc, dùng để trị thương nặng.","detail":"Tộc trưởng Thạch Vân Phong lấy từ bình ngọc hai viên thuốc màu tím thơm nức để cứu Thạch Thủ Sơn: một viên bóp nát xoa lên vết thương, một viên cho uống.","nguon":["@c0013"]},{"id":"thuoc-chan-huyet-hung-thu","name":"Thuốc chân huyết hung thú","category":"dan-duoc","categoryLabel":"Dược liệu","soHuu":["Thạch Lâm Hổ"],"trangThai":"da-dung","blurb":"Thuốc do tộc lão Thạch Thôn nấu từ chân huyết hung thú, dùng sơ cứu vết thương.","detail":"Các tộc lão nấu thuốc bằng chân huyết hung thú cho Thạch Thủ Sơn uống, kèm thuốc lâu năm cắn nát dán lên vết thương để sơ cứu trọng thương.","nguon":["@c0013"]},{"id":"mui-ten-sat-bai-thon","name":"Mũi tên sắt dài một mét ba","category":"khac","categoryLabel":"Vũ khí","soHuu":["Bái Thôn"],"trangThai":"dang-co","blurb":"Tên sắt bóng loáng dài một mét ba, vũ khí chủ lực của Bái Thôn, đủ sức bắn thủng giáp hộ thân.","detail":"Mũi tên sắt dài một mét ba bắn thủng giáp hộ thân Thạch Thủ Sơn, xuyên qua phổi phải ra tới sau lưng. Là vũ khí bắn xuyên giáp ba lớp mà người Bái Thôn dùng tấn công Thạch Thôn.","nguon":["@c0013"]},{"id":"giap-thep-ba-lop","name":"Giáp thép tinh chế ba lớp","category":"khac","categoryLabel":"Phòng cụ","soHuu":["Thạch Thôn"],"trangThai":"hong","blurb":"Giáp thép tinh chế dày ba lớp lót trước ngực người Thạch Thôn, bị thằng nhóc Bái Thôn bắn xuyên toàn bộ.","detail":"Mấy huynh đệ Thạch Thôn trước ngực đều lót ba lớp giáp thép tinh chế dày, nhưng toàn bộ đều bị thằng nhóc Bái Thôn bắn xuyên trong vụ chặn cướp.","nguon":["@c0013"]},{"id":"vang-trang-luoi-liem-van-lac","name":"Vầng trăng lưỡi liềm (văn lạc)","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Chiêu thức do văn lạc tạo, Thạch Hạo dùng ngón tay hiện văn lạc nắm trong lòng bàn tay.","detail":"Thạch Hạo tạo bằng ngón tay hiện văn lạc, nắm trong lòng bàn tay như một vầng trăng lưỡi liềm nhỏ, vung ra hàng loạt điểm sáng khuếch tán đánh vỡ tên nỏ; hóa thành ánh sáng trong suốt đón đánh Bái Phong khiến hắn phun máu.","nguon":["@c0015"]},{"id":"day-deo-tay-rang-thu","name":"Dây đeo tay mài bằng răng thú","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Dây đeo trên cổ tay Thạch Hạo, người Bái Thôn lầm tưởng là Bảo Cụ quý hiếm.","detail":"Dây đeo tay mài bằng răng thú trên cổ tay Thạch Hạo. Người Bái Thôn thấy ký hiệu lấp lóe khi Thạch Hạo dùng sức, hét lên đó là Bảo Cụ quý hiếm giúp tăng sức mạnh — thực chất họ hiểu nhầm về sức mạnh Cốt Văn của nó.","nguon":["@c0015"]},{"id":"cung-long-giac","name":"Cung Long Giác","category":"khac","categoryLabel":"Vũ khí","phamCap":"Không rõ","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Loại cung mà Bái Thôn giao nộp cho Thạch Thôn làm bồi thường sau khi thua trận.","detail":"Nằm trong số vũ khí Bái Thôn phải giao nộp cùng hàng đống tên sắt và kiếm bản to để chuộc Bái Phong và rút khỏi vùng núi.","nguon":["@c0016"]},{"id":"kiem-ban-to-bai-thon","name":"Kiếm bản to","category":"khac","categoryLabel":"Vũ khí","phamCap":"Không rõ","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Kiếm bản to nằm trong số vũ khí Bái Thôn giao nộp làm bồi thường.","detail":"Cùng với tên sắt và cung Long Giác, kiếm bản to được Bái Thôn giao cho Thạch Thôn khi thỏa hiệp bồi thường.","nguon":["@c0016"]},{"id":"chan-huyet-toan-nghe","name":"Chân huyết Toan Nghê","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Chân huyết rút từ thi thể Toan Nghê Thái Cổ Di Chủng để khắc Nguyên Thủy Bảo Phù.","detail":"Vật liệu quý được rút từ thi thể của con Toan Nghê Thái Cổ Di Chủng, dùng để khắc Nguyên Thủy Bảo Phù trên bộ xương như mở kho báu động trời.","nguon":["@c0016","@c0035"]},{"id":"chan-huyet-bao-cot-toan-nghe","name":"Chân huyết và bảo cốt Toan Nghê","category":"nguyen-lieu","categoryLabel":"Di vật","soHuu":[],"trangThai":"dang-co","blurb":"Di thể của Toan Nghê chứa chân huyết kinh thế cùng ký hiệu nguyên thủy, trở thành kho báu vô chủ.","detail":"Sau khi Toan Nghê già chết đi, toàn bộ chân huyết và bảo cốt của nó trở thành kho báu vô chủ, kèm theo Bảo Thuật cùng ký hiệu nguyên thủy, khiến các thế lực quanh vùng đổ xô vào núi tranh đoạt.","nguon":["@c0018"]},{"id":"bao-the-toan-nghe","name":"Bảo thể Toan Nghê","cn":"","category":"khac","categoryLabel":"Di vật","phamCap":"Thái Cổ Di Chủng","soHuu":[],"trangThai":"Chôn dưới đống đá núi, vừa lộ ra","blurb":"Di thể của Thái Cổ Di Chủng Toan Nghê, nuốt vào sẽ tiến hóa thành bá chủ sơn lâm.","detail":"Bảo thể của Thái Cổ Di Chủng Toan Nghê xuất hiện từ giữa đống đá núi khi cá xấu bạc hất tung cự thạch. Một luồng hào quang vàng như vầng thái dương nhỏ nhô lên — đó là một cái chân phải to bằng cột, cường tráng, mọc đầy lông thú màu vàng lóng lánh như vàng ròng, tràn ngập hung khí. Trên người có ký hiệu nguyên thủy lấp lánh rực rỡ, khiến tất cả sinh linh mạnh mẽ đều chấn động, mắt nóng bỏng và xông về phía trước tranh đoạt. Là mục tiêu tranh đoạt của cả đàn hung thú vì nuốt vào sẽ tiến hóa thành bá chủ sơn lâm.","nguon":["@c0019","@c0018"]},{"id":"chan-thu-mau-vang-toan-nghe","name":"Chân thú màu vàng (bảo thể Toan Nghê)","aliases":["Chân thú màu vàng"],"category":"khac","categoryLabel":"Khác","phamCap":"Thái Cổ Di Chủng","soHuu":[],"trangThai":"dang-co","blurb":"Xác của một con Toan Nghê Thái Cổ Di Chủng chân chính, thân dài sáu mét, toàn thân như vàng ròng, dù đã chết hung khí vẫn lan tỏa.","detail":"Sau khi được đào lộ, bảo thể Toan Nghê trở thành mục tiêu tranh đoạt của cả bầy hung thú hung cầm. Thân dài sáu mét, toàn thân như vàng ròng, chứa bảo huyết quý giá. Bất ngờ con Toan Nghê tưởng đã chết bỗng bật dậy sống lại, xé đứt một cánh tay Ác Ma Viên và đánh gãy sừng Ly Hỏa Ngưu Ma, khiến toàn bộ hung thú kinh sợ ngã rạp.","nguon":["@c0020"]},{"id":"canh-tay-ac-ma-vien","name":"Cánh tay Ác Ma Viên","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Bộ phận Thái Cổ Di Chủng","soHuu":["Thanh Lân Ưng"],"trangThai":"dang-co","blurb":"Cánh tay Ác Ma Viên bị Toan Nghê xé đứt, chứa chân huyết hiếm có.","detail":"Trong đại chiến, Toan Nghê xé đứt một cánh tay của Ác Ma Viên. Cánh tay này chứa chân huyết hiếm có nên được Thanh Lân Ưng tha về Thạch Thôn, dùng cho lễ tẩy năm tuổi của Thạch Hạo.","nguon":["@c0021","@c0031"]},{"id":"sung-ly-hoa-nguu-ma","name":"Sừng Ly Hỏa Ngưu Ma","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Thú bảo vô giá","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Cái sừng đỏ dài mấy mét của Ly Hỏa Ngưu Ma, thú bảo vô giá.","detail":"Sau đại chiến, nhóc tỳ khiêng cái sừng dài mấy mét của Ly Hỏa Ngưu Ma về, được xem là thú bảo vô giá.","nguon":["@c0021"]},{"id":"bao-nguyet-thach-hao","name":"Bảo Nguyệt","aliases":["Bảo Cụ của Thạch Hạo"],"category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Vũ khí hình trăng bạc rất mạnh của Thạch Hạo, chém gãy tên mâu sắt.","detail":"Vũ khí hình vầng trăng bạc do Thạch Hạo triệu hồi, uy lực khiến hơn hai mươi người Bái Thôn không địch nổi. Chém rơi và gãy tên sắt mỗi mũi ngàn cân, chém đứt vai tay đối thủ, chém rách bụng thủ lĩnh đội săn.","nguon":["@c0022"]},{"id":"sung-do-tham-thai-co-di-chung","name":"Sừng đỏ thẫm của Thái Cổ Di Chủng","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Sừng dài mấy mét màu đỏ thẫm, bên trong có bảo huyết.","detail":"Sừng đỏ thẫm dài mấy mét của Thái Cổ Di Chủng, bên trong chứa bảo huyết. Thạch Hạo tin bảo huyết này có tác dụng giải độc như sừng Linh Tê nên chém thịt dính sừng cho Thanh Lân Ưng ăn.","nguon":["@c0022"]},{"id":"vong-rang-thu-bai-thon","name":"Vòng răng thú","category":"khac","categoryLabel":"Khác","soHuu":["Thiếu niên trên cáng (Bái Thôn)"],"trangThai":"dang-co","blurb":"Vật thiếu niên Bái Thôn cầm thưởng thức trên cáng.","detail":"Vòng răng thú mà thiếu niên Bái Thôn nằm trên cáng cầm thưởng thức khi đi cùng viện binh.","nguon":["@c0022"]},{"id":"bao-cu-te-linh-ban","name":"Bảo Cụ do Tế Linh ban","category":"khac","categoryLabel":"Khác","soHuu":["Bái Thôn"],"trangThai":"dang-co","blurb":"Trang bị Tế Linh cấp cho Bái Thôn để đối phó Thạch Hạo.","detail":"Bảo Cụ mà Tế Linh ban cho Bái Thôn lần này để đối phó Thạch Hạo. Các ông già Bái Thôn nói Tế Linh sẽ tự đến vì bảo thể Toan Nghê.","nguon":["@c0022"]},{"id":"bao-cu-bai-phong","name":"Bảo Cụ (của Bái Phong)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Bái Phong"],"trangThai":"Đang sử dụng","blurb":"Bảo Cụ của Bái Phong, phóng ra điểm sáng xán lạn có lực sát thương kinh người.","detail":"Bảo Cụ do thiếu niên thiên tài Bái Phong của Bái Thôn nắm giữ. Khi ra tay, nó phát ra điểm sáng xán lạn xông tới, đánh xuyên sáu bảy người Thạch Thôn và làm rách vai Thạch Hạo, một đốm sáng suýt đâm xuyên yết hầu Thạch Hạo. Bái Phong dùng nó tập kích lạnh lùng, khiến đám đông kinh ngạc vì không ngờ người tu Cốt Văn cũng có thể sử dụng Bảo Cụ. Mưa ánh sáng phóng ra bay như mưa sao băng cắt ngang trời.","nguon":["@c0023"]},{"id":"bao-cu-rang-thu-42","name":"Bảo Cụ răng thú (42 răng thú)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo","soHuu":["Thạch Hạo"],"trangThai":"bi-cuop","blurb":"Xâu răng thú trắng như mỡ dê do Bảo cốt Tế Linh làm thành, tụ tán hóa hạt sáng, quái thú, vũ khí, chiến y.","detail":"Xâu 42 răng thú trắng như mỡ dê đá ngọc, do Bảo cốt Tế Linh làm thành, chí bảo của Bái thôn. Có thể tụ tán, hóa thành hạt sáng, mưa sao băng, quái thú sói, vũ khí (chủy thủ, mũi tên) và chiến y. Tế Linh ban cho, khi Tế Linh còn sống thì người được ban không cần Cốt văn cũng dùng được. Ở chương 24, Bái Phong dùng Bảo cụ đâm thủng đá lớn sáu bảy mét như cái sàng, nhưng cuối cùng bị nhóc tỳ đánh bại và cướp mất, đeo lên cổ tay.","nguon":["@c0024"]},{"id":"binh-thuoc-giai-doc-thanh-lan-ung","name":"Bình thuốc giải độc","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Thạch Vân Phong"],"trangThai":"da-dung","blurb":"Bình thuốc Thạch Vân Phong dùng giải độc cho Thanh Lân Ưng.","detail":"Thạch Vân Phong rắc thuốc từ bình lên vết thương để giải độc cho Thanh Lân Ưng đang bị trúng độc.","nguon":["@c0024"]},{"id":"mau-sat-thach-lam-ho","name":"Mâu sắt","category":"linh-khi","categoryLabel":"Vũ khí","phamCap":"Vũ khí thường","soHuu":["Thạch Lâm Hổ"],"trangThai":"Đang sử dụng","blurb":"Cây mâu sắt Thạch Lâm Hổ ném cắm vào con sói biến dị to bằng cái nhà khiến nó bị thương.","detail":"Vũ khí của Thạch Lâm Hổ trong trận vây của đám Sói biến dị. Khi bầy sói to bằng cái nhà, răng nanh dài áp sát, Thạch Lâm Hổ ném cây mâu sắt cắm thẳng vào con sói to làm nó bị trọng thương, cứu người thôn dân đang bị đe dọa.","nguon":["@c0025"]},{"id":"vong-rang-thu-bao-cu","name":"Vòng răng thú (Bảo Cụ)","cn":"","category":"phap-bao","categoryLabel":"Bảo Cụ","phamCap":"","soHuu":["Thạch Hạo"],"trangThai":"Thạch Hạo sử dụng","blurb":"Vòng răng óng ánh như sao mà Thạch Hạo dùng, thực ra là răng của chính con Bái già rụng ra, đã tế luyện trăm lần.","detail":"Một chiếc vòng kết từ răng thú óng ánh như sao, do Thạch Hạo (nhóc tỳ) sử dụng để tấn công con Bái già. Đám răng này thực chất là răng của chính con Bái già rụng ra, đã được tế luyện trăm lần thành bảo cụ. Khi bị dùng làm vũ khí đánh mình, con Bái già nổi giận và lao tới thu hồi.","nguon":["@c0026"]},{"id":"xich-than-rang-xanh","name":"Xích thần ráng xanh","cn":"","category":"phap-bao","categoryLabel":"Thần thông/Pháp bảo","phamCap":"","soHuu":["Tế Linh"],"trangThai":"Tế Linh thi triển","blurb":"Cành non của cây liễu Tế Linh hóa thành một sợi xích thần màu ráng xanh kéo dài hơn một dặm, nhanh như chớp vọt tới tấn công.","detail":"Khi tộc nhân cầu khẩn, cái chồi non của cây liễu Tế Linh cháy đen động đậy, hóa thành một sợi xích thần ráng xanh kéo dài hơn một dặm, nhanh như chớp vọt tới nhắm con Bái dữ chặn đường trước thôn. Là biểu hiện sức mạnh của Tế Linh — thực thể bảo hộ thôn làng dưới hình cây liễu.","nguon":["@c0026"]},{"id":"sung-bao-do-tham-lot-xac","name":"Sừng bảo đỏ thẫm","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Thạch Vân Phong"],"trangThai":"dang-co","blurb":"Sừng bảo màu đỏ thẫm dùng trong kế hoạch lột xác của Nhóc tỳ.","detail":"Sừng bảo màu đỏ thẫm được Thạch Vân Phong chuẩn bị để giúp Nhóc tỳ lột xác trước năm tuổi, cùng với chân huyết Toan Nghê và cánh tay Vược Ác Ma.","nguon":["@c0028"]},{"id":"cot-thu","name":"Cốt thư","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Thạch Vân Phong","Thạch Hạo"],"trangThai":"dang-co","blurb":"Mấy bộ sách phù văn tộc trưởng truyền thụ cho Thạch Hạo.","detail":"Mấy bộ sách ghi chép Cốt văn / phù văn mà Thạch Vân Phong truyền lại cho Thạch Hạo, gồm cả phù văn cuối cùng, giúp nhóc tỳ học Cốt văn và đột phá cảnh Thay máu thần tốc.","nguon":["@c0029"]},{"id":"thien-dia-bao-duoc-truyen-thuyet","name":"Thiên địa bảo dược (truyền thuyết)","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Thuốc quý trong truyền thuyết Thạch Hạo hứa hái để chữa ám thương cho tộc trưởng.","detail":"Thiên địa bảo dược cực kỳ hiếm, dù đại tộc mấy triệu dân chưa chắc có. Thạch Hạo hứa sẽ hái được để chữa ám thương cổ quái cho Thạch Vân Phong.","nguon":["@c0029"]},{"id":"xuong-thu-bao-cu-tu-son-toc","name":"Xương thú Bảo Cụ (Tử Sơn Tộc)","cn":"","category":"phap-bao","categoryLabel":"Bảo cụ","phamCap":"","soHuu":["Chú ruột của Tử Sơn Hầu"],"trangThai":"dang-co","blurb":"Xương thú dài sáu bảy mét, hào quang trắng, lấp lóe ký hiệu, bay sát đất, thu nhỏ còn cỡ bàn tay.","detail":"Bảo cụ của Tử Sơn Tộc: một cái xương thú dài sáu bảy mét, tỏa hào quang trắng và lấp lóe ký hiệu, bay sát đất một thước, súc địa thành thốn; khi cất đi thu nhỏ còn cỡ bàn tay. Chở chú ruột Tử Sơn Hầu tới Tiểu Cô Sơn Trấn.","nguon":["@c0030"]},{"id":"da-thu-co-loi-toc","name":"Da thú cổ (Lôi Tộc)","cn":"","category":"phap-bao","categoryLabel":"Bảo cụ","phamCap":"","soHuu":["Thanh niên Lôi Tộc"],"trangThai":"dang-co","blurb":"Tấm da thú cổ lấp lóe ký hiệu, khí tức cổ lão tang thương, bay sát đất, thu nhỏ còn cỡ bàn tay.","detail":"Bảo cụ của Lôi Tộc: một tấm da thú cổ lấp lóe ký hiệu, khí tức cổ lão tang thương, bay sát đất ba thước; khi cất đi thu nhỏ còn cỡ bàn tay. Chở người Lôi Tộc tới Tiểu Cô Sơn Trấn.","nguon":["@c0030"]},{"id":"chan-huyet-toan-nghe-tay-le","name":"Chân huyết Toan Nghê (dịch tẩy lễ)","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Bảo huyết Thái Cổ Di Chủng","soHuu":["Thạch Thôn"],"trangThai":"da-dung","blurb":"Bảo huyết chứa máu hoàng kim của Toan Nghê, dùng thay nước suối làm dịch tẩy lễ cho Thạch Hạo.","detail":"Chân huyết Toan Nghê chứa dịch thể vàng xán lạn, mang sức mạnh thần thánh của Thái Cổ Di Chủng, đặc mà không đông. Được lấy đầy bình bạc rồi đổ vào đỉnh thay nước suối làm dịch tẩy lễ luyện hóa cơ thể nhóc tỳ.","nguon":["@c0031"]},{"id":"tim-chi-bao-toan-nghe","name":"Tim chí bảo Toan Nghê","cn":"","category":"khac","categoryLabel":"Bảo vật","phamCap":"Chí bảo Thái Cổ Di Chủng","soHuu":["Thạch Thôn"],"trangThai":"da-dung","blurb":"Quả tim vàng nhạt to bằng chậu của Toan Nghê, ẩn chứa thần tính, thả vào đỉnh làm dịch hóa kim quang.","detail":"Tộc trưởng dùng đao ngọc đào ra quả tim vàng nhạt to bằng chậu ẩn chứa thần tính, tuôn mưa ánh sáng vàng, đặt vào trong đỉnh làm bảo vật cốt lõi cho tẩy lễ.","nguon":["@c0031"]},{"id":"dinh-den-to-truyen","name":"Đỉnh đen tổ truyền","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo vật tổ truyền","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Đỉnh lớn khí tức cổ xưa của Thạch Thôn, khắc nhật nguyệt sơn hà và cảnh Tiên Dân Thượng Cổ lễ bái, dùng luyện chân huyết.","detail":"Đỉnh đen tổ truyền toát khí tức cổ xưa, thân khắc nhật nguyệt sơn hà, điểu thú ngư trùng và cảnh Tiên Dân Thượng Cổ lễ bái. Được đun bằng lửa Hắc Giao Mộc để luyện cổ dược, độc trùng và chân huyết Toan Nghê thành dịch tẩy lễ.","nguon":["@c0031"]},{"id":"sung-do-ly-hoa-nguu-ma","name":"Sừng đỏ Ly Hoa Ngưu Ma","cn":"","category":"khac","categoryLabel":"Bảo vật","phamCap":"Chân huyết thông linh","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Sừng đỏ dài mấy mét của Ly Hoa Ngưu Ma, sáng như Mã Não, chứa chân huyết thông linh, chưa được đun.","detail":"Sừng đỏ dài mấy mét sáng như Mã Não, chứa chân huyết thông linh của Ly Hoa Ngưu Ma. Chưa được đun trong tẩy lễ này vì sợ nhóc tỳ tuổi nhỏ không chịu nổi, để dùng sau tùy tình hình.","nguon":["@c0031"]},{"id":"hac-giao-moc","name":"Hắc Giao Mộc","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Kỳ mộc","soHuu":["Thạch Thôn"],"trangThai":"da-dung","blurb":"Kỳ mộc cứng nặng như sắt tinh, thân đen như Ly Long, là nguồn lửa tốt nhất để luyện khoáng chế binh khí.","detail":"Hắc Giao Mộc cứng nặng như sắt tinh, thân đen như Ly Long, đốt lên thế lửa hừng hực, là nguồn lửa tốt nhất để luyện khoáng, chế binh khí và nấu chân huyết. Thanh niên Thạch Thôn chặt nó làm nguồn lửa cho tẩy lễ.","nguon":["@c0031"]},{"id":"dao-ngoc-chuy-tu-kim","name":"Đao ngọc & chùy tử kim","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Pháp khí","soHuu":["Thạch Vân Phong"],"trangThai":"dang-co","blurb":"Đao ngọc chi chít ký hiệu chém ánh sáng đào tim và chùy tử kim đập đầu độc trùng, dụng cụ tẩy lễ của tộc trưởng.","detail":"Tộc trưởng dùng đao ngọc chi chít ký hiệu tỏa ánh sáng để đào tim chí bảo Toan Nghê, và dùng chùy tử kim đập vỡ đầu độc trùng thành phụ dược trong quá trình tẩy lễ.","nguon":["@c0031"]},{"id":"co-duoc-doc-trung-phu-duoc","name":"Cổ dược & độc trùng phụ dược","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Phụ dược","soHuu":["Thạch Thôn"],"trangThai":"da-dung","blurb":"Cổ dược cùng các độc trùng (rết tím, Xuyên Sơn Giáp bạc, rắn vàng, nhện bạc biết bay) luyện thành phụ dược giảm đau và luyện hóa chân huyết.","detail":"Tộc trưởng ném cổ dược vào nước sôi rồi mở mấy chục bình ngọc thả độc trùng gồm rết tím dài hơn nửa mét, Xuyên Sơn Giáp bạc, rắn vàng nhỏ và nhện bạc biết bay, đập vỡ đầu chúng thành phụ dược giúp giảm đau và luyện hóa chân huyết Toan Nghê.","nguon":["@c0031"]},{"id":"dinh-den-dinh-duoc-co-khi-toc","name":"Đỉnh đen Cổ Khí tộc (dược đỉnh cổ)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Dược đỉnh cổ","soHuu":["Thạch Vân Phong"],"trangThai":"dang-co","blurb":"Đỉnh to màu đen tổ tiên Cổ Khí tộc truyền lại, thực chất là một tòa dược đỉnh ghê gớm.","detail":"Đỉnh to màu đen khắc sơn hà nhật nguyệt chim muông ngư trùng và tiên dân thượng cổ. Khi luyện dược lộ chân tướng là dược đỉnh cổ: hình điêu khắc trở nên chân thực, phù văn trên vách đỉnh tự cháy sáng, truyền ra tiếng tế tự tụng kinh và hình tiên dân thượng cổ trấn áp Di chủng Thái cổ. Đỉnh luyện hóa Toan Nghê cùng ba loại chân huyết thành huyết thanh dùng tẩy lễ nhóc tỳ. Thạch Vân Phong nhận ra đỉnh có cùng biểu hiện giống đỉnh của các bộ tộc lớn.","nguon":["@c0032"]},{"id":"huyet-thanh-vang-kim","name":"Huyết thanh màu vàng kim","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Dược dịch","soHuu":[],"trangThai":"da-dung","blurb":"Dịch thuốc vàng kim luyện trong đỉnh đen dùng tẩy lễ nhóc tỳ, chứa mảnh thần tính Toan Nghê.","detail":"Dược dịch màu vàng kim do đỉnh đen luyện hóa Toan Nghê (và về sau thêm chân huyết Bò ma Ly Hỏa, Vượn Ác ma) tạo thành. Huyết thanh xông vào cơ thể nhóc tỳ qua lỗ chân lông, tẩy lễ từ ngoài vào trong khiến thân thể lột xác.","nguon":["@c0032"]},{"id":"dinh-hong-van","name":"Đỉnh Hống văn","cn":"","category":"khac","categoryLabel":"Trọng khí","phamCap":"","soHuu":["Nhóc tỳ"],"trangThai":"dang-co","blurb":"Đỉnh nặng tám ngàn cân nhóc tỳ nâng lên thử thần lực.","detail":"Chiếc đỉnh khắc văn Hống nặng tám ngàn cân; nhóc tỳ nâng lên đi vòng đất trống thử thần lực sau tẩy lễ, thả xuống khiến đất rung chuyển.","nguon":["@c0033","@c0032"]},{"id":"bao-cung-te-giac","name":"Bảo cung Tê giác","cn":"","category":"khac","categoryLabel":"Vũ khí","phamCap":"","soHuu":["Thạch Lâm Hổ"],"trangThai":"dang-co","blurb":"Cung lực căng lớn nhất trong tộc, quá thô to nhóc tỳ không kéo căng nổi.","detail":"Bảo cung làm từ sừng tê giác, lực căng lớn nhất trong Thạch thôn; Thạch Lâm Hổ đưa cho nhóc tỳ thử nhưng cánh tay nó quá ngắn nên không kéo căng được.","nguon":["@c0033"]},{"id":"khoi-xuong-tran-toan-nghe","name":"Khối xương trán Toan Nghê","cn":"","category":"nguyen-lieu","categoryLabel":"Bảo cụ / Nguyên liệu","phamCap":"","soHuu":["Nhóc tỳ"],"trangThai":"dang-co","blurb":"Xương trắng bằng lòng bàn tay chứa Phù văn nguyên thủy; hoạt tính mất dần nếu để lâu.","detail":"Khối xương trắng lấy giữa trán Toan Nghê, chứa Phù văn nguyên thủy. Nếu để lâu hoạt tính biến mất thì chỉ còn thành Bảo cụ chứ không luyện được Bảo thuật; tộc trưởng đưa cho nhóc tỳ ghi nhớ.","nguon":["@c0033"]},{"id":"dinh-co-thach-thon","name":"Đỉnh cổ Thạch Thôn","category":"khac","categoryLabel":"Khí vật luyện thể","soHuu":["Nhị Mãnh"],"trangThai":"dang-co","blurb":"Các đỉnh cổ xưa khắc điểu thú ngư trùng, nặng ngàn cân, dùng để trẻ Thạch Thôn luyện sức.","detail":"Những cái đỉnh cổ xưa của Thạch Thôn khắc điểu thú ngư trùng, mỗi cái nặng ngàn cân, nhiễm hung khí máu Toan Nghê. Trẻ trong thôn dùng chúng để luyện sức; Nhị Mãnh dễ dàng nâng một cái lên. Cường giả cảm nhận hung khí trên các đỉnh, biết có Thú Vương từng đổ máu chết tại đây.","nguon":["@c0035"]},{"id":"linh-hoa","name":"Linh hoa","cn":"","category":"dan-duoc","categoryLabel":"Linh vật","phamCap":"","soHuu":["Lôi Vân Khôn"],"trangThai":"da-dung","blurb":"Đóa linh hoa được Lôi Vân Khôn đổ vào nước sôi, tỏa hương ngào ngạt, linh khí tràn ra.","detail":"Linh hoa là linh vật Lôi Vân Khôn dùng pha vào nước sôi mời trẻ con Thạch thôn uống; khi thả vào nước liền tỏa hương ngào ngạt và linh khí tràn ra.","nguon":["@c0036"]},{"id":"tam-long-tuyet","name":"Tấm lông tuyết","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Ông lão Vân Thiên Cung"],"trangThai":"dang-co","blurb":"Tấm lông tuyết mà ông lão Vân Thiên Cung cầm trong tay khi đứng ra can Giao Bằng.","detail":"Vật phẩm ông lão Vân Thiên Cung nắm trong tay lúc hiện diện quanh Thạch thôn và can ngăn Giao Bằng động thủ.","nguon":["@c0036"]},{"id":"vong-xuong-ngon-cai-tu-son-con","name":"Vòng xương ngón cái","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Tử Sơn Côn"],"trangThai":"dang-co","blurb":"Vòng xương trên ngón cái Tử Sơn Côn, phát sáng phá giải lực đạo.","detail":"Đeo trên ngón cái Tử Sơn Côn, phát sáng phá giải lực đạo giúp tay không bị gãy khi bị Thạch Hạo đá văng.","nguon":["@c0038"]},{"id":"coi-xay-da","name":"Cối xay đá","category":"khac","categoryLabel":"Vật phẩm","soHuu":["Thạch Hạo"],"trangThai":"da-dung","blurb":"Cối xay đá mấy trăm cân Thạch Hạo dùng làm vũ khí.","detail":"Thạch Hạo dùng đá cối xay văng vào Lôi Minh Viễn, sau nắm cả cối xay mấy trăm cân đập thẳng vào đầu Giao Bằng khiến hắn phun máu bọt, rụng hai răng.","nguon":["@c0038"]},{"id":"bao-cot-toan-nghe-tranh-doat","name":"Bảo cốt Toan Nghê","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Bảo vật","soHuu":["Thạch Hạo"],"trangThai":"Bị nhiều thế lực tranh đoạt","blurb":"Xương của Toan Nghê, trục tranh đoạt của toàn chương; các cường giả đòi Thạch Thôn giao ra còn Thạch Hạo tuyên bố là của mình.","detail":"Bảo cốt Toan Nghê là xương của con Toan Nghê, trở thành mục tiêu tranh đoạt của toàn chương. La Phù Đại Trạch, bộ lạc Kim Lang, Lôi Tộc, Vân Thiên Cung cùng nhiều thế lực khác thi nhau chiêu mộ Thạch Hạo hoặc trực tiếp đòi Thạch Thôn giao ra, thực chất chỉ muốn đoạt lấy bảo cốt này cùng ba con dị cầm non. Giao Thương của La Phù Đại Trạch thờ ơ ra lệnh, mặc Giao Bằng đe dọa huyết tẩy Thạch Thôn. Thạch Hạo tuyên bố bảo cốt cùng Đại Bằng, Tiểu Thanh, Tử Vân đều là của mình.","nguon":["@c0039"]},{"id":"thai-co-ma-cam","name":"Thái Cổ Ma Cầm","cn":"","aliases":["Thái Cổ Hung Cầm"],"category":"khac","categoryLabel":"Khác","phamCap":"Thái Cổ","soHuu":["Thạch Hạo"],"trangThai":"Bảo Thuật do Thạch Hạo diễn hóa","blurb":"Bảo Thuật của Thạch Hạo, một con ma cầm che kín vòm trời nuốt chửng và nghiền nát ba dị cầm của ba thiên tài.","detail":"Thái Cổ Ma Cầm (còn gọi Thái Cổ Hung Cầm) là một trong những Bảo Thuật lợi hại của Thạch Hạo. Nó há to cái miệng kinh khủng một phát nuốt chửng con Lôi Cầm của Lôi Minh Viễn khiến con này tan rã. Khi che kín vòm trời, nó xé con Hôi Giao to bằng vại nước thành ba đoạn, nuốt Lôi Điểu và đánh nát Hỏa Lân, khiến ba thiên tài bị đánh bay, ho ra máu lăn lóc dính bụi.","nguon":["@c0039"]},{"id":"phi-giao-giao-bang","name":"Phi Giao","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Dị thú","soHuu":["Giao Bằng"],"trangThai":"Bị cành liễu non đâm chết","blurb":"Con giao dài hai mươi mấy mét Giao Bằng cưỡi, sát khí lan tỏa, nhào xuống định huyết tẩy Thạch Thôn thì bị cành liễu non đâm thủng.","detail":"Phi Giao là con giao dài hai mươi mấy mét, sát khí lan tỏa, do Giao Bằng cưỡi. Giao Bằng lệnh nó xông xuống huyết tẩy Thạch Thôn. Khi con Phi Giao đang há mồm xông tới, một đạo ánh sáng óng ánh xông lên — cành liễu non xanh biếc phát hào quang chọc thủng trời cao. Con Phi Giao mở to mắt, khiếp sợ tới cùng cực, gào thét một tiếng rồi bị cành liễu xanh biếc đâm thủng cơ thể khiến nó im bặt.","nguon":["@c0039"]},{"id":"ba-chim-non-dai-bang-tieu-thanh-tu-van","name":"Ba con chim non (Đại Bằng · Tiểu Thanh · Tử Vân)","cn":"","aliases":["Đại Bằng","Tiểu Thanh","Tử Vân"],"category":"khac","categoryLabel":"Khác","phamCap":"Dị cầm","soHuu":["Thạch Hạo"],"trangThai":"Bị nhiều thế lực thèm muốn","blurb":"Ba con chim non Thạch Hạo coi là bạn, hậu duệ Thái Cổ Ma Cầm, được nhiều thế lực đòi giao ra.","detail":"Đại Bằng, Tiểu Thanh và Tử Vân là ba con chim non mà Thạch Hạo coi là bạn, biểu hiện thân mật. Chúng là hậu duệ Thái Cổ Ma Cầm, tiềm năng lớn nên bị các cường giả thèm muốn đòi giao ra cùng bảo cốt Toan Nghê. Thạch Hạo kiên quyết tuyên bố ba con là của mình.","nguon":["@c0039"]},{"id":"canh-lieu-non-than-vat","name":"Cành liễu non","cn":"","aliases":["Xích thần trật tự"],"category":"than-khi","categoryLabel":"Thần khí","phamCap":"Thần vật","soHuu":["Liễu Thần (cây liễu Thạch Thôn)"],"trangThai":"Xuất hiện cứu Thạch Thôn","blurb":"Cành liễu non xanh biếc như điêu khắc bằng thần ngọc, phát hào quang xán lạn chọc thủng trời cao, đâm thủng cơ thể con Phi Giao.","detail":"Cành liễu non xanh biếc như điêu khắc bằng thần ngọc, phát ra hào quang xán lạn chọc thủng trời cao. Khi con Phi Giao đang xông tới định huyết tẩy Thạch Thôn, cành liễu đột nhiên xông lên khiến Phi Giao khiếp sợ tới cùng cực gào thét. Ngay sau đó cành liễu xanh biếc — ví như xích thần trật tự, rừng rực ánh sáng xanh — đâm thủng cơ thể con Phi Giao khiến nó im bặt. Vật được ví giống “xích thần trật tự”, ám chỉ uy năng và lai lịch phi thường.","nguon":["@c0039"]},{"id":"chat-dich-tinh-luyen-phi-giao","name":"Chất dịch tinh luyện từ Phi Giao","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","soHuu":[],"trangThai":"dang-co","blurb":"Giọt chất lỏng màu xám tỏa sức sống trên cành liễu, do cây liễu hấp thu tinh luyện từ thân Phi Giao.","detail":"Sau khi Liễu Thần giết Phi Giao và hút tinh khí, thân nó phân hủy rơi thành mấy khối; chất dịch tinh luyện được cây liễu hấp thu, đọng thành giọt màu xám tỏa sức sống trên cành liễu.","nguon":["@c0040"]},{"id":"xuong-quy-toan-nghe-chi-bao","name":"Xương quý Toan Nghê (phù văn chí bảo)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Chí bảo","soHuu":[],"trangThai":"dang-co","blurb":"Chí bảo xương quý Toan Nghê kèm phù văn Toan Nghê mà đám Kim Lang cho là có ở Thạch thôn.","detail":"Ba Đồ báo tin rằng trong thôn cổ có xương quý Toan Nghê chí bảo cùng hậu duệ ma cầm Thái cổ, kèm phù văn Toan Nghê. Tin này khiến các đại tộc và Chí cường giả trong phạm vi hai mươi lăm ngàn cây số chấn động kéo về tranh đoạt.","nguon":["@c0041"]},{"id":"son-bao-dai-hoang","name":"Sơn bảo (Đại Hoang)","category":"khac","categoryLabel":"Bảo vật","phamCap":"","soHuu":[],"trangThai":"","blurb":"Bảo vật ẩn trong dãy núi hai năm chưa bị tìm ra, đồn là thánh dược tự bay hoặc thứ còn sống.","detail":"Bảo vật ẩn hai năm trong dãy núi Thương Mãng thuộc vùng Đại Hoang, được đồn đoán là thánh dược có thể tự bay hoặc là thứ còn sống. Chí cường bí ẩn cho Di Chủng Thái Cổ lùa bầy thú dọn bãi để bảo vật này sắp xuất thế.","nguon":["@c0042"]},{"id":"bao-cu-da-soi-kim-lang","name":"Bảo Cụ da sói (Kim Lang)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cực hiếm","soHuu":["Tộc trưởng bộ lạc Kim Lang"],"trangThai":"dang-co","blurb":"Lớp da cũ con Tế Linh Kim Lang lột ra, tế luyện thành Bảo Cụ hoàn chỉnh, hào quang vàng, sinh động như Thần Lang sống.","detail":"Sau khi con Tế Linh Kim Lang lột da hóa chân thân, lớp da vàng cũ được tế luyện thành một Bảo Cụ da sói hoàn chỉnh, tỏa hào quang vàng, sinh động như con Thần Lang sống, cực hiếm và mạnh mẽ, xông tấn công gốc rễ cây liễu cháy đen của Thạch Thôn.","nguon":["@c0043"]},{"id":"bao-cu-soi-than-kim-lang","name":"Bảo cụ da sói vàng kim (Sói thần)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Bộ lạc Kim Lang"],"trangThai":"hong","blurb":"Bảo cụ lột từ đệ nhất Tế linh, toàn thân như đúc hoàng kim.","detail":"Lột từ đệ nhất Tế linh trong bán kính hai mươi lăm nghìn cây số, toàn thân như đúc hoàng kim, vung vuốt phá rễ cây liễu; bị rễ cây vọt lên như Cầu Long cuộn kéo vào lòng đất, cắt gãy móng vuốt thành ba đoạn, da sói khô mục hóa phân bón.","nguon":["@c0044"]},{"id":"lang-nha-chuy","name":"Lang Nha Chủy","category":"phap-bao","categoryLabel":"Bảo Cụ / Tổ Khí","phamCap":"Tổ Khí","soHuu":["Tộc trưởng bộ lạc Kim Lang","Thần Lang"],"trangThai":"bi-cuop","blurb":"Tổ Khí của bộ lạc Kim Lang, dao găm vàng hình răng thú, chính là răng của một Tế Linh mạnh của cổ quốc.","detail":"Dao găm dài một thước toàn thân màu vàng, hình như răng thú mài thành, là răng của một Tế Linh mạnh của cổ quốc; thần tính đã bị cổ quốc lấy đi. Là Tổ Khí bộ lạc Kim Lang do tổ tiên lập công được cổ quốc ban thưởng. Khi tộc trưởng Kim Lang dùng nó chống cây liễu thì thất bại; sau đó Thần Lang xông tới cắn lấy Lang Nha Chủy rồi bỏ chạy mất, bị tộc lão coi là điềm bất tường.","nguon":["@c0045"]},{"id":"bao-cu-da-soi-vang-kim-lang","name":"Bảo Cụ da sói vàng (Kim Lang)","category":"phap-bao","categoryLabel":"Bảo Cụ","phamCap":"Bảo Cụ","soHuu":["Bộ lạc Kim Lang"],"trangThai":"hong","blurb":"Tấm da màu vàng ra oai tấn công Thần Lang, bị cây liễu hủy.","detail":"Bảo Cụ da sói màu vàng của bộ lạc Kim Lang, được điều động ra oai tấn công Thần Lang trong lúc hỗn chiến, sau bị cây liễu hủy diệt.","nguon":["@c0045"]},{"id":"bao-cu-the-than-tu-son-hau","name":"Bảo Cụ thế thân của Tử Sơn Hầu","category":"phap-bao","categoryLabel":"Bảo Cụ","phamCap":"Bảo Cụ","soHuu":["Tử Sơn Hầu"],"trangThai":"hong","blurb":"Bảo Cụ ngưng tụ thành hình người chịu chết thay cho Tử Sơn Hầu.","detail":"Ngưng tụ thành hình người khổng lồ màu tím chịu chết thay giúp Tử Sơn Hầu trốn thoát; bị cành liễu đâm xuyên lấy tinh hoa thần tính, còn Tử Sơn Hầu thì thoát nạn.","nguon":["@c0045"]},{"id":"con-sat-khong-lo","name":"Côn sắt khổng lồ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Sinh vật dùng côn sắt"],"trangThai":"dang-co","blurb":"Thanh côn sắt to như cột chống trời của đối thủ sinh vật mắt xanh, được ký hiệu nguyên thủy gia trì tăng thần uy.","detail":"Trong đại chiến bốn sinh vật cực mạnh sâu trong Thương Mãng Sơn Mạch, sinh vật khổng lồ dùng thanh côn sắt to như cột chống trời đánh trả sinh vật mắt xanh; thanh côn được ký hiệu nguyên thủy gia trì khiến thần uy tăng mạnh.","nguon":["@c0046"]},{"id":"hon-don-chi-bao-thanh-vat","name":"Hỗn độn chí bảo","cn":"","aliases":["Thánh vật (chưa rõ danh)"],"category":"khac","categoryLabel":"Bảo vật trục","phamCap":"Truyền thuyết","soHuu":[],"trangThai":"dang-co","blurb":"Báu vật xuất thế ở trung tâm Thương Mãng Sơn Mạch, tiên quang xông trời, là mục tiêu tranh đoạt của bốn sinh vật cực mạnh.","detail":"Ở trung tâm Thương Mãng Sơn Mạch, loạn thạch vỡ nát, tiên quang xông trời — hỗn độn chí bảo xuất thế. Bốn sinh vật cực mạnh quyết đấu sinh tử để tranh đoạt báu vật vừa đào được. Danh tính thật chưa rõ.","nguon":["@c0046"]},{"id":"thanh-vat-trang-non-ong-anh","name":"Thánh vật (trắng nõn óng ánh)","cn":"","category":"khac","categoryLabel":"Bảo vật","phamCap":"Thánh vật","soHuu":[],"trangThai":"Bị tứ đại sinh linh Chí tôn tranh đoạt; đổi chủ nhiều lần, sau bị hung cầm mắt trăng máu bắt được","blurb":"Bảo vật trắng nõn óng ánh mà tứ đại sinh linh Chí tôn quyết chiến tranh đoạt tại dãy núi Thương Mãng.","detail":"Thánh vật hình dạng trắng nõn óng ánh, là tâm điểm cuộc quyết chiến của bốn sinh linh Chí tôn tại dãy núi Thương Mãng. Trong trận đại chiến, thánh vật đổi chủ nhiều lần nhưng không con nào thật sự lấy được, khiến chiến trường lan rộng ngàn dặm và hủy diệt cả dãy núi Thương Mãng thành núi cụt. Cuối cùng một con hung cầm khổng lồ mắt trăng máu (Thôn Thiên Tước) bắt được rồi bay ra xa.","nguon":["@c0048"]},{"id":"bao-xuong-nguyen-thuy-di-chung-thai-co","name":"Bảo xương Nguyên thủy Di chủng Thái cổ","cn":"","category":"khac","categoryLabel":"Trấn vật","phamCap":"Bảo xương Nguyên thủy Thái cổ","soHuu":[],"trangThai":"Không đủ ngăn tứ đại sinh linh, vùng núi loạn thạch phá trời","blurb":"Mười mấy khối bảo xương nguyên thủy Di chủng Thái cổ vốn trấn giữ vùng núi Thương Mãng.","detail":"Gồm mười mấy khối Bảo xương của Di chủng Thái cổ nguyên thủy, vốn dùng để bảo vệ và trấn giữ vùng núi Thương Mãng. Khi tứ đại sinh linh Chí tôn quyết chiến tranh đoạt Thánh vật, các khối bảo xương này không đủ sức bảo vệ nổi vùng núi, khiến nơi đây loạn thạch phá trời và cuối cùng cả dãy núi bị hủy diệt thành núi cụt.","nguon":["@c0048"]},{"id":"con-sat-sinh-linh-chi-ton","name":"Côn sắt (của sinh linh cầm côn)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí tôn sinh linh","soHuu":[],"trangThai":"dang-co","blurb":"Binh khí khổng lồ của sinh linh chí tôn cầm côn, quét sụp cả vòm trời khi đối đầu Thôn Thiên Tước.","detail":"Một thanh côn sắt khổng lồ do sinh linh chí tôn ẩn trong sương mù cầm giữ, một cú quét có thể sụp cả vòm trời, dùng đối đầu với Thôn Thiên Tước trong trận đại chiến tứ chí tôn.","nguon":["@c0049"]},{"id":"long-tu-ngu","name":"Long Tu Ngư","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Cực phẩm","soHuu":[],"trangThai":"dang-co","blurb":"Cá lớn vảy vàng phẩm chất cực tốt, hai râu rồng óng ánh, giàu linh tính, ăn thường xuyên cường gân tráng cốt.","detail":"Loài cá lớn sống ở con sông vùng đất mới, vảy vàng phẩm chất cực tốt, bên miệng mọc hai râu rồng óng ánh phát mùi thơm, nặng mười mấy cân, giàu linh tính. Thạch Vân Phong nhận ra ăn thường xuyên có thể cường gân tráng cốt tăng sức mạnh, dặn không được bắt giết tùy tiện để chúng sinh sống quanh năm.","nguon":["@c0050","@c0052"]},{"id":"ngu-sac-ke","name":"Ngũ Sắc Kê","aliases":["Tiểu Loan Điểu"],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Chim lông rực rỡ dài hơn hai mét sinh trưởng giống Loan Điểu, là thuốc bổ cốt liền xương thần kỳ.","detail":"Đàn chim lông rực rỡ dài hơn hai mét ở hồ xanh biếc vùng đất mới, sinh trưởng giống Loan Điểu, còn gọi Tiểu Loan Điểu. Là thuốc bổ cốt — đun cả thịt lẫn xương ăn giúp liền xương thần kỳ. Thạch Vân Phong dặn không được bắt giết tùy tiện.","nguon":["@c0050","@c0051"]},{"id":"long-do-tin-vat-tuoc-do","name":"Lông đỏ (tín vật tước đỏ)","category":"khac","categoryLabel":"Tín vật","phamCap":"Vật thường (thần tính đã bị thu lại)","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Chiếc lông đỏ rực tước đỏ rơi lại làm tín vật cho Thạch Thôn.","detail":"Trước khi bay đi, tước đỏ để lại một cọng lông đỏ rực đẹp mắt làm tín vật cho thôn nhân, dặn nếu có người tìm phiền toái thì cứ lấy ra; nhưng nó đã hít thu lại thần tính từ chiếc lông, chỉ còn là lông thường.","nguon":["@c0051"]},{"id":"giot-nuoc-tien-chau-lieu-than","name":"Giọt nước Tiên Châu của Liễu Thần","category":"khac","categoryLabel":"Linh vật","phamCap":"Không rõ","soHuu":["Liễu Thần"],"trangThai":"da-dung","blurb":"Giọt nước trong suốt như Tiên Châu do cành liễu tiết ra, trị lành mọi vết thương.","detail":"Cây liễu cháy đen phát hào quang xanh, cành liễu tiết ra giọt nước trong suốt như Tiên Châu có hào quang và hương thơm; chữa lành vết thương xuyên bụng ngực và các lỗ trên đầu tước đỏ, khử hết ký hiệu phá hủy sinh cơ.","nguon":["@c0051"]},{"id":"long-can-xa","name":"Long Cân Xà","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Bảo dược hiếm thấy","soHuu":["Thạch thôn"],"trangThai":"Bảo dược của Thạch thôn phát hiện tại nơi định cư mới","blurb":"Rắn gân rồng cực hung, gân hầm nhừ ăn vào cường tráng gân cốt, bảo dược hiếm thấy.","detail":"Long Cân Xà (rắn gân rồng) là loài rắn cực hung được thôn nhân Thạch thôn phát hiện một năm sau khi định cư tại vùng đất mới. Gân của nó đem hầm nhừ, ăn vào có công hiệu cường tráng gân cốt, được xem là một loại bảo dược hiếm thấy, quý giá cho việc rèn luyện thân thể.","nguon":["@c0052"]},{"id":"trung-xich-vu-hac-tieu-loan-dieu","name":"Trứng Xích Vũ Hạc / Tiểu Loan Điểu","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Bảo dược","soHuu":[],"trangThai":"da-dung","blurb":"Trứng chim dị cầm ở hồ Thạch thôn, nướng lên là bảo dược bổ dưỡng, ăn vào đỏ ran cả người.","detail":"Trứng của Xích Vũ Hạc (dài mấy mét, đỏ như lửa) và Tiểu Loan Điểu ở hồ xanh ngọc bích Thạch thôn. Mao Cầu trộm hai mươi mấy quả, đám nhóc nướng ăn — là bảo dược bổ dưỡng, ăn vào đỏ ran cả người.","nguon":["@c0054"]},{"id":"co-kim-ti-lot-to","name":"Cỏ Kim Ti","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":[],"trangThai":"","blurb":"Loại cỏ mềm mại lót trong tổ hung cầm Thanh Lân Ưng.","detail":"Cỏ Kim Ti là loại cỏ mềm mại được Thanh Lân Ưng dùng lót trong tổ; giữa lớp cỏ mềm ẩn giấu các tấm vảy kim loại sắc bén khiến Thạch Đại Tráng dẫm phải tóe máu chân.","nguon":["@c0008"]},{"id":"tui-da-thu-cat-trung","name":"Túi da thú","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":["Thạch Đại Tráng","Nhị Mãnh","Bì Hầu"],"trangThai":"dang-co","blurb":"Túi da thú lũ trẻ mang theo để cất ba quả trứng Thanh Lân Ưng.","detail":"Túi da thú là vật dụng lũ trẻ Thạch Thôn mang theo khi vào rừng; ba đứa lớn mỗi đứa vác một quả trứng Thanh Lân Ưng cất vào túi trước khi leo xuống vách đá rời đi.","nguon":["@c0008"]},{"id":"dinh-den-bao-dinh-che-thuoc-thach-thon","name":"Đỉnh đen bảo đỉnh chế thuốc (Cổ khí tộc)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thạch Vân Phong"],"trangThai":"dang-co","blurb":"Đỉnh đen thường ngày của Thạch Thôn, khi luyện lộ ra là bảo đỉnh chế thuốc thần dị.","detail":"Đỉnh đen khắc sơn hà nhật nguyệt chim muông. Khi luyện tẩy lễ, hoa văn sống dậy chân thực, phù văn tự cháy, hiện lên tiên dân thượng cổ và âm thanh tế tự tụng kinh; tiên dân và tiếng tụng kinh trên vách đỉnh trấn áp các Di chủng Thái cổ bị nhốt bên trong. Thạch Vân Phong nhận ra đỉnh có biểu hiện giống đỉnh của các bộ tộc lớn, gợi mở nguồn gốc phi thường của Cổ khí tộc.","nguon":["@c0032"]},{"id":"manh-than-tinh-toan-nghe","name":"Mảnh vỡ thần tính Toan Nghê","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"da-dung","blurb":"Mảnh thần tính do tổ hoàng Thái cổ Toan Nghê truyền thừa, đã chết không có ý thức thật.","detail":"Màu vàng kim dài hơn một thước, giãy dụa xông ra rít gào khi đỉnh chấn động. Là mảnh vỡ thần tính từ tổ hoàng Thái cổ Toan Nghê, đã chết không có ý thức thật. Bị các điểm sáng quanh nhóc tỳ tịnh hóa, tan rã thành chùm sáng thần tính dung vào huyết thanh để tẩm bổ thân nhóc tỳ.","nguon":["@c0032"]},{"id":"dinh-hong-van-tam-ngan-can","name":"Đỉnh Hống văn tám nghìn cân","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Đỉnh nặng nhất trong tộc, khắc một con Hống hung dữ, dùng thử thần lực.","detail":"Đỉnh nặng tám nghìn cân khắc một con Hống hung dữ, là đỉnh nặng nhất trong tộc. Sau lột xác, nhóc tỳ nâng lần lượt đỉnh đồng nghìn cân, đỉnh hắc kim năm ngàn cân rồi cuối cùng nâng đỉnh Hống văn tám nghìn cân qua đỉnh đầu để thử thần lực.","nguon":["@c0032"]},{"id":"vong-xuong-phat-sang-tu-son-con","name":"Vòng xương phát sáng","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tử Sơn Côn"],"trangThai":"dang-co","blurb":"Vòng xương đeo trên ngón cái Tử Sơn Côn, phát sáng phá giải lực đạo giúp tay không gãy khi đón chưởng Thạch Hạo.","detail":"Khi đón chưởng của Thạch Hạo, tay Tử Sơn Côn đau như rạn xương, nhờ vòng xương trên ngón cái phát sáng phá giải lực đạo mới không bị gãy.","nguon":["@c0038"]},{"id":"long-tuyet-van-thien-cung","name":"Lông tuyết","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Ông lão Vân Thiên Cung"],"trangThai":"dang-co","blurb":"Một cái lông tuyết do ông lão Vân Thiên Cung cầm trong tay.","detail":"Vật phẩm ông lão đến từ Vân Thiên Cung mang theo khi được mời làm trọng tài trận đấu.","nguon":["@c0038"]},{"id":"to-khi-thach-thon","name":"Hai món tổ khí của Thạch Thôn","category":"than-khi","categoryLabel":"Thần khí","phamCap":"Không rõ","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Hai món tổ khí của Thạch Thôn, vật rơi ra từ thân chủng tộc Thái Cổ siêu cấp.","detail":"Hai món tổ khí của Thạch Thôn là vật rơi ra từ thân hai con thuộc chủng tộc Thái Cổ siêu cấp, sau khi được mài giũa tế luyện trở thành vật báu đáng sợ của bộ tộc.","nguon":["@c0012","@c0011"]},{"id":"dinh-den-duoc-dinh-co","name":"Đỉnh đen (dược đỉnh cổ Thạch thôn)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Dược đỉnh cổ","soHuu":["Thạch thôn"],"trangThai":"dang-co","blurb":"Đỉnh đen tổ tiên Thạch thôn truyền lại, lộ ra là bảo đỉnh chế thuốc cổ ghê gớm khi luyện dược.","detail":"Đỉnh đen tổ tiên Thạch thôn truyền lại, thường ngày không đáng chú ý. Khi luyện thuốc lộ ra là bảo đỉnh chế thuốc cổ: vách khắc sơn hà nhật nguyệt, chim muông ngư trùng chân thực như sắp sống lại, phù văn tự cháy, tiên dân thượng cổ hiện lên, phát khí tức cổ xưa cùng âm thanh tế tự và tiếng tụng kinh vang vọng.","nguon":["@c0032"]},{"id":"sung-bo-ma-ly-hoa","name":"Sừng quý Bò ma Ly Hỏa","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Chân huyết Thái cổ","soHuu":["Thạch thôn"],"trangThai":"da-dung","blurb":"Sừng đỏ thẫm sáng chói chứa chân huyết Di chủng Thái cổ, đổ vào đỉnh đợt tẩy lễ hai.","detail":"Sừng quý màu đỏ thẫm sáng chói của Bò ma Ly Hỏa, chứa chân huyết Thái cổ; Thạch Lâm Hổ trích máu đổ vào đỉnh trong đợt tẩy lễ thứ hai của nhóc tỳ.","nguon":["@c0032"]},{"id":"canh-tay-vuon-ac-ma","name":"Cánh tay Vượn Ác ma","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Chân huyết Thái cổ","soHuu":["Thạch thôn"],"trangThai":"da-dung","blurb":"Cánh tay Vượn Ác ma chứa chất lỏng màu đen, đổ vào đỉnh đợt tẩy lễ hai.","detail":"Cánh tay của Vượn Ác ma chứa chất lỏng màu đen (chân huyết Di chủng Thái cổ); Thạch Lâm Hổ trích đổ vào đỉnh trong đợt tẩy lễ thứ hai của nhóc tỳ.","nguon":["@c0032","@c0025"]},{"id":"dinh-dong-nghin-can","name":"Đỉnh đồng nghìn cân","category":"khac","categoryLabel":"Khác","phamCap":"Nghìn cân","soHuu":["Nhóc tỳ"],"trangThai":"dang-co","blurb":"Đỉnh đồng nặng nghìn cân nhóc tỳ từng nâng được.","detail":"Đỉnh đồng nặng nghìn cân, một trong những vật nhóc tỳ từng nâng được thể hiện thần lực.","nguon":["@c0032"]},{"id":"dinh-hac-kim-nam-ngan-can","name":"Đỉnh hắc kim năm ngàn cân","category":"khac","categoryLabel":"Khác","phamCap":"Năm ngàn cân","soHuu":["Thạch thôn"],"trangThai":"dang-co","blurb":"Đỉnh hắc kim nặng năm ngàn cân nhóc tỳ nâng lên trong màn thử thần lực.","detail":"Đỉnh hắc kim nặng năm ngàn cân, nhóc tỳ nâng lên trong màn thử thần lực sau khi lột xác.","nguon":["@c0032"]},{"id":"dinh-den-che-thuoc","name":"Đỉnh đen (bảo đỉnh chế thuốc Cổ khí tộc)","aliases":["Đỉnh đen","Dược đỉnh Cổ khí tộc"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo đỉnh chế thuốc thần dị","soHuu":["Thạch Vân Phong"],"trangThai":"dang-co","blurb":"Đỉnh dày nặng vốn dùng thường ngày của Cổ khí tộc, hóa ra là một bảo đỉnh chế thuốc thần dị tổ truyền.","detail":"Đỉnh to màu đen khắc sơn hà nhật nguyệt chim muông ngư trùng trên vách. Khi luyện thuốc, hoa văn trở nên chân thực, phù văn tự cháy, hiện tiên dân thượng cổ cùng âm thanh tế tự tụng kinh, trấn áp các Di chủng Thái cổ. Dùng làm nơi tẩy lễ cho nhóc tỳ, chứa huyết thanh Toan Nghê cùng chân huyết Bò ma Ly Hỏa và Vượn Ác ma. Tộc trưởng Thạch Vân Phong kinh dị nhận ra đây là một tòa dược đỉnh ghê gớm do tổ tiên truyền lại.","nguon":["@c0032"]},{"id":"dinh-hong-van-tam-nghin-can","name":"Đỉnh Hống văn tám nghìn cân","aliases":["Đỉnh Hống văn"],"category":"khac","categoryLabel":"Khác","phamCap":"Đỉnh nặng nhất trong tộc","soHuu":["Thạch thôn"],"trangThai":"dang-co","blurb":"Đỉnh nặng nhất trong tộc, khắc một con Hống hung dữ, dùng thử thần lực nhóc tỳ.","detail":"Đỉnh nặng tám nghìn cân, khắc hình một con Hống hung dữ, là đỉnh nặng nhất trong Thạch thôn. Sau khi lột xác, nhóc tỳ lần lượt nâng đỉnh đồng nghìn cân, đỉnh hắc kim năm ngàn cân, cuối cùng nâng được đỉnh Hống văn tám nghìn cân qua đỉnh đầu, chứng tỏ thần lực phi thường.","nguon":["@c0032"]},{"id":"dinh-hac-kim","name":"Đỉnh hắc kim (năm ngàn cân)","category":"khac","categoryLabel":"Khác","phamCap":"Đỉnh thử sức nặng năm ngàn cân","soHuu":["Thạch thôn"],"trangThai":"dang-co","blurb":"Một trong các đỉnh dùng thử sức nhóc tỳ sau lột xác.","detail":"Đỉnh hắc kim nặng năm ngàn cân, được nhóc tỳ nâng lên trong lúc thử thần lực trước khi nâng đỉnh Hống văn tám nghìn cân.","nguon":["@c0032"]},{"id":"huyet-thanh-vang-kim-toan-nghe","name":"Huyết thanh vàng kim (dược dịch Toan Nghê)","category":"khac","categoryLabel":"Dược dịch","phamCap":"Chưa rõ","soHuu":[],"trangThai":"da-dung","blurb":"Chất lỏng vàng kim đặc sôi trong đỉnh đen, sinh ra dược hồn Toan Nghê.","detail":"Huyết thanh vàng kim đặc sôi trào trong đỉnh đen dùng cho tẩy lễ; sinh ra một con Toan Nghê vàng kim — mảnh vỡ thần tính truyền thừa từ tổ hoàng Thái cổ Toan Nghê — dài hơn một thước. Trong tẩy lễ, chất lỏng này xông vào cơ thể nhóc tỳ qua lỗ chân lông, tẩm bổ xương thịt cho tới khi gần cạn thì lột xác lần một hoàn tất.","nguon":["@c0032"]},{"id":"dinh-den-gia-truyen","name":"Đỉnh đen gia truyền","aliases":["Dược đỉnh","Bảo đỉnh chế thuốc"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thạch thôn","Thạch Vân Phong"],"trangThai":"dang-co","blurb":"Đỉnh đen dày nặng gia truyền của Cổ khí tộc, hóa ra là một dược đỉnh ghê gớm.","detail":"Đỉnh đen dày nặng của Cổ khí tộc, khắc sơn hà nhật nguyệt chim muông ngư trùng. Khi luyện dược, phù văn tự cháy, hoa văn sống động như sắp sống lại, có tiếng tế tự và tụng kinh của tiên dân thượng cổ vang lên. Thạch Vân Phong kinh dị nhận ra nó vốn là một dược đỉnh ghê gớm giống đỉnh của các bộ tộc lớn, dùng để chủ trì tẩy lễ cho nhóc tỳ.","nguon":["@c0032"]},{"id":"dinh-den-bao-dinh-che-thuoc","name":"Đỉnh đen (bảo đỉnh chế thuốc)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo đỉnh chế thuốc","soHuu":["Thạch Vân Phong"],"trangThai":"dang-co","blurb":"Đỉnh đen tổ tiên Cổ khí tộc truyền lại, thường ngày không đáng chú ý nhưng thực chất là một tòa dược đỉnh chế thuốc ghê gớm.","detail":"Đỉnh to màu đen do tổ tiên Thạch thôn truyền lại. Trong quá trình tẩy lễ cho nhóc tỳ, đỉnh tỏa bảo quang, vách khắc sơn hà nhật nguyệt chim muông sống động, phù văn tự cháy, hiện lên hình tiên dân thượng cổ tụng kinh và cộng minh với nhóc tỳ. Thạch Vân Phong kinh dị nhận ra đây thật sự là một bảo đỉnh chế thuốc.","nguon":["@c0032"]},{"id":"hac-dinh","name":"Hắc đỉnh","cn":"","aliases":["Đỉnh to màu đen","Dược đỉnh Cổ khí tộc"],"category":"phap-bao","categoryLabel":"Dược đỉnh","phamCap":"Dược đỉnh cổ","soHuu":[],"trangThai":"dang-co","blurb":"Đỉnh đen dày nặng tổ tiên Cổ khí tộc truyền lại, thường ngày không đáng chú ý nhưng thật ra là một tòa dược đỉnh cổ ghê gớm.","detail":"Cái đỉnh đen thường ngày chẳng ai để ý, dùng để tẩy lễ cho nhóc tỳ. Khi luyện thuốc, hoa văn sơn hà nhật nguyệt chim muông ngư trùng trên đỉnh trở nên chân thực như sắp sống lại, tỏa khí tức cổ xưa; phù văn trên vách đỉnh tự cháy sáng, vang tiếng hung cầm mãnh thú lẫn tiếng tế tự tụng kinh, hiện lên tiên dân thượng cổ, mặt đỉnh dần trong suốt luyện hóa huyết thanh. Thạch Vân Phong kinh dị nhận ra đây là một tòa dược đỉnh cổ ghê gớm, có cùng biểu hiện với đỉnh của các bộ tộc lớn.","nguon":["@c0032"]},{"id":"duoc-hon-toan-nghe","name":"Dược hồn Toan Nghê","cn":"","aliases":["Mảnh vỡ thần tính Toan Nghê"],"category":"dan-duoc","categoryLabel":"Dược hồn","phamCap":"Truyền thừa Thái cổ","soHuu":["Nhóc tỳ"],"trangThai":"da-dung","blurb":"Con Toan Nghê vàng kim dài hơn một thước — mảnh vỡ thần tính truyền thừa từ tổ hoàng Thái cổ Toan Nghê, tinh hoa dược tính trong hắc đỉnh.","detail":"Dược hồn hình con Toan Nghê màu vàng kim, không có ý thức thật, tự thiêu đốt và va chạm điên cuồng vào nắp đỉnh muốn xông ra. Trong quá trình tẩy lễ, nhóc tỳ dùng thần tính và vô số điểm sáng như thần linh tụng kinh dẫn dắt, tịnh hóa và dung luyện nó; con Toan Nghê giãy dụa né tránh rồi tan rã, bị hắc đỉnh luyện hóa thành các chùm sáng thần tính vàng kim dung nhập huyết dịch nhóc tỳ.","nguon":["@c0032"]},{"id":"dinh-dong-thach-thon","name":"Đỉnh đồng xanh nghìn cân","category":"khac","categoryLabel":"Vật phẩm","soHuu":[],"trangThai":"dang-co","blurb":"Đỉnh đồng xanh nặng ngàn cân dùng làm vật thử sức của bọn trẻ Thạch Thôn.","detail":"Vật thử sức đặt ở Thạch Thôn; Thạch Hạo, Thạch Đại Tráng và Thạch Mãnh từng nâng hoặc gần nâng được đỉnh đồng này. Việc nâng được đỉnh đưa Thạch Hạo trở thành phần tử nòng cốt trong đám trẻ.","nguon":["@c0007"]},{"id":"cung-lon-sung-rong","name":"Cung lớn sừng rồng","category":"phap-bao","categoryLabel":"Vũ khí","phamCap":"Không rõ","soHuu":["Thạch Lâm Hổ","Bái Phong"],"trangThai":"dang-co","blurb":"Cung lớn màu đen cao quá nửa thân người làm từ sừng rồng, dùng đấu tiễn.","detail":"Cây cung lớn màu đen làm từ sừng rồng, cao quá nửa thân người. Cả Thạch Lâm Hổ và Bái Phong đều dùng loại cung này để đấu tiễn — hai bên bắn liên tiếp mười mấy mũi tên va chạm nhau giữa không trung, không phân cao thấp. (@c0014)","nguon":["@c0014"]},{"id":"cung-lon-ten-sat-bai-phong","name":"Cung lớn và tên sắt của Bái Phong","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Bái Phong"],"trangThai":"dang-co","blurb":"Cung lớn cao hơn nửa người kèm tên sắt to dài của Bái Phong.","detail":"Cung lớn cao hơn nửa người, tên sắt to dài bắn nứt kim loại, đủ bắn chết Long Giác Tượng. Bái Phong dùng bắn liên tiếp tám mũi tên sắt nhắm chỗ yếu hại Thạch Hạo nhưng bị né năm mũi và đánh bay ba mũi cắm sâu vào đá.","nguon":["@c0015"]},{"id":"truong-mau-huyet-van-thiet","name":"Trường mâu Huyết Văn Thiết","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Bái Phong"],"trangThai":"hong","blurb":"Trường mâu màu đỏ đậm làm bằng Huyết Văn Thiết của Bái Phong.","detail":"Trường mâu màu đỏ đậm chế từ Huyết Văn Thiết, được Bái Phong dùng đâm ngực Thạch Hạo. Bị Thạch Hạo vung tay phải tạo quỹ tích phát sáng chém đứt thành hai đoạn mà tay trắng nõn không bị tổn thương; mâu gãy sau đó bị Bái Phong ném nhắm mắt phải Thạch Hạo.","nguon":["@c0015"]},{"id":"bao-cu-rang-thu","name":"Bảo cụ răng thú (42 răng)","aliases":["vòng răng thú","xâu chuỗi răng thú (42 răng)","Bảo Cụ của Bái Phong"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thạch Hạo","Bái Phong"],"trangThai":"dang-co","blurb":"Xâu 42 răng thú trắng như mỡ dê đá ngọc, do Bảo cốt Tế linh làm thành, chí bảo của Bái thôn.","detail":"Bảo cụ gồm 42 cái răng thú trắng như mỡ dê đá ngọc, do Bảo cốt Tế linh làm thành. Có thể tụ tán, hóa thành hạt sáng, mưa sao băng, quái thú sói, vũ khí (chủy thủ, mũi tên) và chiến y; từng đâm thủng đá lớn 6-7 mét như cái sàng. Do Tế linh ban cho Bái thôn; khi Tế linh còn sống thì người được ban không cần Cốt văn cũng dùng được. Trong trận, 42 răng thú bị đánh rơi rụng rồi bị nhóc tỳ (Thạch Hạo) cướp và đeo lên cổ tay.","nguon":["@c0024"]},{"id":"xau-chuoi-rang-thu-nhoc-ty","name":"Xâu chuỗi răng thú","cn":"","category":"phap-bao","categoryLabel":"Bảo cụ","phamCap":"Bảo cụ khắc phù văn","soHuu":["Nhóc tỳ"],"trangThai":"Nhóc tỳ đang dùng","blurb":"Xâu 42 cái răng thú trắng đeo cổ tay nhóc tỳ, khắc phù văn, uy lực cực mạnh.","detail":"Bảo cụ gồm xâu chuỗi 42 cái răng thú trắng đeo ở cổ tay nhóc tỳ, được khắc phù văn. Khi vận dụng, các răng thú tách ra bay tán loạn như mưa ánh sáng, phóng hào quang trắng loáng xuyên thủng thân thể rất nhiều người, có thể hóa thành chủy thủ bắn ra mũi tên ánh sáng. Nhóc tỳ hiểu Cốt văn nên khi điều khiển Bảo cụ khiến uy lực mạnh mẽ hơn nhiều lần so với xâu răng thú từng ở trong tay Bái Phong. Trong trận đánh, nhóc tỳ dùng Bảo cụ này khai sát giới với người Bái thôn khiến chúng suy sụp bỏ chạy, đồng thời phối hợp với trăng bạc chém đám sói biến dị làm đôi.","nguon":["@c0025"]},{"id":"sung-do-di-chung-thai-co","name":"Sừng đỏ dị chủng Thái cổ","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Chiến lợi phẩm quý","soHuu":["Thạch thôn"],"trangThai":"Được dùng chữa trị Thanh Lân Ưng","blurb":"Sừng đỏ chót như ngọc của dị chủng Thái cổ, móc máu tươi cho Thanh Lân Ưng ăn để chữa thương.","detail":"Một cây sừng đỏ chót như ngọc, là chiến lợi phẩm thuộc dị chủng Thái cổ. Thạch Vân Phong dùng thuốc nhuyễn và móc máu tươi từ sừng đỏ này cho Thanh Lân Ưng ăn để chữa thương. Về sau nó được đội Thạch Phi Giao vận chuyển cùng các chiến lợi phẩm khác khi Thạch thôn rút quân.","nguon":["@c0025"]},{"id":"son-bao-thanh-vat","name":"Sơn bảo","aliases":["Thánh vật","Thần vật kinh thế"],"category":"khac","categoryLabel":"Bảo vật trục","phamCap":"Kinh thiên","soHuu":[],"trangThai":"dang-co","blurb":"Vật kinh thiên đang dựng dục nơi sâu Đại Hoang, khiến các siêu cấp đại tộc kéo tới tranh đoạt.","detail":"Sơn bảo (còn gọi Thánh vật, Thần vật) là vật kinh thiên đang được dựng dục nơi sâu Đại Hoang. Suốt hai năm, Di chủng Thái cổ tranh đoạt chưa ngã ngũ. Tin tức khiến bộ lạc Ngựa vảy sừng, vương hầu mặt trời tím, Tử Sơn hầu, Lôi Hậu và gia tộc cổ núi tuyết đều cử lớp trẻ đi kiến thức, mở màn xung đột lớn.","nguon":["@c0028"]},{"id":"thien-dia-bao-duoc","name":"Thiên địa bảo dược","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Truyền thuyết","soHuu":[],"trangThai":"khong-ro","blurb":"Thuốc quý trong truyền thuyết Thạch Hạo hứa hái để chữa ám thương cho tộc trưởng.","detail":"Loại thiên địa bảo dược cực hiếm mà trong dân số mấy triệu người chưa chắc có được. Thạch Hạo hứa sẽ tìm hái để trị tận gốc thương tật cổ quái của tộc trưởng Thạch Vân Phong.","nguon":["@c0029"]},{"id":"khoi-xuong-trang-thach-van-phong","name":"Khối xương trắng trước ngực","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Chưa rõ","soHuu":["Thạch Vân Phong"],"trangThai":"dang-co","blurb":"Vật thần bí tộc trưởng mang trước ngực, sờ vào thì thân run rẩy.","detail":"Khối xương trắng bạch tộc trưởng Thạch Vân Phong giữ trước ngực. Cuối chương lão sờ vào nó rồi bỗng run rẩy một cơn, có vẻ liên quan mật thiết tới ám thương cổ quái của ông.","nguon":["@c0029"]},{"id":"chan-huyet-bo-ma-ly-hoa","name":"Chân huyết Bò ma Ly Hỏa","category":"dan-duoc","categoryLabel":"Dược liệu","phamCap":"Không rõ","soHuu":["Thạch thôn"],"trangThai":"da-dung","blurb":"Chân huyết quý trong sừng Bò ma Ly Hỏa, dùng giải độc và khôi phục.","detail":"Chân huyết trong sừng quý của Ly Hỏa Ngưu Ma, có công dụng giải độc; được Thạch thôn dùng khôi phục cho Thanh Lân Ưng giúp nó hồi phục hoàn toàn.","nguon":["@c0033"]},{"id":"bao-cung-ten-sat-thien-tai","name":"Bảo cung và tên sắt hàn quang","category":"phap-bao","phamCap":"Vũ khí của thiên tài niên thiếu","soHuu":["Giao Bằng","Tử Sơn Côn","Lôi Minh Viễn"],"trangThai":"dang-co","blurb":"Bảo cung kèm tên sắt hàn quang lực xuyên thấu kinh người, dùng để săn thú.","detail":"Vũ khí các thiên tài niên thiếu La Phù Đại Trạch, Tử Sơn Tộc, Lôi Tộc mang theo để săn ba con chim non Thanh Lân Ưng của Thạch Thôn. Giao Bằng bắn liên châu tiễn khiến Đại Bằng và Tiểu Thanh trúng tên rụng vảy. Bảo cung của Tử Sơn Côn về sau bị đỉnh đồng ngàn cân Thạch Hạo đá văng đánh gãy đôi.","nguon":["@c0037"]},{"id":"dinh-den-to-truyen-thach-thon","name":"Đỉnh đen tổ truyền (Thạch thôn)","cn":"","aliases":["Bảo đỉnh chế thuốc","Đỉnh thuốc màu đen"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Chiếc đỉnh màu đen tổ tiên Thạch thôn truyền lại, khắc hình tiền dân Thượng cổ cùng nhật nguyệt sơn hà.","detail":"Bảo vật tổ truyền của Thạch thôn. Khi cả tộc mang tế phẩm tế bái dưới gốc cây liễu, chiếc đỉnh rung nhẹ, hình điêu khắc tiền dân Thượng cổ và nhật nguyệt sơn hà hiện rõ hơn, có ánh sáng yếu ớt vòng quanh. Người Thạch thôn dùng nó chế thuốc nhưng chưa hiểu hết uy năng thần bí.","nguon":["@c0041"]},{"id":"bao-cu-the-than-la-phu","name":"Khối xương thú (Bảo cụ thế thân)","cn":"","category":"phap-bao","categoryLabel":"Bảo cụ","phamCap":"Không rõ","soHuu":["Chủ nhân La Phù Đại Trạch"],"trangThai":"hong","blurb":"Bảo cụ thế thân bằng xương thú của tộc chủ La Phù Đại Trạch.","detail":"Khi bị cành liễu truy sát tới con sông phương Tây, tộc chủ La Phù Đại Trạch dùng khối xương thú làm bảo cụ thế thân để tránh đòn, nhưng bị chồi non đánh nát hóa thành vụn xương, sau đó chính hắn bị chém đứt làm hai.","nguon":["@c0044"]},{"id":"bao-cu-da-soi-vang","name":"Bảo Cụ da sói vàng","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo Cụ","soHuu":[],"trangThai":"hong","blurb":"Tấm da màu vàng ra oai tấn công Thần Lang, bị cây liễu hủy diệt.","detail":"Một tấm da sói màu vàng dùng làm Bảo Cụ, xuất hiện trong cuộc tận diệt tứ đại cường giả để tấn công Thần Lang, nhưng lập tức bị cây liễu hủy chỉ trong nháy mắt.","nguon":["@c0045"]},{"id":"bao-cot-ngung-ky-hieu-nguyen-thuy","name":"Bảo cốt ngưng ký hiệu nguyên thủy","aliases":["Bảo cốt kỳ dị","bảo cốt kỳ dị"],"category":"khac","categoryLabel":"Bảo vật","phamCap":"Thái Cổ","soHuu":[],"trangThai":"dang-co","blurb":"Hơn mười khúc xương thú kỳ dị ngưng ký hiệu nguyên thủy, rơi ra khi bốn sinh vật đại chiến, trấn áp Thương Mãng Sơn Mạch.","detail":"Trong trận đại chiến sâu trong dãy núi nguyên thủy, hơn mười khúc bảo cốt rơi ra: có khúc đỏ như Huyết Toản, có khúc đen như mực, có khúc trắng óng ánh. Đây là bảo cốt ngưng kết ký hiệu nguyên thủy, rơi từ Thái Cổ Di Chủng, phân tán khắp Thương Mãng Sơn Mạch để ổn định núi sông.","nguon":["@c0046"]},{"id":"bao-cot-nguyen-thuy-tran-nui","name":"Bảo cốt nguyên thủy (trấn áp)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cực phẩm","soHuu":[],"trangThai":"hong","blurb":"Hơn mười mấy khối Bảo cốt nguyên thủy trấn áp dãy núi Thương Mãng, giữ sơn hà không bị đại chiến đánh tan hoang.","detail":"Nhờ hơn mười mấy khối Bảo cốt nguyên thủy trấn áp mà núi sông nơi tứ đại sinh linh huyết chiến không bị đánh tan hoang, phù văn sáng rực bao phủ dãy núi. Cuối chương Bảo cốt rốt cuộc không còn khóa nổi, khối Thánh vật xuyên phá phù văn, mở đường cho bốn sinh linh xông ra ngoài.","nguon":["@c0047"]},{"id":"chan-huyet-thai-co","name":"Chân huyết Thái Cổ","aliases":["Chân huyết chủng tộc Thái Cổ"],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Chưa rõ","soHuu":[],"trangThai":"dang-co","blurb":"Vật quý các tộc lớn dùng tôi luyện, tẩy rửa thân xác trẻ thiên tư.","detail":"Chân huyết chủng tộc Thái Cổ cùng thánh dược là bảo vật các tộc siêu cấp và lãnh địa vương hầu dùng tôi luyện trẻ thiên tư trong tẩy lễ; Thạch Thôn khởi điểm thấp không có, phải thay bằng huyết dược tích lũy từ máu mãnh thú. Chỉ chân huyết phẩm chất cao mới có tác dụng.","nguon":["@c0006"]},{"id":"dinh-dong","name":"Đỉnh đồng","aliases":[],"category":"khac","categoryLabel":"Khác","phamCap":"Phàm vật","soHuu":[],"trangThai":"dang-co","blurb":"Chiếc đỉnh lớn nặng ngàn cân trong thôn.","detail":"Chiếc đỉnh đồng lớn nặng ngàn cân mà Thạch Hạo mới ba tuổi nhấc bổng rồi ném xuống đất, khiến cả Thạch Thôn chấn động về thể chất phi thường của cậu.","nguon":["@c0006"]},{"id":"ac-ma-vien-vuong","name":"Ác Ma Viên Vương","aliases":["Vượn Ác Ma","Vược Ác Ma","Ác Ma Viên"],"category":"khac","categoryLabel":"Hung thú","phamCap":"Huyết thống vương giả cực cao","soHuu":[],"trangThai":"bi-thuong","blurb":"Vượn dữ đen có cánh và sừng, huyết thống vương giả cực cao, uy áp khiến vạn thú im bặt.","detail":"Từ sâu trong núi hàng lâm, uy áp khiến hung cầm mãnh thú run rẩy im bặt, giống như Cái Thế Ma Vương hàng lâm phát ra hung uy ngập trời. Đè đầu con Điêu Hùng dài mười mét thưởng thức, giẫm chân dọn sạch đá quanh Toan Nghê. Giằng co với Ly Hỏa Ngưu Ma tranh xác Toan Nghê; bất ngờ bị Toan Nghê tưởng đã chết bật dậy xé đứt một cánh tay.","nguon":["@c0020"]},{"id":"ten-sat-mau-sat-bai-thon","name":"Tên sắt và mâu sắt Bái Thôn","category":"khac","categoryLabel":"Vũ khí","soHuu":["Bái Thôn"],"trangThai":"dang-co","blurb":"Bộ vũ khí sắt của đội săn thú Bái Thôn dùng phục kích Thạch Hạo.","detail":"Tên sắt lạnh lẽo mỗi mũi ngàn cân, bắn ra với tốc độ vượt âm thanh, khiến Thạch Hạo phải nghiêng người mới tránh kịp mũi đầu tiên. Mâu sắt dài hai mét nặng mấy chục cân, uy lực đâm xuyên da Hỏa Tê, được Bái Thôn ném ra khi bị Bảo Nguyệt chém gãy tên. Cả hai loại vũ khí bị vầng trăng bạc của Thạch Hạo chém gãy và đánh rơi.","nguon":["@c0022"]},{"id":"vong-rang-thu","name":"Vòng răng thú (Bảo Cụ 42 răng thú)","cn":"","aliases":["Xâu chuỗi răng thú","Bảo cụ răng thú","Bảo cụ 42 răng thú"],"category":"phap-bao","categoryLabel":"Bảo cụ","phamCap":"Bảo cụ Tế linh","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Xâu 42 răng thú trắng như mỡ dê ngọc, do Bảo cốt Tế linh làm thành, có thể tụ tán biến hóa.","detail":"Bảo cụ gồm 42 cái răng thú, do Bảo cốt Tế linh Bái thôn làm thành, có thể tụ tán hóa thành hạt sáng, mưa sao băng, quái thú sói, vũ khí như chủy thủ, mũi tên hay chiến y; sức mạnh đâm thủng đá lớn sáu bảy mét như cái sàng. Bảo cụ do Tế linh ban cho, khi Tế linh còn sống thì người được ban không cần Cốt văn cũng dùng được, nếu Tế linh chết thì phải có Cốt văn mới điều khiển. Bái Phong dùng nó áp đảo nhóc tỳ nhưng bại trận; nhóc tỳ đoạt lấy và đeo lên cổ tay mình.","nguon":["@c0024"]},{"id":"to-khi-da-thu","name":"Tổ Khí (da thú)","cn":"","category":"than-khi","categoryLabel":"Tổ Khí","phamCap":"Tổ Khí (bảo vật bí truyền của Thạch Thôn)","soHuu":["Thạch Phi Giao","Thạch Hạo"],"trangThai":"Được dung hợp sử dụng trong trận chiến giữ thôn","blurb":"Tổ Khí thứ hai của Thạch Thôn — một miếng da thú cổ loang máu, dung hợp lên ngực người dùng để triệu ra hung thú giống Bệ Ngạn.","detail":"Là một trong hai Tổ Khí bí mật của Thạch Thôn, dưới hình dạng một miếng da thú cổ loang máu. Vốn nên do Thạch Phi Giao giữ, nhưng được ngầm giao cho nhóc tỳ Thạch Hạo vì Cốt Văn của cậu cao thâm hơn, phát huy được nhiều sức mạnh hơn. Khi ấn miếng da thú lên ngực, da thú và ngực dung hợp với nhau in dấu ở phía trên, ngưng thành cổ phù triệu ra hư ảnh hung thú giống Bệ Ngạn — đòn sát thủ ôm chân cắn giết, làm gãy và biến hình chân sau con Bái già, sau đó đánh vỡ nát nửa thân sau của nó. Cùng với Tổ Khí xương thú, đây là bảo vật không thể để lộ ánh sáng, nếu bị phát hiện sẽ khiến vài đại tộc ngấp nghé mà chuốc đại họa cho Thạch Thôn.","nguon":["@c0026"]},{"id":"binh-chan-huyet-hung-thu-tu-son","name":"Bình chân huyết hung thú (Tử Sơn Tộc)","category":"nguyen-lieu","categoryLabel":"Chân huyết","phamCap":"Hiếm","soHuu":["Chú ruột của Tử Sơn Hầu"],"trangThai":"dang-co","blurb":"Bình chân huyết hung thú cực hiếm do chú ruột Tử Sơn Hầu đặt cược cho cuộc so tài các thiên tài trẻ.","detail":"Vật đặt cược cực hiếm mà ông lão chú ruột Tử Sơn Hầu đưa ra cho ai thắng trong cuộc so tài của bọn trẻ các tộc tại Tiểu Cô Sơn Trấn.","nguon":["@c0030"]},{"id":"binh-mau-di-chung-la-phu","name":"Bình máu dị chủng hung cầm (La Phù)","category":"nguyen-lieu","categoryLabel":"Chân huyết","phamCap":"Hiếm","soHuu":["Người trung niên La Phù Đại Trạch"],"trangThai":"dang-co","blurb":"Bình máu dị chủng hung cầm do người trung niên La Phù Đại Trạch đặt cược.","detail":"Vật đặt cược của người La Phù Đại Trạch trong cuộc so tài giữa các thiên tài trẻ tại Tiểu Cô Sơn Trấn.","nguon":["@c0030"]},{"id":"xuong-tran-toan-nghe","name":"Xương trán Toan Nghê (Phù văn nguyên thủy)","cn":"","category":"khac","categoryLabel":"Bảo vật","phamCap":"Quý hiếm","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Khối xương trắng giữa trán Toan Nghê lưu Phù văn nguyên thủy.","detail":"Khối xương trắng to bằng lòng bàn tay, lấy từ giữa trán Toan Nghê, chứa Phù văn nguyên thủy để luyện Bảo thuật. Hoạt tính phù văn sẽ biến mất theo thời gian; nếu không kịp ghi nhớ trước lúc đó thì chỉ còn là Bảo cụ không thể luyện Bảo thuật. Thạch Vân Phong giao cho Thạch Hạo ghi nhớ.","nguon":["@c0033"]},{"id":"mui-ten-sat-mot-met-ba","name":"Mũi tên sắt to dài một mét ba","category":"khac","categoryLabel":"Vũ khí","soHuu":["Thiếu niên Bái Thôn"],"trangThai":"dang-co","blurb":"Mũi tên sắt to dài một mét ba, tốc độ nhanh hơn ánh chớp, xuyên thủng ba lớp áo giáp tinh cương.","detail":"Mũi tên sắt to dài một mét ba do thiếu niên Bái Thôn bắn, tốc độ nhanh hơn ánh chớp, xuyên thủng ba lớp áo giáp tinh cương và cắm sâu vào tảng đá núi.","nguon":["@c0014"]},{"id":"thai-co-di-chung-toan-nghe","name":"Bảo thể Toan Nghê (Thái Cổ Di Chủng)","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Chí bảo","soHuu":["Thạch Hạo"],"trangThai":"Bị Bái Thôn tranh đoạt","blurb":"Di thể của Toan Nghê chứa Thái Cổ chân huyết, được coi là chí bảo mà nhiều thế lực tranh cướp.","detail":"Di thể của mãnh thú Toan Nghê, bên trong hàm chứa Thái Cổ chân huyết cực kỳ quý giá. Mùi máu của nó khiến mãnh thú khắp vùng bị hấp dẫn kéo tới, đồng thời là mục tiêu tranh đoạt của Bái Thôn — Bái Lý Thanh nói Tế Linh của tộc sắp đột phá nên cần gấp một lượng chân huyết lớn. Thạch Hạo một mình thủ hộ bảo thể này, chém giết cả mãnh thú lẫn người Bái Thôn để bảo vệ.","nguon":["@c0023"]},{"id":"sung-bao-ly-hoa-nguu-ma","name":"Sừng bảo Ly Hỏa Ngưu Ma","aliases":["Sừng bảo đỏ thẫm","Sừng đỏ Ly Hỏa Ngưu Ma"],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Thạch Vân Phong"],"trangThai":"dang-co","blurb":"Sừng quý của Ly Hỏa Ngưu Ma, một trong ba vật liệu tẩy lễ của Thạch Thôn.","detail":"Sừng bảo lấy từ Ly Hỏa Ngưu Ma, được tộc trưởng Thạch Vân Phong dùng làm một trong ba vật liệu tẩy lễ cho Thạch Hạo cùng bảo thể Toan Nghê và tay Ác Ma Viên Vương.","nguon":["@c0030"]},{"id":"di-the-bao-cot-toan-nghe","name":"Di thể bảo cốt Toan Nghê","category":"nguyen-lieu","categoryLabel":"Nguyên liệu / Thánh vật","phamCap":"Thánh vật Thái cổ","soHuu":["Thạch thôn"],"trangThai":"dang-co","blurb":"Di thể/bảo cốt của một con Toan Nghê mà người Thạch thôn được cho là chiếm giữ, ẩn chứa Bảo thuật Phù văn nguyên thủy Toan Nghê.","detail":"Cường giả các thế lực suy ra Thạch thôn có thể chiếm được di thể một con Toan Nghê nên mới ẩn chứa Bảo thuật chí cường; suy đoán này khiến La Phù Đại Trạch, bộ lạc Kim Lang run sợ nhưng cũng đỏ mắt tham lam, mở ra xung đột tranh đoạt.","nguon":["@c0036"]},{"id":"bao-cung-cuong-gia","name":"Bảo cung","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Giao Bằng","Tử Sơn Côn","Lôi Minh Viễn"],"trangThai":"dang-co","blurb":"Bảo cung mà đám thiên tài Giao Long, Tử Sơn Côn, Lôi Minh Viễn lấy ra định bắn ba con chim non Đại Bằng, Tiểu Thanh, Tử Vân làm con mồi.","detail":"Khi ba con chim non biến dị lộ diện với chân huyết hung cầm Thái cổ, đám Giao Long, Tử Sơn Côn, Lôi Minh Viễn cùng lấy bảo cung ra coi ba con chim non là con mồi chuẩn bị bắt lại; hành động này khiến nhóc tỳ nổi giận gầm lên bảo vệ.","nguon":["@c0036"]},{"id":"dai-bang-di-cam","name":"Đại Bằng","category":"khac","categoryLabel":"Dị cầm","phamCap":"Hậu duệ Thái Cổ Ma Cầm","soHuu":["Thạch Hạo"],"trangThai":"Bạn thân của Thạch Hạo, bị các cường giả thèm muốn","blurb":"Một trong ba con chim non hậu duệ Thái Cổ Ma Cầm, được Thạch Hạo coi là bạn thân.","detail":"Đại Bằng là một trong ba con chim non được Thạch Hạo nuôi cùng ở Thạch Thôn, được xem như bạn thân thiết chứ không phải vật nuôi hay pháp bảo. Trong chương này, các cường giả La Phù Đại Trạch cùng nhiều thế lực khác đòi Thạch Thôn giao ba con chim non cùng bảo cốt Toan Nghê, nhưng Thạch Hạo tuyên bố Đại Bằng, Tiểu Thanh và Tử Vân là của mình, không đưa cho ai. Đại Bằng mang huyết mạch phi thường, được các thế lực lớn thèm muốn thu thập.","nguon":["@c0039"]},{"id":"tieu-thanh-di-cam","name":"Tiểu Thanh","category":"khac","categoryLabel":"Dị cầm","phamCap":"Hậu duệ Thái Cổ Ma Cầm","soHuu":["Thạch Hạo"],"trangThai":"Bạn thân của Thạch Hạo, bị các cường giả thèm muốn","blurb":"Một trong ba con chim non hậu duệ Thái Cổ Ma Cầm, được Thạch Hạo coi là bạn thân.","detail":"Tiểu Thanh là một trong ba con chim non được Thạch Hạo nuôi cùng ở Thạch Thôn, được coi là bạn của cậu bé chứ không phải sở hữu vật. Trong chương, các cường giả đòi giao nộp Tiểu Thanh cùng Đại Bằng và Tử Vân, nhưng Thạch Hạo kiên quyết từ chối, khẳng định đây là bạn của mình. Tiểu Thanh mang huyết mạch dị cầm phi thường, tiềm năng lớn, được các thế lực thèm muốn.","nguon":["@c0039"]},{"id":"tu-van-di-cam","name":"Tử Vân","category":"khac","categoryLabel":"Dị cầm","phamCap":"Hậu duệ Thái Cổ Ma Cầm","soHuu":["Thạch Hạo"],"trangThai":"Bạn thân của Thạch Hạo, bị các cường giả thèm muốn","blurb":"Một trong ba con chim non hậu duệ Thái Cổ Ma Cầm, được Thạch Hạo coi là bạn thân.","detail":"Tử Vân là một trong ba con chim non được Thạch Hạo nuôi ở Thạch Thôn, được cậu bé xem như bạn thân thiết. Trong chương này, các cường giả La Phù Đại Trạch cùng nhiều thế lực đòi Thạch Thôn giao ba con chim non và bảo cốt Toan Nghê, nhưng Thạch Hạo tuyên bố Đại Bằng, Tiểu Thanh, Tử Vân đều là bạn của mình, không giao cho ai. Tử Vân được cho là mang huyết mạch dị cầm phi thường.","nguon":["@c0039"]},{"id":"xuong-quy-toan-nghe","name":"Xương quý Toan Nghê","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Bảo vật hiếm","soHuu":["Thạch thôn"],"trangThai":"dang-co","blurb":"Xương quý Toan Nghê mà các tộc bàn nhau âm mưu chiếm đoạt của Thạch thôn.","detail":"Thứ bảo vật các tộc (La Phù Đại Trạch, Lôi tộc, Tử Sơn gia, bộ lạc Kim Lang…) bàn nhau tàn sát Thạch thôn để cướp, bị đám nhóc Thạch thôn khơi lại giữa cuộc đối đầu với Liễu Thần.","nguon":["@c0040"]},{"id":"bao-cu-soi-duong","name":"Bảo cụ soi đường","category":"khac","categoryLabel":"Khác","soHuu":["La Phù Đại Trạch"],"trangThai":"dang-co","blurb":"Bảo cụ được các cường giả các tộc móc ra soi đường khi chạy trốn trong đêm.","detail":"Vật phẩm phát sáng dùng để soi đường trong rừng nguyên thủy tối om, được các cường giả các tộc lấy ra khi tháo chạy khỏi Thạch thôn.","nguon":["@c0040"]},{"id":"dinh-thuoc-mau-den-thach-thon","name":"Đỉnh thuốc màu đen (đỉnh tổ tiên Thạch thôn)","category":"phap-bao","categoryLabel":"Bảo vật tổ truyền","phamCap":"Chưa rõ","soHuu":["Thạch thôn"],"trangThai":"dang-co","blurb":"Cái đỉnh màu đen tổ tiên Thạch thôn truyền lại, cảm ứng với sức mạnh tế tự.","detail":"Đỉnh thuốc màu đen do tổ tiên Thạch thôn truyền lại. Khi người trong thôn tế bái sinh ra sức mạnh tế tự, cái đỉnh rung nhẹ, hình điêu khắc tiền dân Thượng cổ cùng nhật nguyệt sơn hà trên thân đỉnh hiện rõ hơn và có ánh sáng yếu ớt vòng quanh, cho thấy nó liên hệ mật thiết với sức mạnh thần bí thời thượng cổ.","nguon":["@c0041"]},{"id":"bao-cot-nguyen-thuy-tran-son","name":"Bảo cốt nguyên thủy","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":[],"trangThai":"mat","blurb":"Hơn mười mấy khối bảo cốt nguyên thủy trấn áp nơi sâu nhất dãy núi Thương Mãng, giữ cho sơn hà không bị đánh tan hoang giữa đại chiến tứ đại sinh linh.","detail":"Hơn mười khối bảo cốt nguyên thủy được bố trí trấn áp vùng núi sâu nhất Thương Mãng, phát ra phù văn sáng khóa chặt sơn hà để đại chiến của tứ đại sinh linh không san bằng núi non. Cuối chương, sức mạnh của Thánh vật trắng rốt cuộc xuyên phá phù văn, bảo cốt không còn khóa được nữa, mở đường cho đại chiến tràn ra ngoài dãy núi.","nguon":["@c0047"]},{"id":"cung-den-day-gan-giao-thap-ngu-gia","name":"Cung đen dây gân Giao","category":"phap-bao","categoryLabel":"Pháp bảo (cung)","phamCap":"Không rõ","soHuu":["Thập Ngũ Gia"],"trangThai":"dang-co","blurb":"Cung thân màu đen, dây cung làm bằng gân Giao — pháp bảo tiễn thuật của Lão Thập Ngũ trong ký ức Thạch Hạo.","detail":"Phát ra sát khí mãnh liệt; khi bắn, mũi tên phóng ra như Giao Long, hào quang ngập trời. Lão Thập Ngũ dùng nó hạ Loan Điểu ở Thánh Hồ.","nguon":["@c0055"]},{"id":"bao-huyet-than-cam-loan-dieu","name":"Bảo huyết Thần Cầm","aliases":["Bảo huyết Loan Điểu"],"category":"dan-duoc","categoryLabel":"Bảo dược (huyết)","phamCap":"Quý hiếm","soHuu":["Thập Ngũ Gia","Thạch Hạo"],"trangThai":"da-dung","blurb":"Hơn nửa bát bảo huyết quý nhất xẻ từ hậu duệ Thái Cổ Thần Cầm (Loan Điểu), ẩn chứa hơn nửa tinh hoa của con chim.","detail":"Được Lão Thập Ngũ dùng đũa ngọc nhỏ vào miệng Hạo Nhi lúc còn quấn tã; đứa bé mút mạnh, mắt sáng, cười. Trưởng bối nói tương lai Hạo Nhi sẽ vượt xa gia gia và cha.","nguon":["@c0055"]},{"id":"dua-ngoc-thap-ngu-gia","name":"Đũa ngọc","category":"khac","categoryLabel":"Vật dụng","soHuu":["Thập Ngũ Gia"],"trangThai":"dang-co","blurb":"Đôi đũa ngọc nhỏ Lão Thập Ngũ dùng chấm bảo huyết Thần Cầm nhỏ vào miệng Hạo Nhi.","detail":"Xuất hiện trong ký ức tế trời của cổ quốc, gắn với nghi thức nhỏ bảo huyết cho hài nhi.","nguon":["@c0055"]},{"id":"chi-ton-cot","name":"Chí Tôn cốt","cn":"至尊骨","aliases":["Thánh cốt trời sinh","Nguyên thủy bảo cốt"],"category":"khac","categoryLabel":"Bảo cốt trời sinh","phamCap":"Nguyên thủy · Chí Tôn (trời sinh)","soHuu":["Thạch Hạo","Thạch Nghị"],"trangThai":"Sinh ra trong lồng ngực Thạch Hạo; bị Lục tẩu lập kế chiết ra và cấy sang Thạch Nghị tại mật thất trang viên.","blurb":"Bảo cốt Nguyên thủy cực hiếm trời sinh trong lồng ngực Thạch Hạo, chứa dày đặc Nguyên thủy phù văn; như Kim Sí Đại Bàng, Chân Hống sinh ra đã có, tương lai sánh vai hung thú Thái cổ.","detail":"Chí Tôn cốt là loại Thánh cốt / Nguyên thủy bảo cốt trời sinh, cực kỳ hiếm gặp — thường chỉ Chí cường giả Nhân tộc mới rèn ra được Thánh cốt cùng Nguyên thủy ấn ký, còn loại trời sinh sẵn thì chỉ những dị chủng bậc nhất như Kim Sí Đại Bàng, Chân Hống mới có. Thạch Hạo bẩm sinh mang Chí Tôn cốt trong lồng ngực; khi cha hắn dùng phù văn tra xét đã kinh sợ đến run tay, khẳng định con mình tương lai có thể sánh vai hung thú Thái cổ, danh chấn Nhân tộc. Bảo cốt có thể tự phát sáng chống lại pháp thuật hôn mê: đầu ngón tay Lục tẩu điểm phù văn định đánh ngất Hạo nhưng bị Bảo cốt phát sáng hóa giải, càng làm Lục tẩu xác nhận đúng là Chí Tôn cốt. Chuyện được liệt hàng tuyệt mật, chỉ bí mật bẩm báo cho hai vị lão gia tử chủ sự trong tộc, khác với Trọng Đồng của Thạch Nghị vừa nhìn là biết. Sau khi bị bóng u linh mổ lồng ngực bằng đao bạc, Chí Tôn cốt hiện ra là một đoàn sáng chói lọi mang ma lực không thể cưỡng lại; vừa sinh trưởng đã khiến linh hồn người ta run rẩy, tỏa thần tính chói cả mật thất. Bóng đen gào lên như dã thú khi tách thành công, rồi ngân đao rạch lồng ngực Nghị nhi trên giường ngọc để cấy Bảo cốt sang — Lục tẩu tuyên bố con ruột mình chính là Chí tôn trời sinh, tương lai sở hữu cả mảnh đại vực này.","nguon":["@c0056","@c0065"]},{"id":"bao-cot-thai-co-di-chung","name":"Bảo cốt Thái cổ di chủng","category":"nguyen-lieu","categoryLabel":"Nguyên liệu trận pháp","phamCap":"Bảo cốt Thái cổ (di chủng)","soHuu":["Thập Ngũ gia"],"trangThai":"Đã dùng xếp Thần trận cứu Thập Ngũ gia thoát khỏi truy sát Tỳ Hưu tại Bách tộc chiến trường; tăm tích sau đó không rõ.","blurb":"Mấy khối bảo cốt lấy từ Thái cổ di chủng, đủ sức xếp thành một tòa Thần trận cứu mạng khi bị hung thú Thái cổ huyết mạch tinh thuần truy sát.","detail":"Là mấy khối bảo cốt vốn lấy được từ Thái cổ di chủng, mang theo tàn dư khí tức Nguyên thủy của các dị chủng thời thượng cổ. Khi Thập Ngũ gia bị con Tỳ Hưu huyết mạch cực kỳ tinh thuần đuổi giết mấy chục vạn dặm ở Bách tộc chiến trường, bị chém đứt một cánh tay, xương cốt toàn thân gần như gãy nát, cuối cùng lão sai tùy tùng lấy mấy khối bảo cốt Thái cổ di chủng này xếp thành một tòa Thần trận, mới miễn cưỡng thoát mạng. Sau trận đó tăm tích Thập Ngũ gia không rõ, sống chết khó nói — mấy khối bảo cốt cũng theo lão biệt tích. Đây là bằng chứng vật chất về đẳng cấp gia sản của Vương hầu phủ và độ khủng khiếp của con Tỳ Hưu vừa mất con.","nguon":["@c0056","@c0060"]},{"id":"cot-thu-chi-ton-cot","name":"Cốt Thư","cn":"","category":"khac","categoryLabel":"Điển tịch","phamCap":"Bí điển","soHuu":[],"trangThai":"Được thiếu phụ và bóng đen dùng làm căn cứ thi thuật","blurb":"Điển tịch ghi chép tường tận về Chí Tôn Cốt cùng cách cấy ghép, có tiền lệ để dựa theo.","detail":"Cốt Thư là sách ghi chép kỹ càng về Chí Tôn Cốt: nguồn gốc, đặc tính và phương pháp cấy ghép mảnh cốt bẩm sinh này từ người này sang người khác. Nhờ có tiền lệ và cách thức ghi trong Cốt Thư, thiếu phụ cùng bóng đen (u linh) mới đủ căn cứ tiến hành thủ thuật moi Chí Tôn Cốt khỏi Thạch Hạo và cấy vào lồng ngực Thạch Nghị. Sách cũng hàm ý những hạn chế của thủ thuật, chẳng hạn cốt sẽ khô nếu cấy ghép nhiều lần.","nguon":["@c0057"]},{"id":"bao-phu-tu-thai-gia","name":"Bảo Phù","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp bảo hộ thân/cứu chữa","soHuu":["Tứ Thái Gia"],"trangThai":"Trong tay Tứ Thái Gia, dùng cứu chữa Thạch Hạo","blurb":"Pháp bảo của Tứ Thái Gia; khi vận chuyển phát ra thụy hà bọc lấy người để cứu chữa.","detail":"Bảo Phù là pháp bảo mang theo mình của Tứ Thái Gia, một trong hai lão chủ sự bối phận cực cao của Thạch Tộc. Khi Tứ Thái Gia phá cửa địa cung xông vào cứu Thạch Hạo đã bị moi Chí Tôn Cốt và rút cạn chân huyết, ông ôm nhóc tỳ vào lòng rồi vận chuyển sức mạnh thần bí của Bảo Phù, khiến nó phát ra thụy hà (ráng lành) bao bọc lấy Thạch Hạo để bảo hộ và cứu chữa sinh mệnh mong manh của đứa bé.","nguon":["@c0057"]},{"id":"hoang-kim-than-mau-thach-tu-lang","name":"Hoàng Kim thần mâu","cn":"","aliases":["Hoàng Kim chiến mâu"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Thạch Tử Lăng"],"trangThai":"Đang sử dụng","blurb":"Chiến mâu vàng của Thạch Tử Lăng, phù văn lượn quanh, một mâu đánh bay cả mảnh cung điện.","detail":"Binh khí trấn thân của Thạch Tử Lăng (lão thập nhất Thạch Tộc). Khi vung ra, thần quang vạn trượng, vô số phù văn kết thành cây chiến mâu bằng ánh sáng, khiến chủ nhân như Hoàng Kim Chiến Thần tắm trong thần diễm. Trong cơn thịnh nộ vì con trai bị đoạt Chí Tôn cốt, Thạch Tử Lăng dùng nó phá tan một mảnh cung điện phủ đệ Thạch Tộc, bẻ gãy binh khí và nghiền nát bảo cụ của chú ruột Thạch Nghị, xuyên thủng lồng ngực đối phương khiến hắn bay xa cắm vào cửa cung điện. Vạch một vòng trong không trung, chiến mâu còn phát bảo thuật kinh thiên như Chư Thiên thần linh cùng ngâm xướng chú ngôn, đinh tai nhức óc, đánh bay chư lão can ngăn phun máu tươi.","nguon":["@c0058"]},{"id":"chuoi-cot-chau-bao-cu","name":"Chuỗi cốt châu","category":"phap-bao","categoryLabel":"Bảo Cụ","phamCap":"Bảo Cụ","soHuu":["Lão già chuỗi cốt châu"],"trangThai":"hong","blurb":"Chuỗi hạt ngọc bằng xương, mỗi viên to như trứng ngỗng phát ánh sáng như sao Ngoại Vực; xếp thành bức vẽ chư tinh dải ngân hà.","detail":"Bảo Cụ quý của một lão bề trên Thạch tộc. Khi kích hoạt, mỗi viên châu phát ánh sáng lấp lánh như sao từ Ngoại Vực bay tới, tạo hình dải ngân hà chư tinh giáng xuống phủ đối thủ. Bị Thạch Tử Lăng đánh nát, sức mạnh phù văn trong hạt châu tiêu tán hóa biển ánh sáng thần thánh — nhiều trưởng lão đau lòng vì Bảo Cụ quý bị lãng phí.","nguon":["@c0059"]},{"id":"quat-long-phong-loi","name":"Quạt lông Phong Lôi","category":"phap-bao","categoryLabel":"Bảo cụ","phamCap":"Bảo cụ","soHuu":["Lão già quạt lông Phong Lôi"],"trangThai":"hong","blurb":"Quạt lông lượn lờ Phong Lôi, phẩy nhẹ như Lôi Thần hiện thế tạo vô tận quầng sáng tím.","detail":"Bảo cụ trong tay lão bề trên Thạch tộc. Khi phẩy tạo vô tận quầng sáng tím như Lôi Thần hiện thế. Bị sấm sét vàng của Thạch Tử Lăng đánh nứt vỡ.","nguon":["@c0059"]},{"id":"nhanh-day-bao-cu","name":"Nhánh dây bảo cụ","category":"phap-bao","categoryLabel":"Bảo cụ","phamCap":"Bảo cụ","soHuu":["Lão già dây leo"],"trangThai":"hong","blurb":"Loài thực vật mạnh mẽ hóa bảo cụ, thân nâu đen, khi kích hoạt sáng óng ánh, phóng nhánh trói như Giao Long.","detail":"Bảo cụ do lão bề trên Thạch tộc dùng để trói buộc đối thủ. Khi hét Trói buộc, các nhánh dây vọt lên như Giao Long lao trói mục tiêu, có thể xuyên thấu một tòa cung điện. Bị Thạch Tử Lăng đánh nổ tung hóa tro tàn.","nguon":["@c0059"]},{"id":"mau-ty-huu-thu-con","name":"Máu Tỳ Hưu (thú con huyết mạch tinh khiết)","category":"dan-duoc","categoryLabel":"Vật phẩm quý","phamCap":"Thái cổ huyết mạch","soHuu":["Thập Ngũ Gia","Thạch Hạo"],"trangThai":"da-dung","blurb":"Máu chân chính của thú con Tỳ Hưu huyết mạch tinh khiết, do Thập Ngũ Gia bắn chết lấy về gột rửa thân thể cho cháu trai Thạch Hạo.","detail":"Thập Ngũ Gia từng bắn chết một thú con Tỳ Hưu huyết mạch tinh khiết để lấy máu chân chính, dùng gột rửa thân thể cho cháu trai (nhóc tỳ Thạch Hạo), hé lộ nền tảng thân thể đặc biệt của Thạch Hạo đã được gia công từ trước.","nguon":["@c0059"]},{"id":"giao-long-dao","name":"Giao Long Đao","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo Thuật hóa thành","soHuu":["Thạch Lạp"],"trangThai":"dang-co","blurb":"Pháp bảo hình đao do Bảo Thuật ngưng ký hiệu tụ thành, phủ vảy giao, xuất hiện khi Thạch Lạp cõng Thạch Nghị xông vào chiến trường.","detail":"Ký hiệu Bảo Thuật tụ thành một thanh đao phủ vảy giao, được Thạch Lạp vung ra sượt qua đầu Thạch Tử Lăng, chém rơi một sợi tóc của hắn nhờ trùng đồng gia trì nhìn thấu khe hở.","nguon":["@c0061"]},{"id":"tan-do-to-dia-thach-toc","name":"Tàn đồ (tổ địa Thạch tộc)","cn":"","category":"khac","categoryLabel":"Vật phẩm dẫn đường","phamCap":"","soHuu":["Thạch Tử Lăng"],"trangThai":"Do Tứ tổ lén trao cho Thạch Tử Lăng","blurb":"Tấm bản đồ tàn dẫn đường tới tổ địa chính thức của Thạch tộc, được Tứ tổ lén trao cho Thạch Tử Lăng.","detail":"Một tấm tàn đồ (bản đồ mảnh) chỉ đường tới tổ địa chính thức của Thạch tộc — nơi thần bí đầy truyền thuyết, tương truyền có thể sinh ra Thần, là chốn tổ tiên Thạch tộc từ đó đi ra khai sáng Cổ quốc, về sau đã bị cắt liên hệ theo Tổ huấn. Tứ tổ giấu tất cả mọi người, lén trao tấm tàn đồ này cho Thạch Tử Lăng như một lối thoát để khôi phục sức sống cho Hạo nhi. Thạch Tử Lăng dồn hi vọng nghiên cứu tàn đồ để tìm tổ địa; tàn đồ cũng liên quan tới đường vào Thái Cổ Thần Sơn — nơi cực kỳ nguy hiểm mà nếu vạn bất đắc dĩ y mới xông vào.","nguon":["@c0062"]},{"id":"nguyen-thuy-chan-giai","name":"Nguyên Thủy Chân Giải","cn":"","aliases":["Cục xương trắng","Bảo cốt Nguyên Thủy Chân Giải"],"category":"phap-bao","categoryLabel":"Bảo cốt","phamCap":"Không rõ","soHuu":["Thạch Hạo","Thạch Vân Phong"],"trangThai":"dang-co","blurb":"Cục xương trắng óng khắc chi chít ký hiệu, ghi chép chân nghĩa vô thượng của Cốt Văn, do Liễu Thần đặt tên bốn chữ.","detail":"Cục xương trắng tinh óng như dương chi mỹ ngọc, to bằng bàn tay, khắc vô số ký hiệu ẩn hiện, ẩn hiện tiếng ca ngâm chư thiên thần ma; nhìn lâu sẽ phun máu bị trọng thương. Mấy chục năm trước, trong một đêm sấm sét, một luồng sáng bao bọc cục xương cùng rơi xuống Thạch Thôn với Liễu Thần khi cây liễu bị gãy cháy đen. Tộc trưởng Thạch Vân Phong cất giữ, nhiều lần cầm cúng bái cây liễu mà không được đáp; cuối cùng trao lại cho nhóc tỳ. Con Chu Yếm thấy cục xương thì cực bất an, gào thét muốn đoạt lấy. Sau im lặng hồi lâu, Liễu Thần lên tiếng đặt cho nó bốn chữ: Nguyên Thủy Chân Giải.","nguon":["@c0063"]},{"id":"phuong-thuoc-truc-co-thai-co-hung-thu","name":"Phương thuốc trúc cơ Thái Cổ Hung Thú non","category":"khac","categoryLabel":"Đan phương","soHuu":["Liễu Thần","Thạch Hạo"],"trangThai":"dang-co","blurb":"Đan phương chuyên trúc cơ cho Thái Cổ Hung Thú non do Liễu Thần trao cho Thạch Hạo.","detail":"Phương thuốc do Liễu Thần cấp, cần thuốc cổ, tinh huyết Di Chủng và bảo cốt cực hiếm mà bộ tộc siêu cấp cũng khó có; Liễu Thần cho phép dùng đồ bình thường thay thế trừ chủ dược, chủ dược lấy một giọt máu vàng Chu Yếm mỗi ngày cách. Khi đủ nguyên liệu, đỉnh đen tỏa sáng, nước sục sôi phát tiếng như chư thần ngâm xướng và lễ bái.","nguon":["@c0064"]},{"id":"long-giac-tuong","name":"Long Giác Tượng","category":"nguyen-lieu","categoryLabel":"Mãnh thú/nguyên liệu","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Mãnh thú thân chi chít vảy, đầu có đôi sừng rồng, nặng mấy vạn cân, bị Thạch Hạo bắt sống vác về Thạch Thôn.","detail":"Con vật lớn được Thạch Hạo bắt sống vác chổng bốn vó chạy về thôn suốt nửa tháng liên tiếp; thịt dùng làm thức ăn cho tộc và bồi bổ Chu Yếm — mỗi ngày Chu Yếm ăn hơn nửa con. Sau nửa tháng tộc nhân chán ăn nên Thạch Hạo chủ động đổi loại thú.","nguon":["@c0064"]},{"id":"ret-vang-dan-lieu","name":"Rết vàng","category":"nguyen-lieu","categoryLabel":"Đan liệu","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Đan liệu cùng thuốc cổ, Long Cân Xà, Long Tu Ngư tan trong đỉnh đen khi tộc trưởng luyện phương thuốc trúc cơ.","detail":"Rết vàng được dùng làm một trong các phụ liệu trong đỉnh đen tổ truyền, cùng thuốc cổ, Long Cân Xà và Long Tu Ngư tỏa hương chờ chủ dược máu Chu Yếm.","nguon":["@c0064"]},{"id":"phuong-thuoc-co-truyen-thach-thon","name":"Phương thuốc cổ truyền Thạch Thôn","category":"khac","categoryLabel":"Đan phương","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Các phương thuốc cổ truyền tích lũy từ thời Thượng Cổ huy hoàng của Thạch tộc.","detail":"Kho phương thuốc cổ được tộc lưu lại từ thời Thượng Cổ khi từng có thần linh xuất hiện; đã bị Thạch Hạo dùng hết trong quá trình bồi bổ ba tháng để nâng cơ thể lên mức năm vạn cân.","nguon":["@c0064"]},{"id":"di-the-toan-nghe","name":"Di thể Toan Nghê","aliases":["Thánh vật bảo cốt Toan Nghê","Bảo cốt Toan Nghê"],"category":"nguyen-lieu","categoryLabel":"Di thể Thái cổ","phamCap":"Chí bảo","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Di thể/bảo cốt Toan Nghê mà cường giả suy đoán Thạch thôn chiếm giữ, ngang tầm chí bảo.","detail":"Sau hai canh giờ tra xét, các cường giả suy ra Thạch thôn có thể chiếm được di thể một con Toan Nghê, tức có Bảo thuật/Phù văn nguyên thủy Toan Nghê chí cường ngang thần thông trấn tộc. Suy đoán này khiến La Phù Đại Trạch và bộ lạc Kim Lang run sợ nhưng cũng đỏ mắt tham lam.","nguon":["@c0036"]},{"id":"bao-cot-ky-di-nguyen-thuy","name":"Bảo cốt kỳ dị","cn":"","category":"khac","categoryLabel":"Bảo vật","phamCap":"","soHuu":[],"trangThai":"dang-co","blurb":"Hơn mười khúc xương thú ngưng ký hiệu nguyên thủy, rơi ra khi bốn sinh vật đại chiến, trấn áp Thương Mãng Sơn Mạch.","detail":"Trong trận đại chiến giữa các sinh vật cực mạnh, hơn mười khúc bảo cốt kỳ dị rơi ra, có khúc đỏ như Huyết Toản, đen như mực, trắng óng ánh; bảo cốt ngưng ký hiệu nguyên thủy phân tán khắp Thương Mãng Sơn Mạch để ổn định núi sông, rơi từ Thái Cổ Di Chủng.","nguon":["@c0046"]},{"id":"dinh-co-to-truyen-thach-thon","name":"Đỉnh cổ tổ truyền Thạch Thôn","cn":"","category":"khac","categoryLabel":"Bảo vật","phamCap":"","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Đỉnh cổ tổ truyền trong Thạch Thôn khắc nhật nguyệt sơn hà và tiên dân Thượng Cổ, cộng minh khi Liễu Thần lên tiếng.","detail":"Đỉnh trong thôn khắc nhật nguyệt sơn hà cùng hình tiên dân Thượng Cổ trên vách. Khi Liễu Thần lên tiếng và sức mạnh thần bí lan ra, đỉnh cộng minh và hình tiên dân Thượng Cổ trên vách hiện rõ hơn, gợi liên hệ nguồn gốc cổ xưa với Cốt Thư.","nguon":["@c0046"]},{"id":"duoc-dinh-to-tien-thach-thon","name":"Dược đỉnh tổ tiên Thạch thôn","cn":"","category":"phap-bao","categoryLabel":"Bảo vật tộc","phamCap":"","soHuu":["Thạch thôn"],"trangThai":"dang-co","blurb":"Dược đỉnh do tổ tiên truyền xuống trong tộc Thạch thôn, phát sáng cộng minh khi cây liễu phát uy.","detail":"Khi cây liễu cổ Thạch thôn phát ánh sáng xanh dệt Xích thần trật tự, dược đỉnh tổ tiên trong tộc cộng minh phát sáng, khiến đồ án tiên dân Thượng cổ trên vách đỉnh hiện lên rõ ràng hơn — gợi liên hệ giữa Thạch thôn và tiên dân Thượng cổ.","nguon":["@c0048"]},{"id":"thanh-duoc","name":"Thánh dược","cn":"","category":"dan-duoc","categoryLabel":"Dược liệu","phamCap":"","soHuu":[],"trangThai":"dang-co","blurb":"Dược liệu cha mẹ Thạch Hạo đi tìm để trị tận gốc bệnh cho nó, mọc ở cổ địa nguyên thủy nguy hiểm.","detail":"Thánh dược là dược liệu quý mọc ở cổ địa nguyên thủy nguy hiểm; cha mẹ Thạch Hạo rời thôn đi tìm để trị tận gốc bệnh cho con, có thể phải tranh chấp với Di Chủng Thái Cổ.","nguon":["@c0052","@c0062"]},{"id":"cung-den-thap-ngu-gia","name":"Cung đen dây gân Giao","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Thập Ngũ Gia"],"trangThai":"dang-co","blurb":"Cây cung thân đen của Lão Thập Ngũ, dây cung làm bằng gân Giao, sát khí mãnh liệt.","detail":"Thân cung màu đen, dây cung bện bằng gân Giao, phát ra sát khí mãnh liệt; khi buông tên bắn ra mũi tên như Giao Long, hào quang ngập trời. Trong ký ức, Lão Thập Ngũ dùng nó bắn hai tên hạ một con Loan Điểu ở Thánh Hồ.","nguon":["@c0055"]},{"id":"nguyen-thuy-bao-cot","name":"Nguyên thủy bảo cốt","cn":"","aliases":["Thánh cốt trời sinh"],"category":"than-khi","categoryLabel":"Thần khí","phamCap":"Bảo cốt trời sinh cực hiếm","soHuu":["Thạch Hạo"],"trangThai":"Bị Lục tẩu chiết khỏi lồng ngực Thạch Hạo, cấy sang Thạch Nghị","blurb":"Loại xương trời sinh cực hiếm chứa dày đặc Nguyên thủy phù văn, còn gọi là Chí Tôn cốt; sinh ra đã có như Kim Sí Đại Bàng, Chân Hống.","detail":"Nguyên thủy bảo cốt là loại xương trời sinh cực hiếm, bên trong chứa dày đặc Nguyên thủy phù văn — đây chính là Chí Tôn cốt trời sinh. Chỉ số cực hiếm Nhân tộc mới sinh ra đã có, như Kim Sí Đại Bàng, Chân Hống; người mang nó tương lai có thể sánh vai với hung thú Thái cổ, danh chấn Nhân tộc. Thạch Hạo trời sinh sở hữu Bảo cốt này: khi bị Lục tẩu điểm phù văn định làm ngất, Bảo cốt tự phát sáng hóa giải pháp thuật khiến Thạch Hạo không ngất được. Khi bị bóng u linh phẫu thuật tách khỏi lồng ngực, nó hiện ra là một đoàn sáng chói lọi mang ma lực không thể cưỡng lại, vừa sinh trưởng đã khiến linh hồn người ta run rẩy, tỏa thần tính chói khắp mật thất, rồi bị cưỡng ép cấy sang Thạch Nghị.","nguon":["@c0056","@c0078","@c0098"]},{"id":"bao-cot-thai-co-di-chung-c56","name":"Bảo cốt Thái cổ di chủng","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Nguyên liệu trận pháp","soHuu":["Thập Ngũ gia"],"trangThai":"Được Thập Ngũ gia dùng xếp Thần trận thoát mạng","blurb":"Mấy khối bảo cốt của Thái cổ di chủng dùng để xếp thành Thần trận cứu mạng.","detail":"Bảo cốt của Thái cổ di chủng — mấy khối xương quý. Khi bị con Tỳ Hưu đuổi giết mấy chục vạn dặm, chém đứt một cánh tay, xương cốt toàn thân gần như gãy nát, Thập Ngũ gia sai người dùng mấy khối bảo cốt này xếp thành một tòa Thần trận mới thoát được mạng, nhưng sau đó tăm tích không rõ.","nguon":["@c0056"]},{"id":"ngan-dao-chiet-xuong","name":"Ngân đao chiết xương","cn":"","aliases":["Đao bạc"],"category":"than-khi","categoryLabel":"Thần khí","phamCap":"Khí giới ám sát","soHuu":["Bóng u linh"],"trangThai":"Dùng để chiết Chí Tôn cốt","blurb":"Thanh đao bạc lóe ánh sáng lạnh lẽo trong tay bóng u linh, dùng cứa lồng ngực để chiết và cấy Chí Tôn cốt.","detail":"Thanh đao bạc trong tay bóng u linh, lóe lên một tia ánh sáng lạnh lẽo. Bóng u linh dùng nó cứa nhẹ vào lồng ngực nhóc tỳ (Thạch Hạo) khiến máu tươi phún ra kèm luồng ánh sáng thần thánh mông lung, để tách Chí Tôn cốt. Sau đó ngân đao lại lướt qua lồng ngực Nghị nhi rạch mở để cấy Chí Tôn cốt vào, huyết dịch chảy ra.","nguon":["@c0056"]},{"id":"giuong-ngoc-nghi-nhi","name":"Giường ngọc","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm","phamCap":"Bệ ngọc cấy ghép","soHuu":["Thạch Nghị"],"trangThai":"Dùng trong ca cấy ghép Chí Tôn cốt","blurb":"Bệ ngọc dành cho Nghị nhi nằm trong quá trình cấy Chí Tôn cốt, đặt cạnh giường lạnh của nhóc tỳ.","detail":"Chiếc giường ngọc là bệ dành riêng cho Nghị nhi — con ruột thiếu phụ — nằm trong quá trình cấy ghép Chí Tôn cốt. Nó được đặt cạnh chiếc giường lạnh lẽo dành cho nhóc tỳ (kẻ bị lấy Chí Tôn cốt), thể hiện rõ sự đối xử hai bậc: giường ngọc cho con ruột được hiền từ chăm sóc, giường lạnh cho bé gái bị lạnh nhạt bỏ mặc.","nguon":["@c0056"]},{"id":"binh-ngoc-chua-bao-huyet","name":"Bình ngọc chứa bảo huyết","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Bóng đen (u linh)"],"trangThai":"dang-co","blurb":"Bình ngọc bóng đen dùng bí pháp rút và chứa chân huyết Thạch Hạo để tẩm bổ Chí Tôn Cốt.","detail":"Do bóng đen lấy ra, dùng bí pháp rút chân huyết còn sót trong cơ thể Thạch Hạo, chứa vào bình ngọc rồi tẩm bổ Chí Tôn Cốt trong người Thạch Nghị.","nguon":["@c0057"]},{"id":"dao-bac-dau-giuong","name":"Dao bạc đầu giường","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Thạch Nghị"],"trangThai":"dang-co","blurb":"Con dao bạc ở đầu giường Thạch Nghị chộp lấy kề vào cổ mình để ép Tứ Thái Gia tha mẹ.","detail":"Vật phẩm ở đầu giường; Thạch Nghị cầm nó kề lên cổ tự cứa chảy máu để uy hiếp Tứ Thái Gia, sau đó ném đi khi khai nhận Chí Tôn Cốt.","nguon":["@c0057"]},{"id":"hoang-kim-than-mau","name":"Hoàng Kim thần mâu","cn":"","aliases":["Hoàng Kim chiến mâu","chiến mâu Hoàng Kim"],"category":"than-khi","categoryLabel":"Thần khí","phamCap":"","soHuu":["Thạch Tử Lăng"],"trangThai":"Trong tay Thạch Tử Lăng","blurb":"Chiến mâu vàng của Thạch Tử Lăng, phù văn lượn quanh, một mâu đánh bay cả mảnh cung điện.","detail":"Binh khí chủ lực của Thạch Tử Lăng — chiến mâu bằng hoàng kim, xung quanh có vô số phù văn lượn quanh. Khi Thạch Tử Lăng trở về thấy con nguy kịch, hắn cầm mâu này phá tan một mảnh cung điện, khiến bản thân trông như Hoàng Kim Chiến Thần tắm trong thần diễm. Khi đâm ra, thần quang tỏa vạn trượng, vô tận phù văn kết thành một cây chiến mâu bằng ánh sáng; đâm xuyên thủng lồng ngực chú ruột của Thạch Nghị khiến người này bay xa cắm vào cửa một tòa cung điện, ho ra máu. Vũ khí này còn dùng để thi triển bảo thuật kinh thiên: vạch một vòng, phát ra âm thanh như Chư Thiên thần linh cùng ngâm xướng chú ngôn, đánh bay đám chư lão can ngăn.","nguon":["@c0058"]},{"id":"bao-thuat-hoang-kim-chien-mau","name":"Bảo thuật Hoàng Kim chiến mâu","cn":"","aliases":[],"category":"khac","categoryLabel":"Bảo thuật","phamCap":"","soHuu":["Thạch Tử Lăng"],"trangThai":"Thạch Tử Lăng thi triển","blurb":"Bảo thuật kinh thiên phát ra từ Hoàng Kim chiến mâu, âm thanh như Chư Thiên thần linh cùng ngâm xướng chú ngôn.","detail":"Bảo thuật do Thạch Tử Lăng vận dụng qua Hoàng Kim chiến mâu: hắn vung mâu vạch một vòng, phát bảo thuật kinh thiên, âm thanh vang lên như vô số Chư Thiên thần linh cùng ngâm xướng chú ngôn, đinh tai nhức óc. Uy lực khủng bố khiến mấy lão già ngăn cản đều bị đánh bay, phun máu tươi, hoảng sợ. Được thi triển trong cảnh Thạch Tử Lăng quyết đại khai sát giới để báo thù cho con.","nguon":["@c0058"]},{"id":"chien-mau-vang-thach-tu-lang","name":"Chiến mâu màu vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thạch Tử Lăng"],"trangThai":"dang-co","blurb":"Binh khí của Thạch Tử Lăng tỏa ánh hoàng kim.","detail":"Thanh mâu màu vàng tỏa ánh hoàng kim, ghim rồi giết thiếu phụ mẹ Thạch Nghị, đâm nổ tung một tộc lão chi thứ.","nguon":["@c0061"]},{"id":"tan-do-to-dia-chinh-thuc","name":"Tàn đồ","cn":"","category":"khac","categoryLabel":"Vật phẩm dẫn đường","phamCap":"","soHuu":["Thạch Tử Lăng"],"trangThai":"dang-co","blurb":"Tấm bản đồ tàn Tứ tổ lén trao, dẫn tới tổ địa chính thức Thạch tộc.","detail":"Tấm tàn đồ Thạch Tử Lăng nghiên cứu, được Tứ tổ giấu tất cả mọi người lén trao, chỉ đường tới tổ địa chính thức Thạch tộc — nơi thần bí tương truyền có thể sinh ra Thần, đã bị cắt liên hệ theo Tổ huấn; liên quan cả đường vào Thái Cổ Thần Sơn, gửi hi vọng tìm được tổ địa.","nguon":["@c0062"]},{"id":"mau-chu-yem-chu-duoc","name":"Máu Chu Yếm","cn":null,"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Cực hiếm","soHuu":["Thạch Hạo"],"trangThai":"đang dùng","blurb":"Giọt máu vàng của Chu Yếm dùng làm chủ dược cho phương thuốc trúc cơ Thái Cổ Hung Thú non.","detail":"Mỗi ngày cách Chu Yếm hiến một giọt máu vàng. Khi nhỏ vào đỉnh đen tổ truyền, vách đỉnh tỏa sáng, nước sục sôi phát tiếng ầm vang, có tiếng như chư thần ngâm xướng và lễ bái to lớn, khiến cả thôn chấn động — cho thấy huyết mạch Chu Yếm cực kỳ tôn quý phi thường.","nguon":["@c0064"]},{"id":"bao-huyet-toan-nghe","name":"Bảo huyết Toan Nghê","aliases":["chân huyết Toan Nghê"],"category":"nguyen-lieu","categoryLabel":"Bảo vật huyết dịch","phamCap":"Thái Cổ Di Chủng","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Bảo huyết chân huyết của Toan Nghê Thái Cổ Di Chủng mà Thạch Thôn thu được, dùng tẩy lễ luyện thể và chữa ám tật.","detail":"Chân huyết của con Toan Nghê mà Thạch Thôn đã ăn. Trẻ trong thôn như Nhị Mãnh trải qua tẩy lễ bằng chân huyết Toan Nghê thì sức mạnh tăng vọt, gần như nâng nổi đỉnh đồng ngàn cân. Tộc trưởng Thạch Thôn uống bảo huyết Toan Nghê để chữa ám tật rồi chuyên tâm bế quan tu hành.","nguon":["@c0035"]},{"id":"tang-da-phu-van-te-linh-tieu-co-son","name":"Tảng đá phù văn (Tế linh Tiểu Cô Sơn)","cn":"","category":"khac","categoryLabel":"Vật/hóa thân tế linh","phamCap":"Không rõ","soHuu":[],"trangThai":"hong","blurb":"Tảng đá lớn khắc dày đặc phù văn, hóa thân tế linh Tiểu Cô Sơn tự xưng hậu duệ Thần núi.","detail":"Tảng đá phù văn phát sáng rực, chấn ra đại lực đập nát tốp hung thú để bảo vệ Tiểu Cô Sơn trấn, tự xưng là hậu duệ của Thần núi. Cuối cùng bị Sư Tử Kim Mao đập nứt rồi nát vụn, tia máu đầy ánh sáng bị nuốt ực.","nguon":["@c0048"]},{"id":"bao-huyet-than-cam-thai-co","name":"Bảo huyết Thái Cổ Thần Cầm","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Bảo dược","soHuu":["Thạch Hạo","Thập Ngũ Gia"],"trangThai":"da-dung","blurb":"Máu quý nhất của Loan Điểu, chứa hơn nửa tinh hoa con chim, được nhỏ cho Hạo Nhi uống bồi bổ.","detail":"Máu quý nhất của con Loan Điểu bị Lão Thập Ngũ bắn hạ tại Thánh Hồ, hơn nửa bát chứa hơn nửa tinh hoa con chim, trong máu có dòng máu Thái Cổ Thần Cầm. Lão Thập Ngũ nhỏ mấy giọt vào miệng Hạo Nhi (Thạch Hạo sơ sinh) để bồi bổ, đặt nền tảng thể chất phi phàm từ nhỏ.","nguon":["@c0055"]},{"id":"cung-lao-thap-ngu","name":"Cung của Lão Thập Ngũ","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thập Ngũ Gia"],"trangThai":"dang-co","blurb":"Cung thân màu đen, dây làm bằng gân Giao, phát sát khí mãnh liệt.","detail":"Cung thân đen, dây làm bằng gân Giao, phát sát khí mãnh liệt. Lão Thập Ngũ dùng nó hai tên bắn hạ một con Loan Điểu mạnh mẽ tại Thánh Hồ.","nguon":["@c0055"]},{"id":"co-thu-chiet-xuong","name":"Cố thư chiết xương","cn":"","category":"khac","categoryLabel":"Cổ thư bí tịch","phamCap":"","soHuu":["Lục tẩu"],"trangThai":"Đang được Lục tẩu tra cứu","blurb":"Bộ Cố thư ghi chép phương pháp chiết Chí Tôn cốt cấy sang người khác.","detail":"Một bộ Cố thư mà Lục tẩu đã tra cứu kỹ, trong đó khẳng định việc chiết xương Chí Tôn cốt có thể thành công. Nhờ tài liệu này, Lục tẩu mới dám lập kế lừa Thạch Hạo xuống mật thất dưới trang viên, dùng bóng u linh cầm đao bạc cứa lồng ngực để tách Chí Tôn cốt ra và cấy sang con ruột mình là Thạch Nghị. Sự tồn tại của Cố thư hàm ý còn có thế lực khác cũng biết cách đoạt Chí Tôn cốt.","nguon":["@c0056"]},{"id":"dao-bac-bong-u-linh","name":"Đao bạc (bóng u linh)","cn":"","category":"phap-bao","categoryLabel":"Khí giới ám sát","phamCap":"","soHuu":["Bóng u linh"],"trangThai":"Đang được dùng để chiết Chí Tôn cốt","blurb":"Thanh đao bạc trong tay bóng u linh, cứa lồng ngực Thạch Hạo để chiết Chí Tôn cốt.","detail":"Một thanh đao bạc lóe ánh sáng lạnh lẽo, được bóng u linh (sát thủ do Lục tẩu triệu tới) sử dụng trong mật thất dưới trang viên. Đao bạc cứa nhẹ vào lồng ngực Thạch Hạo, khiến máu tươi phún ra kèm luồng ánh sáng thần thánh mông lung tỏa ra từ Chí Tôn cốt. Là khí giới then chốt trong ca chiết xương tàn nhẫn của Lục tẩu.","nguon":["@c0056"]},{"id":"dao-bac-dau-giuong-thach-nghi","name":"Dao bạc đầu giường","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Vật phẩm phàm","soHuu":["Thạch Nghị"],"trangThai":"da-dung","blurb":"Con dao bạc đặt ở đầu giường Thạch Nghị, được cậu chộp lấy kề vào cổ mình để ép Tứ Thái Gia tha mẹ.","detail":"Khi bị tiếng rống của Tứ Thái Gia đánh thức, Thạch Nghị chộp con dao bạc ở đầu giường kề lên cổ mình, cứa ra một vết máu để đe dọa tự sát, ép trưởng bối tha thiếu phụ.","nguon":["@c0057"]},{"id":"truong-mau-thach-tu-lang","name":"Trường mâu Hoàng Kim (Thạch Tử Lăng)","category":"phap-bao","categoryLabel":"Bảo cụ vũ khí","soHuu":["Thạch Tử Lăng"],"trangThai":"dang-co","blurb":"Chiến mâu hoàng kim của Thạch Tử Lăng, khi vung xuất hiện nguyên thủy phù văn liên miên, mỗi bước đạp xuống làm mặt đất nứt khe lớn.","detail":"Vũ khí chính của Thạch Tử Lăng trong chương này: trường mâu hoàng kim, vung lên hiện nguyên thủy phù văn, tỏa ánh sáng hoàng kim rực rỡ đánh nát chuỗi cốt châu, quất bay lão bảo cụ dây leo, cắm xuống đất làm điểm tựa vận Bảo Thuật triệu hung thú Thái cổ.","nguon":["@c0059"]},{"id":"mau-ty-huu","name":"Máu Tỳ Hưu","aliases":["Máu thú con Tỳ Hưu huyết mạch tinh khiết"],"category":"dan-duoc","categoryLabel":"Vật phẩm quý","soHuu":["Thập Ngũ Gia","Thạch Hạo"],"trangThai":"da-dung","blurb":"Máu chân chính từ thú con Tỳ Hưu huyết mạch tinh khiết, được Thập Ngũ Gia lấy để gột rửa thân thể cho cháu trai Thạch Hạo.","detail":"Thập Ngũ Gia bắn chết thú con Tỳ Hưu huyết mạch tinh khiết để lấy máu chân chính gột rửa thân thể cho nhóc tỳ (Thạch Hạo) từ trước; ẩn ý nền tảng thân thể đặc biệt đã được gia công.","nguon":["@c0059"]},{"id":"chien-mau-hoang-kim-thach-tu-lang","name":"Chiến mâu Hoàng Kim (Thạch Tử Lăng)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thạch Tử Lăng"],"trangThai":"dang-co","blurb":"Thanh mâu màu vàng tỏa ánh hoàng kim, binh khí giết người của Thạch Tử Lăng.","detail":"Chiến mâu tỏa ánh hoàng kim của Thạch Tử Lăng: hắn vẫy tay rút mâu khiến thân thiếu phụ (mẹ Thạch Nghị) nổ tung gần nửa, sau đó đâm nổ tung một tộc lão chi thứ để lại một màn mưa máu.","nguon":["@c0061"]},{"id":"hoang-kim-chien-mau-thach-tu-lang","name":"Hoàng kim chiến mâu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Thạch Tử Lăng"],"trangThai":"Đang sử dụng","blurb":"Binh khí chủ lực của Thạch Tử Lăng, kim sắc, phù văn ẩn hiện, có uy lực đâm xuyên thiên địa.","detail":"Cây chiến mâu màu hoàng kim là binh khí chủ lực của Thạch Tử Lăng. Trên thân mâu phù văn ẩn hiện, khi thi triển có thể đâm xuyên thiên địa. Trong đại chiến tại Thạch phủ ở Hoàng Đô, Thạch Tử Lăng cầm mâu này, thân hiện huyễn ảnh Thái cổ hung thú, một mình áp đảo bốn tông lão/lão tổ Thạch tộc, khiến họ liên tục thổ huyết. Bấy giờ hắn tựa một vị thiên thần màu vàng tung hoành giữa vòng vây bốn đại cao thủ mà vẫn chiếm cứ thượng phong.","nguon":["@c0062"]},{"id":"nguyen-thuy-chan-giai-cot","name":"Nguyên Thủy Chân Giải (cục xương trắng)","cn":"原始真解","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Vô thượng","soHuu":["Thạch Hạo"],"trangThai":"đang sở hữu","blurb":"Cục xương trắng khắc vô số ký hiệu ẩn hiện tiếng ca chư thiên thần ma, nhìn lâu phun máu trọng thương; do Liễu Thần đặt tên.","detail":"Xương trắng óng như dương chi mỹ ngọc to bằng bàn tay, khắc chi chít ký hiệu, ẩn hiện tiếng ca ngâm chư thiên thần ma. Rơi cùng Liễu Thần xuống Thạch Thôn trong một đêm sấm sét mấy chục năm trước — Liễu Thần tắm trong biển sét, cành liễu hóa thần liên đâm xuyên trời rồi bị gãy cháy đen rơi xuống, kèm một luồng sáng bao bọc cục xương. Tộc trưởng Thạch Vân Phong cất giữ mấy chục năm, nhiều lần cúng bái cây liễu nhưng không được đáp lại, cuối cùng trao cho Thạch Hạo. Liễu Thần lên tiếng đặt tên bốn chữ: Nguyên Thủy Chân Giải.","nguon":["@c0063"]},{"id":"dinh-thuoc-co-to-truyen","name":"Đỉnh thuốc cổ tổ truyền","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Chí bảo Thạch Thôn — đỉnh luyện dược cổ, vách khắc tiên dân Thượng Cổ tế thiên và Thái Cổ Hung Thú, đã thông linh biết tự rút thần tinh thiên địa.","detail":"Đỉnh thuốc cổ tổ truyền của Thạch Thôn. Khi máu vàng Chu Yếm được dùng làm chủ dược, đỉnh cộng minh, vách phát sáng, hiện hình núi non, nhật nguyệt, tiên dân Thượng Cổ tế thiên và Thái Cổ Hung Thú (Ly Long, Tỳ Hưu) sống động. Do nhiều lần đun bảo dược nên hấp thu dược tính, nay thông linh — tự rút thần tinh thiên địa và sinh ra dịch thể óng ánh gọi là dược căn, tăng phẩm chất thuốc nấu bên trong.","nguon":["@c0065"]},{"id":"duoc-can","name":"Dược căn","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Vô giá","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Tinh thể lỏng óng ánh như cam lộ trên vách đỉnh cổ, kết tinh dược tính tích lũy với thần tinh thiên địa, tăng phẩm chất thuốc đang nấu.","detail":"Dịch thể óng ánh như cam lộ xuất hiện trên vách đỉnh cổ tổ truyền khi đỉnh sống lại. Được lão tộc trưởng giải thích là tinh thể lỏng do dược tính tích lũy qua năm tháng kết hợp với thần tinh thiên địa, có thể tăng phẩm chất lô thuốc đang nấu. Đỉnh xuất được dược căn là bảo vật vô giá, không đổi được, chứng tỏ đỉnh đã thông linh và tự rút thần tinh thiên địa.","nguon":["@c0065"]},{"id":"mau-vang-chu-yem","name":"Máu vàng Chu Yếm","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":["Chu Yếm","Thạch Hạo"],"trangThai":"da-dung","blurb":"Máu vàng của Chu Yếm — chủ dược khiến đỉnh cổ tổ truyền cộng minh, luyện ra lô thuốc tẩy tủy cường thân.","detail":"Máu vàng của Chu Yếm được dùng làm chủ dược trong đỉnh cổ tổ truyền. Khi đổ vào đỉnh, đỉnh cộng minh, sống lại và nhuộm thành màu vàng; lô thuốc luyện ra có công dụng tẩy tủy, làm máu bầm tan, xương cốt sáng óng, tạng phủ trong suốt. Thạch Hạo uống một bát, cả thôn và ba con chim non cũng được chia một ngụm.","nguon":["@c0065"]},{"id":"mau-thai-co-di-chung","name":"Máu Thái Cổ Di Chủng","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":["Thạch Nghị"],"trangThai":"dang-co","blurb":"Linh dược/nguyên liệu quý của nhà Vương Hầu, dùng để bồi dưỡng Thạch Nghị — loại Thạch Thôn không có.","detail":"Máu của Thái Cổ Di Chủng — loại linh dược/nguyên liệu cực quý mà Thạch Thôn không có, nhưng nhà Vương Hầu cổ quốc có sẵn để bồi dưỡng Thạch Nghị. Được nhắc như biểu tượng của khoảng cách tài nguyên giữa Thạch Thôn và cổ quốc.","nguon":["@c0065"]},{"id":"chat-long-vang-kim-duoc-dinh","name":"Chất lỏng vàng kim trong dược đỉnh","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Chất lỏng màu vàng kim ninh trong dược đỉnh, giúp thể chất lột xác thần tốc.","detail":"Nhóc tỳ ăn chất lỏng vàng kim trong dược đỉnh khiến thể chất không ngừng lột xác, mạnh lên thần tốc, hỗ trợ khổ tu giữa thiên uy.","nguon":["@c0066"]},{"id":"cu-thach-muoi-van-can","name":"Cự thạch mười vạn cân","aliases":["Thần thiết","Đá phơi thịt khô"],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Khối cự thạch/thần thiết nặng mười vạn cân, vật rèn thân của Thạch Hạo, cũng là đá phơi thịt khô da thú của thôn.","detail":"Được nhóc tỳ dùng để luyện sức: nâng đứng sừng sững dưới ánh bình minh, đi ngược cơn lũ đá vào Loạn thạch sơn. Một tay nâng nổi cự thạch trước tộc nhân là mốc xác nhận đạt cực cảnh rèn thân.","nguon":["@c0066"]},{"id":"trung-ngu-sac-khong-tuoc","name":"Trứng Ngũ Sắc Khổng Tước","aliases":["Trứng ngũ sắc","Trứng thần cầm","Trứng hậu duệ Thái Cổ Thần Điểu"],"category":"khac","categoryLabel":"Linh vật / Trứng thần cầm","phamCap":"Không rõ","soHuu":["Chu Yếm","Thạch Hạo"],"trangThai":"dang-co","blurb":"Quả trứng to như cối đá, vằn ngũ sắc rực rỡ, nghi mang huyết mạch thần cầm.","detail":"Quả trứng to bằng cối đá, lốm đốm vằn ngũ sắc rực rỡ, tỏa hào quang cùng khí tức kinh khủng, bị nghi là có huyết mạch thần cầm. Bóng Lông trộm được đem về cho nhóc tỳ; thần cầm mẹ gào rú truy đuổi, sau đó Bóng Lông định cầm đá đập trứng để tẩm bổ cho nhóc tỳ.","nguon":["@c0069"]},{"id":"manh-vo-trung-thai-co-di-chung","name":"Mảnh vỏ trứng Thái cổ di chủng","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Thái Cổ","soHuu":["Bà lão cầm mảnh vỏ trứng"],"trangThai":"dang-co","blurb":"Mảnh vỏ trứng vỡ nhẵn như ngọc, óng ánh hoa văn ngũ sắc, do hậu duệ Thái cổ thần điểu sinh; dùng để cảm ứng khí tức của trứng gốc.","detail":"Bà lão giữ mảnh vỏ này, khi cảm ứng thấy khí tức tương ứng trên tiểu thú của Thạch Hạo liền xác nhận quả trứng đã bị ăn mất.","nguon":["@c0072"]},{"id":"xich-kiem-nhi-hoa","name":"Xích kiếm nhị hoa","aliases":["Phi kiếm đỏ","Nhị hoa xích"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tế linh Xung Vân"],"trangThai":"dang-co","blurb":"Phi kiếm toàn thân đỏ đậm, trong suốt như hỏa ngọc; thực chất là cái nhị của đóa hoa đỏ trên tế linh Xung Vân.","detail":"Bay ra chém giết mấy chục mãnh thú trong thú triều rồi trở về, đóa hoa khép cánh; là một trong ba đóa kỳ hoa của tế linh Xung Vân.","nguon":["@c0072"]},{"id":"phu-bai-vu-toc","name":"Phù bài Vũ tộc","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Hạ U Vũ"],"trangThai":"dang-co","blurb":"Khối phù bài mà nhóm Vũ tộc ở Xung Vân trấn cần xin từ Hạ U Vũ tiểu thư; công dụng chưa rõ.","detail":"Được người trung niên Vũ tộc nhắc như vật phẩm phải chờ Hạ U Vũ về mới xin được, gợi mở một mạch nhiệm vụ tại Xung Vân trấn.","nguon":["@c0072"]},{"id":"ba-phi-kiem-te-linh","name":"Ba phi kiếm của cây Tế linh","aliases":["Phi kiếm đỏ thẫm","Phi kiếm trắng","Phi kiếm tím"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo cụ liên thành","soHuu":["Liễu Thần"],"trangThai":"dang-co","blurb":"Ba thanh phi kiếm màu đỏ thẫm, trắng, tím do ba đóa hoa cây Tế linh thai nghén ra; cực sắc bén, được đánh giá là bảo cụ hiếm thấy giá trị liên thành.","detail":"Khi thủ lĩnh hung cầm khổng lồ chỉ huy thú triều công thành Trùng Vân, ba đóa hoa Tế linh nở rộ tỏa ánh sáng đỏ/trắng/tím, thai nghén ba thanh phi kiếm cùng màu bay lên trời. Ba kiếm đánh tan lửa hung cầm phun ra, cuối cùng bổ đôi thân hung cầm và chém đứt đầu nó. Người trung niên Vũ tộc nhận định đây là bảo cụ liên thành nhưng Vũ tộc không thể đụng vào.","nguon":["@c0073"]},{"id":"phu-bai-thach-hao","name":"Phù bài không rõ chất liệu","aliases":["Khối kim loại hay đá của Thạch Hạo"],"category":"khac","categoryLabel":"Vật phẩm khác","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Khối phù bài không rõ chất liệu Thạch Hạo mang trong lòng, gắn với lời thề đưa ‘một mình khác’ đến Bổ Thiên Các.","detail":"Vật Thạch Hạo mang bên mình, không rõ là kim loại hay đá. Khi phát hiện đứa bé bệnh tật ở tổ địa rách nát chính là ‘một mình khác’, hắn đưa tay sờ vào phù bài trong lòng và thề bằng mọi giá đưa đứa bé đến Bổ Thiên Các dù đường có xa xôi thế nào.","nguon":["@c0073"]},{"id":"phu-bai-bo-thien-cac","name":"Phù bài Bổ Thiên Các","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":[],"trangThai":"Chưa lấy được","blurb":"Phù bài do sứ giả Bổ Thiên Các cấp; Vũ Mông muốn xin để giao cho một thiên tài trong Vũ Tộc.","detail":"Một loại phù bài do sứ giả của Bổ Thiên Các ban cấp. Vũ Mông phụng lệnh tông lão tuần tra Tây Cương, đồng thời muốn xin một phù bài này để giao cho một thiên tài trong tộc vốn được các tông lão chiều chuộng. Tuy nhiên phải chính chủ — tiểu thư U Vũ — mới có thể nhận, mà nàng chưa xuất hiện nên Vũ Mông chưa lấy được.","nguon":["@c0075","@c0097"]},{"id":"trung-tieu-loan-dieu","name":"Trứng Tiểu Loan Điểu","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Bảo dược đại bổ","soHuu":[],"trangThai":"da-dung","blurb":"Trứng của loài chim quý hiếm Tiểu Loan Điểu ở hồ xanh lam Thạch thôn, được xem là bảo dược đại bổ.","detail":"Trứng của Tiểu Loan Điểu — loài chim quý hiếm sống bên hồ nước xanh lam Thạch thôn; vỏ lốm đốm nhiều màu sắc, là bảo dược đại bổ. Chập tối đám trẻ cùng Bóng Lông trộm được một đống, thả vào đống lửa nướng ăn cùng cá Long Tu, khiến Thạch Lâm Hổ từ xa la mắng vì sợ dọa hết chim quý thú lạ.","nguon":["@c0077"]},{"id":"ca-long-tu","name":"Cá Long Tu","category":"khac","categoryLabel":"Khác","soHuu":[],"blurb":"Loài cá ở hồ xanh lam Thạch thôn, nướng lên vàng óng bóng nhẫy làm thức ăn.","detail":"Cá bắt ở hồ xanh lam Thạch thôn; đám trẻ nướng vàng óng bóng nhẫy ăn cùng trứng Tiểu Loan Điểu bên bờ hồ.","nguon":["@c0077"]},{"id":"bao-duoc-noi-gan-cot","name":"Bảo dược nối gân cốt","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Chưa rõ","soHuu":["Thanh Phong"],"trangThai":"Đã dùng","blurb":"Một đỉnh bảo dược nhóc tỳ luyện trong dược đỉnh để nối liền gân cốt chân cho Thanh Phong.","detail":"Bảo dược được luyện trong dược đỉnh ban đêm, có thành phần gồm hai giọt máu vàng của Bóng Lông và máu Chu Yếm, khi thành đan thì dược đỉnh tỏa sáng và hiện hình một con chim thần thú lạ. Nhóc tỳ (Thạch Phi Giao) dùng toàn bộ đỉnh bảo dược này cho Thanh Phong: một phần bôi lên chân, một phần cho uống. Chỉ trong mấy ngày, gân cốt vết thương ở chân Thanh Phong (vết sẹo rách từng chảy máu, đã chỉnh khớp) mọc lại và liền hẳn, khiến tộc lão thán phục ‘máu của Chu Yếm’. Kết hợp thêm phù văn trị liệu mỗi ngày và tác dụng của Nguyên Thủy Chân Giải, Thanh Phong hồi phục hoàn toàn.","nguon":["@c0078"]},{"id":"hac-kim","name":"Hắc Kim","cn":"","category":"nguyen-lieu","categoryLabel":"Khoáng vật","phamCap":"Chưa rõ","soHuu":[],"trangThai":"Bị cưỡng đoạt","blurb":"Khoáng vật quý mà đám cướp hung ác đòi các thôn xóm giao nộp; thôn không đủ số lượng liền bị tàn sát cả thôn.","detail":"Hắc Kim là một loại khoáng vật quý bị đám cướp hung ác nhắm tới. Theo lời trăng trối của ông lão hấp hối trong thôn bị diệt, đám cướp từng đến yêu cầu thôn giao nộp Hắc Kim; đến kỳ hạn mà thôn không gom đủ nên bị tàn sát toàn bộ, không tha cả trẻ mấy tháng tuổi, ngay cả Tế Linh của thôn cũng chết trận. Giá trị của Hắc Kim gợi ý mức độ nguy hiểm mà các thôn trong vùng phải đối mặt.","nguon":["@c0078"]},{"id":"long-giac-cung","name":"Long Giác Cung","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Thạch Lâm Hổ","Thạch Phi Giao","Thôn nhân Thạch Thôn"],"trangThai":"dang-co","blurb":"Cung phòng thủ của thôn nhân Thạch Thôn, giương lên khi hung khấu áp sát.","detail":"Đám Thạch Lâm Hổ, Thạch Phi Giao đứng đầu thôn giương Long Giác Cung nhắm kĩ về phương xa, thề chết bảo vệ nơi ở; bị hung khấu khinh miệt gọi là 'cung tên rác rưởi'.","nguon":["@c0079"]},{"id":"chi-ton-cot-thu","name":"Cốt Thư","aliases":["Cốt Thư Chí Tôn địa"],"category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":[],"trangThai":"khong-ro","blurb":"Sách Cốt Văn quý báu nhóm Thạch Vân Phong tìm được trong động phủ Chí Tôn năm xưa, tuy quý nhưng chưa phải truyền thừa chân chính.","detail":"Nhóm Thạch Vân Phong khi đi thí luyện gặp động phủ Chí Tôn thì tìm được nhiều Cốt Thư nhưng không phá được cửa vào khu trung tâm; tin lộ ra khiến các thế lực ra tay cướp đoạt, nhóm bị truy sát chạy vào sâu Đại Hoang, huynh đệ chết gần hết.","nguon":["@c0079"]},{"id":"giap-vay-xuyen-son-giap","name":"Giáp vảy Xuyên Sơn Giáp","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cận Bảo Cụ (chưa đạt)","soHuu":["Thủ lĩnh giáp vảy"],"trangThai":"Bị Thạch Hạo đánh rụng vảy, xác nhận phù văn không trọn vẹn","blurb":"Giáp trụ ghép từ vảy Xuyên Sơn Giáp, do thủ lĩnh cướp mặc; phù văn trong vảy đã không còn trọn vẹn nên chưa đạt mức Bảo Cụ.","detail":"Một thủ lĩnh trong sơn trại cướp Đại Hoang mặc bộ giáp làm từ vảy Xuyên Sơn Giáp, đánh giá cứng cỏi phi thường. Khi Tiểu Thạch Hạo đánh gãy tay hắn, thử xem vảy có phải Bảo Cụ hay không, tiếp tục ra đòn đánh gãy nốt tay còn lại và lõm xương ngực, làm rụng vảy. Sau khi kiểm tra, Thạch Hạo kết luận phù văn khắc trong vảy đã không còn trọn vẹn, do đó bộ giáp chưa thể xem là Bảo Cụ thật sự — chỉ là vật cận Bảo Cụ. 「Đáng tiếc. Vẫn chưa thể coi là Bảo Cụ. Phù văn ở trong vảy đã không còn trọn vẹn rồi」","nguon":["@c0082"]},{"id":"vay-giap-vang-kim-xuyen-son-giap","name":"Vảy giáp vàng kim","aliases":["Bảo Cụ vảy vàng kim","Vảy giáp Bảo Cụ"],"category":"phap-bao","categoryLabel":"Bảo Cụ","phamCap":"Bảo Cụ (cực khó tổn hại)","soHuu":["Xuyên Sơn Giáp (Tế Linh vàng kim)"],"trangThai":"dang-co","blurb":"Toàn bộ vảy giáp vàng kim trên thân Tế Linh Xuyên Sơn Giáp là bảo vật; có thể lột ra trong nháy mắt hóa mưa ánh sáng công kích như cơn bão cuồng bạo.","detail":"Vảy giáp vàng kim phủ thân con Tế Linh Xuyên Sơn Giáp chính là Bảo Cụ của nó. Trong nháy mắt con thú lột toàn bộ vảy giáp thành mưa ánh sáng vàng kim tung đòn khủng bố, xuyên thủng cả núi đá; cực khó tổn hại, cuối cùng có ba cái vảy bắn xuyên qua cơ thể nhóc tỳ thành ba lỗ thủng.","nguon":["@c0083"]},{"id":"bao-kinh-toan-nghe","name":"Bảo Kính (Cốt kính của Toan Nghê)","cn":"","aliases":["Cốt kính","Bảo kính"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo cụ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Tấm gương lớn cỡ bàn tay mài từ miếng bảo cốt trên trán Toan Nghê, phóng ánh sáng thần thánh và lôi đình phá nát nội tạng địch.","detail":"Bảo cụ Thạch Hạo mài từ miếng bảo cốt lấy trên trán di chủng Thái Cổ Toan Nghê, ôn dưỡng mấy năm mới thành. Khi thi triển, gương phóng ra ánh sáng thần thánh sắc như lưỡi kiếm kèm lôi đình, đồng thời hiện phù văn cổ xưa bắn vào cơ thể đối phương. Trong trận chém Tế Linh, cốt kính bắn phù văn vào ngực và nhược điểm Xuyên Sơn Giáp, phá nát nội tạng địch — đòn nghiêm trọng nhất khiến Tế Linh khó giữ mạng. Đây là một trong nhiều bảo thuật, bảo cụ Thạch Hạo còn lưu từ Toan Nghê.","nguon":["@c0084"]},{"id":"cot-tien-xuong-vang","name":"Cốt Tiễn Xương Vàng","cn":"","aliases":["Cốt tiễn màu vàng","Cốt tiễn kim cốt","Bảo tiễn"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo cụ","soHuu":["Xuyên Sơn Giáp (Tế Linh vàng kim)"],"trangThai":"mat","blurb":"Hai mảnh xương hàm màu vàng đậm hợp lại như cái kéo, cắt đứt núi đá trăm mét, hiện Long văn của Cầu Long huyết thống Thái Cổ.","detail":"Bảo cụ của Tế Linh, gồm hai mảnh xương hàm màu vàng đậm (phần cứng nhất dùng đào núi) hợp lại như một cái kéo cắt ngang, chém đứt cả ngọn núi đá cao hơn trăm mét. Trên tiễn hiện Long văn vì mang Cầu Long huyết thống từ Thái Cổ; đây không phải bảo cốt của bản thân Tế Linh mà là xương của một di chủng lai lịch lớn hơn — một Xuyên Sơn Giáp Vương huyết thống thuần khiết cực kỳ khủng bố. Tế Linh tế luyện nuôi mảnh xương này hòng làm nó sống lại nên tự tổn mệnh nguyên. Sau khi Tế Linh chết, kim quang lóe lên, cốt tiễn mất chủ rơi từ trên trời xuống, chờ được đoạt.","nguon":["@c0084"]},{"id":"bao-dan-mau-bong-long","name":"Bảo đan luyện từ máu Bóng Lông","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"da-dung","blurb":"Hạt đan thơm ngát luyện từ máu Bóng Lông kết hợp thuốc cổ, chữa thương thần kỳ.","detail":"Bảo đan được luyện từ máu Bóng Lông cùng thuốc cổ, đựng trong bình ngọc. Khi nuốt xuống, đan giúp chữa trọng thương và bành trướng tinh khí nhanh chóng. Thạch Hạo dùng một hạt để trị vết thương đầy mình sau đại chiến; Bóng Lông tiếc rẻ giành lại bình nhưng bình đã cạn.","nguon":["@c0085"]},{"id":"huyet-nhuc-te-linh","name":"Huyết nhục Tế Linh","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Thạch thôn"],"trangThai":"da-dung","blurb":"Huyết nhục con Tế Linh (Xuyên Sơn Giáp) ẩn chứa tinh huyết, bảo bối giá trị khó phỏng đoán.","detail":"Thịt và xương cốt Tế Linh ẩn chứa tinh huyết quý giá, khó phỏng đoán giá trị. Phần thịt xương phải luyện chế cùng lão dược mới cho hiệu quả cao, chỉ một phần nhỏ được luộc và quay để ăn; huyết được chia cho mọi tộc nhân giúp tăng cường thể chất, còn bảo huyết và gân mạch là phần quý nhất do tộc lão đích thân thu thập. Với Thạch thôn, săn được một con Xuyên Sơn Giáp như chiếm được một bảo tàng.","nguon":["@c0085"]},{"id":"toan-nghe-di-the","name":"Toan Nghê di thể","cn":"","category":"nguyen-lieu","categoryLabel":"Thái Cổ di chủng","phamCap":"Vô giá","soHuu":["Thạch thôn"],"trangThai":"da-dung","blurb":"Di thể của Toan Nghê, một Thái Cổ di chủng không tầm thường, vô giá.","detail":"Cả Thạch thôn từng ăn trọn con Toan Nghê di thể này, nhờ đó thể chất tộc nhân được cải thiện khiến lũ trẻ mới tu được Cốt Văn. Loại di thể quý giá tới mức các đại bộ lạc dòm ngó có thể gây họa diệt tộc.","nguon":["@c0086"]},{"id":"tinh-bich","name":"Tinh Bích","cn":"","category":"khac","categoryLabel":"Linh vật / tiền tệ","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Vật giá trị được tu sĩ Hư Thần Giới dùng làm phương tiện trao đổi.","detail":"Lão già ở Sơ Thủy Địa dùng ‘rất nhiều tinh bích’ để đề nghị đổi lấy Phù Cốt nếu nhóc tỳ đào được, cho thấy tinh bích là vật giá trị dùng làm tiền tệ trong Hư Thần Giới.","nguon":["@c0087"]},{"id":"tinh-bich-khoang","name":"Tinh bích","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Tinh Bích đại gia"],"trangThai":"dang-co","blurb":"Khoáng vật/tiền tệ ở Hư Thần Giới, được ông lão định dùng lượng lớn để đổi Nguyên Thủy Bảo Cốt.","detail":"Loại vật phẩm mà Tinh Bích đại gia nêu ra làm giá đổi lấy Nguyên Thủy Bảo Cốt của Thạch Hạo; Thạch Hạo nghe lạ tai, tự nhủ phải hỏi cho biết tinh bích rốt cuộc là gì. Vì chuyện đổi này, ông lão bị nó cưỡng đặt biệt danh “Tinh Bích đại gia”.","nguon":["@c0089"]},{"id":"bia-da-ky-luc-hu-than-gioi","name":"Bia đá kỷ lục Hư Thần Giới","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp khí ghi chép của Hư Thần Giới","soHuu":["Hư Thần Giới"],"trangThai":"dang-co","blurb":"Bia đá quanh vẩn sương mù, hiện chữ phát sáng ghi và thông báo kỷ lục cho thiên hạ Hư Thần Giới.","detail":"Bia đá xuất hiện ở các lĩnh vực Hư Thần Giới, chung quanh sương mù giăng, tự hiện chữ phát sáng khi có kỷ lục mới; ghi chép và thông báo tin tức cho toàn thiên hạ, đồng thời lưu thần hi và sóng năng lượng tường hòa để người lập kỷ lục khắc thông tin. Ở Sơ Thủy Địa, bia hiện chữ thưởng Nguyên Thủy Bảo Cốt cho Thạch Hạo và ghi các dòng “Thích Nhất Uống Sữa Thú”, “Cực tốc” do nó khắc.","nguon":["@c0089"]},{"id":"xich-vu-bao-phien","name":"Xích Vũ","aliases":["Bảo Phiến","Thần Vũ"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo Cụ chấn tộc (nghi lông Thái Cổ Di Chủng)","soHuu":["Xích Vân công tử","Xích Phong","Thạch Hạo"],"trangThai":"dang-co","blurb":"Bảo Cụ mười tám lông đỏ hợp lại thành quạt màu đỏ, nghi lông quý Thái Cổ Di Chủng có sóng sinh mạng riêng.","detail":"Nguyên hình là một cái quạt đỏ; khi tách ra là mười tám lông đỏ, mỗi lông dài hơn mười mét như trường mâu màu máu, mang sát khí mãnh thú Hồng Hoang, phun ánh sáng đỏ như dung nham; người thường chạm phải hóa tro. Một lông có thể lắc biến dài mười trượng quét ngang. Vốn là binh khí của Xích Vân công tử — cường giả thanh niên nổi tiếng khắp Hư Thần Giới; đệ đệ Xích Phong mang xuống Sơ Thủy Địa nhưng không đủ sức thúc giục nên phải tách ra dùng, bị nhóc tỳ đoạt sau khi hạ gục Xích Phong.","nguon":["@c0090"]},{"id":"phu-cot-bao-cot","name":"Phù Cốt","aliases":["Bảo cốt","Khối bảo cốt"],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Cực quý","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Khối bảo cốt nhóc tỳ thu được khi phá hỏng thông đạo Hư Thần Giới, được cho là từng dùng xây thông đạo.","detail":"Cục xương cực quý trong tay nhóc tỳ, được người vây xem đoán từng dùng để xây thông đạo Hư Thần Giới nên mới kinh động bộ tộc lớn kéo tới. Bọn cướp bảo cốt vứt lại mười viên tinh bích tuyên bố ‘mua’ rồi định cưỡng đoạt, bị nhóc tỳ dùng cối xay bạc Thần Nguyệt đánh bay lấy lại.","nguon":["@c0090"]},{"id":"bia-da-ky-luc-hu-than-gioi-thach-nghi","name":"Bia đá kỷ lục Thạch Nghị","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Bia đá ghi chiến tích Thạch Nghị chém chín Thú Vương tại Sơ Thủy Địa và nhảy một bước lên đỉnh núi.","detail":"Bia đá kỷ lục Hư Thần Giới chép Thạch Nghị người ‘trùng đồng khai thiên’ trong một trận giết chín con Thú Vương tại Sơ Thủy Địa — lập kỷ lục chém số lượng Thú Vương nhiều nhất; kỷ lục thứ hai là dùng sức mạnh cơ thể (không dùng Cốt Văn) nhảy một bước lên đỉnh núi. Nhóc tỳ đọc bia liền ngông nghênh đòi phá mọi kỷ lục.","nguon":["@c0090"]},{"id":"bao-cu","name":"Bảo Cụ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":[],"trangThai":"dang-co","blurb":"Khí cụ luyện hồn phách dùng trong Hư Thần Giới, ít ai dám mang theo vì rủi ro mất mát.","detail":"Bảo Cụ là khí cụ luyện hồn phách. Nếu bị mất trong Hư Thần Giới thì hồn phách tinh luyện ở thế giới hiện thực cũng tổn thất, khiến uy lực giảm mạnh và về lâu dài có thể biến thành vật phàm — nên phần lớn cao thủ không dám mang theo khi vào Sơ Thủy Địa. Thạch Hạo đòi tộc nhân mang Bảo Thuật hoặc Bảo Cụ ‘đủ tốt, đủ đẹp’ tới chuộc người mới chịu rời đi, và chê hai tộc lão nghèo vì không mang Bảo Cụ bên người.","nguon":["@c0091"]},{"id":"khoi-bao-cot-trang-ong-anh","name":"Khối bảo cốt trắng óng ánh","category":"phap-bao","categoryLabel":"Bảo vật","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Khối bảo cốt trắng đào từ tảng đá xanh, là vật dẫn thông đạo Hư Thần Giới.","detail":"Gom nhiều khối có thể xây thông đạo Hư Thần Giới; dùng đơn độc thì quấy rối không gian. Thạch Hạo tung ra để phá đại trận lam của tứ đại gia tộc, khiến trận nổ tung. Chính là mục tiêu thật khiến tứ đại gia tộc hưng sư động chúng.","nguon":["@c0092"]},{"id":"bon-khoi-phu-cot-tu-dai-gia-toc","name":"Bốn khối Phù Cốt của tứ đại gia tộc","category":"phap-bao","categoryLabel":"Bảo vật","soHuu":["Tứ đại gia tộc"],"trangThai":"dang-co","blurb":"Bốn khối kỳ cốt bất phàm thần bí dùng bố cổ trận vây Thạch Hạo.","detail":"Ban đầu chỉ là hư ảnh Bảo Cụ hiện hóa nên chỉ dùng được một lần; sau khi trận đầu bị phá, lập lại trận thuần để tiêu diệt. Cuối cùng một cường giả ôm bốn khối bỏ chạy khi hai địch nổ tung.","nguon":["@c0092"]},{"id":"binh-ngoc-chan-huyet-hung-thu","name":"Bình ngọc chân huyết hung thú","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Bốn bình ngọc nhỏ mà nặng chứa bảo huyết bốn màu khác nhau, huyết mạch gần Thái Cổ Di Chủng.","detail":"Bốn tộc mỗi tộc đưa một bình ngọc chân huyết hung thú để chuộc người bị bắt; giá trị liên thành. Uống vào cường tráng sức mạnh tinh thần, quay về thế giới hiện thực còn tẩm bổ thêm từ tinh thần tới thể xác. Thạch Hạo cất cả bốn bình vào ngực.","nguon":["@c0092"]},{"id":"bao-cot-thuong-thong-dao","name":"Bảo Cốt (thưởng đánh nát thông đạo)","category":"khac","categoryLabel":"Bảo cốt","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Phần thưởng Hư Thần giới ban khi có người đánh nát thông đạo ở Sơ Thủy Địa.","detail":"Là phần thưởng cơ chế của Hư Thần giới cho kẻ đánh nát thông đạo tại Sơ Thủy Địa. Nhóc tỳ đoạt liên tiếp hai khối trong hai lần đầu, thời gian mỗi lần một ngắn hơn; lần thứ ba nó định lấy thêm để chế một bộ thần trận thì bị Hư Thần giới cảnh cáo, từ chối thưởng và liệt vào ‘nhân vật không được hoan nghênh’.","nguon":["@c0094"]},{"id":"so-thuy-dia-ky-luc-bi","name":"Sơ Thủy Địa Kỷ Lục Bi","aliases":["Kỷ Lục Bi","bia ghi kỷ lục"],"category":"khac","categoryLabel":"Bia đá","phamCap":"Không rõ","soHuu":[],"trangThai":"hong","blurb":"Tấm bia đá ghi chép kỷ lục thành tích ở Sơ Thủy Địa, bị nhóc tỳ đánh nát.","detail":"Tấm bia đá ghi các kỷ lục thành tích tại Sơ Thủy Địa trong Hư Thần giới, nơi lưu kỷ lục nhảy của Thạch Nghị. Nhóc tỳ sờ tìm Bảo Cốt trên bia rồi phá vỡ luôn tấm bia trước sự sững sờ của mọi người; hành vi này dẫn tới án khắc bia phán quyết, cảnh cáo nghiêm trọng và trục xuất nó khỏi Hư Thần giới hai năm.","nguon":["@c0094"]},{"id":"long-chim-do-tieu-hong","name":"Lông chim đỏ Tiểu Hồng","cn":"","category":"phap-bao","categoryLabel":"Tín vật","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Lông chim đỏ thẫm Tiểu Hồng để lại đền ơn Liễu thần, có sức uy hiếp với một số tộc lớn.","detail":"Tộc trưởng Thạch thôn tặng cho nhóc tỳ làm tín vật hộ thân trước khi lên đường. Tiểu Hồng từng được Liễu thần chữa thương nên để lại lông này đền ơn.","nguon":["@c0095"]},{"id":"toan-nghe-bao-huyet","name":"Toan nghê bảo huyết","cn":"","category":"nguyen-lieu","categoryLabel":"Bảo huyết","phamCap":"Thái cổ di chủng","soHuu":["Thạch Hạo"],"trangThai":"da-dung","blurb":"Bảo huyết thái cổ di chủng Toan nghê dùng rèn luyện thân thể nhóc tỳ trước năm tuổi.","detail":"Trước năm tuổi Thạch Hạo được phong kín vào đỉnh, dùng Toan nghê bảo huyết rèn luyện thân thể, đánh nền cơ sở vững chắc cho tu hành về sau.","nguon":["@c0095"]},{"id":"hoang-xa-hoa-quoc","name":"Hoàng Xa của Hỏa Quốc","category":"phap-bao","categoryLabel":"Bảo vật thế lực","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Cỗ xe bay của Hỏa Quốc do một Dị Cầm màu xanh lấp lánh bảo quang kéo.","detail":"Một cỗ Hoàng Xa bay ngang trời gần Bổ Thiên Các, do một Dị Cầm màu xanh lấp lánh bảo quang kéo, có người ngờ là Thanh Hoàng; được xác nhận là Hoàng Xa của Hỏa Quốc, chở một nhân vật khó lường.","nguon":["@c0096"]},{"id":"thu-cot-toa-may-tia","name":"Thú cốt tỏa mây tía","category":"phap-bao","categoryLabel":"Tọa kỵ","phamCap":"Không rõ","soHuu":["Cô gái áo tím"],"trangThai":"dang-co","blurb":"Xương thú bay lơ lửng tỏa mây tía làm phương tiện cho cô gái áo tím và đám cường giả.","detail":"Tọa kỵ xương thú bay lơ lửng tỏa mây tía mà cô gái áo tím (nghi hoàng tộc cổ quốc) và đám cường giả cưỡi khi tới Sơ Thủy Địa nghe tin nhóc tỳ.","nguon":["@c0096"]},{"id":"hoang-xa","name":"Hoàng Xa","category":"phap-bao","categoryLabel":"Tọa kỵ","phamCap":"Không rõ","soHuu":["Tiểu công chúa"],"trangThai":"dang-co","blurb":"Xe của tiểu công chúa Nhân Hoàng, cưỡi gió đi trong đêm hướng Bổ Thiên Các.","detail":"Cỗ Hoàng Xa mà tiểu công chúa được Nhân Hoàng sủng ái dùng khi rời Hoàng Thành đi “cầu học”, cưỡi gió đi trong đêm hướng Bổ Thiên Các.","nguon":["@c0096"]},{"id":"thai-co-di-chung","name":"Thái Cổ di chủng","cn":"","category":"linh-khi","categoryLabel":"Dị thú / Toạ kỵ","phamCap":"Không rõ","soHuu":["Vũ Vương phủ","Thạch Nghị"],"trangThai":"dang-co","blurb":"Sinh vật thượng cổ hai cánh khổng lồ như mây che trời, được Vũ Vương phủ dùng làm toạ kỵ đưa tiễn Thạch Nghị.","detail":"Hai cánh khổng lồ trải dài như đám mây che trời, khí thế huy hoàng; Vũ Vương phủ huy động để đưa tiễn Thạch Nghị vào Bổ Thiên các dự tuyển Thánh Viện, thể hiện quyết tâm dốc sức bồi dưỡng Trùng Đồng giả.","nguon":["@c0098"]},{"id":"chim-loan-nam-mau","name":"Chim Loan năm màu","cn":"","category":"linh-khi","categoryLabel":"Dị thú / Toạ kỵ","phamCap":"Không rõ","soHuu":["Nữ Chiến Thần Trục Lộc thư viện"],"trangThai":"dang-co","blurb":"Chim Loan ngũ sắc bao quanh mây mù thần hi, toạ kỵ của Nữ Chiến Thần Trục Lộc thư viện.","detail":"Xuất hiện tại sơn môn Bổ Thiên các, chở Nữ Chiến Thần Trục Lộc thư viện đến đoạt người; lông vũ năm màu rực rỡ tôn thêm khí chất kiêu ngạo của chủ nhân.","nguon":["@c0098"]},{"id":"phu-cot","name":"Phù cốt","aliases":["Bảo cốt"],"category":"nguyen-lieu","categoryLabel":"Bảo vật","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Mười tám khối xương óng ánh trong suốt đầy phù văn, đào từ khu vực thứ tám cổ chiến trường.","detail":"Mười tám khối phù cốt óng ánh trong suốt, đầy phù văn, giá trị cực lớn dù không phải di chủng bảo cốt Thái cổ. Nhóc tỳ đào được cả một bao lớn, chia thành sáu nhóm mỗi nhóm ba khối, chôn giấu ở đầm lầy, khe nước và tổ chim bỏ hoang tại tầng thứ hai chiến trường để sau này đi đường vòng vào lấy lại.","nguon":["@c0099"]},{"id":"bo-thien-thach","name":"Bổ Thiên Thạch","category":"khac","categoryLabel":"Vật phẩm ải","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Hòn đá đen bay ra từ bia phù quang, là vật phẩm tính công qua ải chiến trường thứ hai.","detail":"Hòn đá đen bay ra từ tấm bia trong chiến trường thứ hai. Luật ải yêu cầu giữ hai khối mới tính qua ải, giữ mười khối trở lên được môn phái trọng điểm bồi dưỡng — cơ chế khích lệ chém giết cướp thạch giữa các thiên tài.","nguon":["@c0100"]},{"id":"bia-bo-thien-cac","name":"Bia Bổ Thiên các","category":"khac","categoryLabel":"Cơ quan","trangThai":"dang-co","blurb":"Tấm bia phù quang khí lành nhả ra Bổ Thiên Thạch rồi tự lặn xuống đất.","detail":"Tấm bia phù quang tỏa khí lành trong chiến trường thứ hai, nhả ra một Bổ Thiên Thạch bay vào tay người tới rồi tự lặn xuống đất để không ai chiếm giữ ổ tại chỗ.","nguon":["@c0100"]},{"id":"hac-sat-lien","name":"Hắc Sát Liên","category":"khac","categoryLabel":"Linh Dược","trangThai":"dang-co","blurb":"Bảo dược cực hiếm cao hơn một thước, hình như hoa sen, thân đen như ngọc đen, rút sát khí mà sinh.","detail":"Bảo dược cực hiếm cao hơn một thước, hình dáng như hoa sen, cả thân đen như ngọc đen; rút sát khí mà sinh nên rất khó thấy vì thưa thớt. Là Linh Dược đặc biệt, dược tính kịch liệt bá đạo hơn Linh Dược thường; cây ở sào huyệt Hắc Hổ hấp thu sát khí của Hắc Hổ nên dược lực càng mãnh liệt.","nguon":["@c0100"]},{"id":"tinh-than-thao","name":"Tinh Thần Thảo","category":"nguyen-lieu","categoryLabel":"Linh Dược","trangThai":"dang-co","blurb":"Cỏ bốn lá thân tím, mỗi lá có hoa văn hình ngôi sao, được gọi là Linh Chu chân chính.","detail":"Loại Linh Dược mọc cạnh đầm khí tím lạnh giá ở ngoại vi Bổ Thiên các, cỏ bốn lá thân tím, bảo huy mờ, mỗi lá có hoa văn hình ngôi sao. Được gọi là Linh Chu chân chính; Bổ Thiên các để dành cho hậu nhân, không ai dám trộm.","nguon":["@c0097"]},{"id":"khuyen-diep-dang","name":"Khuyển Diệp Đằng","category":"nguyen-lieu","categoryLabel":"Lão Dược","trangThai":"dang-co","blurb":"Cây mây thân đen, lá như ngọc đen hình con chó, sắp tuyệt chủng, sinh trưởng ít nhất mấy trăm năm.","detail":"Lão Dược cắm rễ vách đá ngoại vi Bổ Thiên các, cây mây thân đen, lá như ngọc đen hình con chó, sắp tuyệt chủng, sinh trưởng ít nhất mấy trăm năm. Bổ Thiên các không hái vì chưa thành Linh Dược chân chính, để dành cho hậu nhân.","nguon":["@c0097"]}]};
